{
  "name": "SuperBloonsTD 3D",
  "description": "A 3D Tower Defense game inspired by Bloons TD. defend the path against waves of colored balloons using various monkeys."
}

import { Vector3 } from 'three';

export enum BloonType {
  RED = 'RED',
  BLUE = 'BLUE',
  GREEN = 'GREEN',
  YELLOW = 'YELLOW',
  PINK = 'PINK',
  BLACK = 'BLACK',
  LEAD = 'LEAD',
}

export interface BloonConfig {
  type: BloonType;
  rbe: number; // Red Bloon Equivalent (Health/Layer count)
  speed: number;
  color: string;
  radius: number;
  children: BloonType[]; // What spawns when popped
  immunity: string[]; // 'SHARP', 'EXPLOSION', etc.
}

export interface BloonEntity {
  id: string;
  type: BloonType;
  position: Vector3;
  waypointIndex: number; // Current target waypoint index
  progress: number; // 0-1 progress between waypoints
  distanceTraveled: number; // Total distance for targeting priority
  frozen: boolean;
}

export enum TowerType {
  DART_MONKEY = 'DART_MONKEY',
  TACK_SHOOTER = 'TACK_SHOOTER',
  SNIPER_MONKEY = 'SNIPER_MONKEY',
}

export interface TowerConfig {
  name: string;
  cost: number;
  range: number;
  attackSpeed: number; // Seconds between shots
  damage: number;
  color: string;
  projectileSpeed: number;
  description: string;
}

export interface TowerEntity {
  id: string;
  type: TowerType;
  position: Vector3;
  lastFired: number;
  range: number;
}

export interface ProjectileEntity {
  id: string;
  position: Vector3;
  targetId: string | null; // Homing or last known position
  velocity: Vector3;
  damage: number;
  speed: number;
  pierce: number;
  color: string;
}

export interface GameState {
  money: number;
  lives: number;
  round: number;
  isPlaying: boolean;
  isGameOver: boolean;
  gameWon: boolean;
}

import { BloonConfig, BloonType, TowerConfig, TowerType } from './types';
import { Vector3 } from 'three';

// --- MAP PATH ---
// Simple winding path on X-Z plane (Y=0)
export const PATH_POINTS: Vector3[] = [
  new Vector3(-15, 0, -10),
  new Vector3(-10, 0, -10),
  new Vector3(-10, 0, 5),
  new Vector3(0, 0, 5),
  new Vector3(0, 0, -5),
  new Vector3(10, 0, -5),
  new Vector3(10, 0, 10),
  new Vector3(15, 0, 10),
];

// --- BLOON STATS ---
export const BLOONS: Record<BloonType, BloonConfig> = {
  [BloonType.RED]: {
    type: BloonType.RED,
    rbe: 1,
    speed: 3.5,
    color: '#ff0000',
    radius: 0.4,
    children: [],
    immunity: [],
  },
  [BloonType.BLUE]: {
    type: BloonType.BLUE,
    rbe: 2,
    speed: 4.9, // 1.4x Red
    color: '#0066ff',
    radius: 0.45,
    children: [BloonType.RED],
    immunity: [],
  },
  [BloonType.GREEN]: {
    type: BloonType.GREEN,
    rbe: 3,
    speed: 6.3, // 1.8x Red
    color: '#00aa00',
    radius: 0.5,
    children: [BloonType.BLUE],
    immunity: [],
  },
  [BloonType.YELLOW]: {
    type: BloonType.YELLOW,
    rbe: 4,
    speed: 11.2, // 3.2x Red
    color: '#ffff00',
    radius: 0.55,
    children: [BloonType.GREEN],
    immunity: [],
  },
  [BloonType.PINK]: {
    type: BloonType.PINK,
    rbe: 5,
    speed: 12.25, // 3.5x Red
    color: '#ff69b4',
    radius: 0.55,
    children: [BloonType.YELLOW],
    immunity: [],
  },
  [BloonType.BLACK]: {
    type: BloonType.BLACK,
    rbe: 11,
    speed: 6.3,
    color: '#222222',
    radius: 0.4,
    children: [BloonType.PINK, BloonType.PINK],
    immunity: ['EXPLOSION'],
  },
  [BloonType.LEAD]: {
    type: BloonType.LEAD,
    rbe: 23,
    speed: 3.5,
    color: '#6e7a89',
    radius: 0.5,
    children: [BloonType.BLACK, BloonType.BLACK],
    immunity: ['SHARP'],
  }
};

// --- TOWER STATS ---
export const TOWERS: Record<TowerType, TowerConfig> = {
  [TowerType.DART_MONKEY]: {
    name: "Dart Monkey",
    cost: 200,
    range: 6,
    attackSpeed: 0.95,
    damage: 1,
    color: '#8B4513',
    projectileSpeed: 25,
    description: "Cheap, balanced tower."
  },
  [TowerType.TACK_SHOOTER]: {
    name: "Tack Shooter",
    cost: 280,
    range: 4,
    attackSpeed: 0.7, // Fast
    damage: 1,
    color: '#ffaacc',
    projectileSpeed: 20,
    description: "Short range, 8-way attack."
  },
  [TowerType.SNIPER_MONKEY]: {
    name: "Sniper",
    cost: 350,
    range: 100, // Infinite effectively
    attackSpeed: 2.0, // Slow
    damage: 2,
    color: '#4B5320',
    projectileSpeed: 100, // Instant
    description: "Infinite range, pops 2 layers."
  }
};

// --- WAVES ---
export interface WavePart {
  type: BloonType;
  count: number;
  interval: number; // Seconds between spawns
}

export const WAVES: WavePart[][] = [
  // Round 1
  [{ type: BloonType.RED, count: 20, interval: 1.0 }],
  // Round 2
  [{ type: BloonType.RED, count: 30, interval: 0.8 }],
  // Round 3
  [
    { type: BloonType.RED, count: 10, interval: 0.8 },
    { type: BloonType.BLUE, count: 5, interval: 1.5 }
  ],
  // Round 4
  [
    { type: BloonType.BLUE, count: 15, interval: 1.0 },
    { type: BloonType.RED, count: 10, interval: 0.5 }
  ],
  // Round 5
  [{ type: BloonType.GREEN, count: 5, interval: 1.5 }, { type: BloonType.BLUE, count: 20, interval: 0.8 }],
  // Round 6 (Fast Yellows)
  [{ type: BloonType.YELLOW, count: 5, interval: 2.0 }],
  // Round 7 (Blacks - split)
  [{ type: BloonType.BLACK, count: 5, interval: 2.5 }],
  // Round 8 (Lead)
  [{ type: BloonType.LEAD, count: 3, interval: 4.0 }, { type: BloonType.GREEN, count: 20, interval: 0.5 }],
];

import React, { useRef, useState, useMemo, useEffect } from 'react';
import { Canvas, useFrame, ThreeEvent } from '@react-three/fiber';
import { OrbitControls, Line, Text, Sphere, Cylinder } from '@react-three/drei';
import * as THREE from 'three';
import { Vector3 } from 'three';
import { BLOONS, PATH_POINTS, TOWERS, WAVES } from '../constants';
import { BloonEntity, BloonType, ProjectileEntity, TowerEntity, TowerType } from '../types';

interface GameSceneProps {
  round: number;
  isPlaying: boolean;
  money: number;
  onMoneyChange: (amount: number) => void;
  onLivesChange: (amount: number) => void;
  onRoundComplete: () => void;
  onGameOver: () => void;
  selectedTower: TowerType | null;
  onPlaceTower: (cost: number) => void;
  gameState: { isGameOver: boolean; gameWon: boolean };
}

// Helper to get position along path segments
const getPositionOnPath = (startIdx: number, progress: number): Vector3 => {
  if (startIdx >= PATH_POINTS.length - 1) return PATH_POINTS[PATH_POINTS.length - 1];
  const p1 = PATH_POINTS[startIdx];
  const p2 = PATH_POINTS[startIdx + 1];
  return new Vector3().lerpVectors(p1, p2, progress);
};

const getDistanceBetweenPoints = (idx1: number, idx2: number): number => {
    return PATH_POINTS[idx1].distanceTo(PATH_POINTS[idx2]);
};

export const GameScene: React.FC<GameSceneProps> = ({
  round,
  isPlaying,
  money,
  onMoneyChange,
  onLivesChange,
  onRoundComplete,
  onGameOver,
  selectedTower,
  onPlaceTower,
  gameState
}) => {
  // Mutable game state for high-frequency updates
  const enemiesRef = useRef<BloonEntity[]>([]);
  const towersRef = useRef<TowerEntity[]>([]);
  const projectilesRef = useRef<ProjectileEntity[]>([]);

  // Wave Management
  const waveState = useRef({
    currentWaveIdx: 0,
    bloonsSpawned: 0,
    timeSinceLastSpawn: 0,
    waveActive: false,
    waveComplete: false,
  });

  // Mouse tracking for placement
  const [hoverPos, setHoverPos] = useState<Vector3 | null>(null);

  // Initialize/Reset Wave when round changes
  useEffect(() => {
    if (isPlaying && round > 0 && round <= WAVES.length) {
      waveState.current.currentWaveIdx = 0;
      waveState.current.bloonsSpawned = 0;
      waveState.current.timeSinceLastSpawn = 0;
      waveState.current.waveActive = true;
      waveState.current.waveComplete = false;
    }
  }, [round, isPlaying]);

  // Main Game Loop
  useFrame((state, delta) => {
    if (gameState.isGameOver || gameState.gameWon) return;

    // 1. Spawning Logic
    if (isPlaying && waveState.current.waveActive) {
      const waveConfig = WAVES[round - 1];
      if (waveConfig && waveState.current.currentWaveIdx < waveConfig.length) {
        const part = waveConfig[waveState.current.currentWaveIdx];

        waveState.current.timeSinceLastSpawn += delta;

        if (waveState.current.timeSinceLastSpawn >= part.interval) {
          waveState.current.timeSinceLastSpawn = 0;

          // Spawn Bloon
          const newBloon: BloonEntity = {
            id: Math.random().toString(36).substr(2, 9),
            type: part.type,
            position: PATH_POINTS[0].clone(),
            waypointIndex: 0,
            progress: 0,
            distanceTraveled: 0,
            frozen: false,
          };
          enemiesRef.current.push(newBloon);
          waveState.current.bloonsSpawned++;

          // Check if part complete
          if (waveState.current.bloonsSpawned >= part.count) {
            waveState.current.currentWaveIdx++;
            waveState.current.bloonsSpawned = 0;
            // Add a small pause between wave parts
            waveState.current.timeSinceLastSpawn = -1.0; 
          }
        }
      } else {
        // All parts spawned
        if (enemiesRef.current.length === 0 && waveState.current.waveActive) {
          waveState.current.waveActive = false;
          onRoundComplete();
        }
      }
    }

    // 2. Enemy Movement
    enemiesRef.current.forEach(enemy => {
      if (enemy.frozen) return; // Implement freeze later

      const config = BLOONS[enemy.type];
      const segmentLength = getDistanceBetweenPoints(enemy.waypointIndex, enemy.waypointIndex + 1);

      // Calculate movement amount
      const moveAmt = config.speed * delta;
      const progressInc = moveAmt / segmentLength;

      enemy.progress += progressInc;
      enemy.distanceTraveled += moveAmt;

      if (enemy.progress >= 1) {
        // Reached waypoint
        enemy.waypointIndex++;
        enemy.progress = 0;

        // Reached End?
        if (enemy.waypointIndex >= PATH_POINTS.length - 1) {
          // Bloon escaped
          onLivesChange(-config.rbe);
          enemy.distanceTraveled = 999999; // Mark for deletion
        } else {
          // Snap to new start
          enemy.position.copy(PATH_POINTS[enemy.waypointIndex]);
        }
      } else {
        // Interpolate
        enemy.position.copy(getPositionOnPath(enemy.waypointIndex, enemy.progress));
      }
    });

    // Remove escaped enemies
    enemiesRef.current = enemiesRef.current.filter(e => e.distanceTraveled < 999999);

    // 3. Tower Targeting & Firing
    const now = state.clock.elapsedTime;
    towersRef.current.forEach(tower => {
      const config = TOWERS[tower.type];

      if (now - tower.lastFired >= config.attackSpeed) {
        // Find Target: First (Furthest) Enemy in Range
        let target: BloonEntity | null = null;
        let maxDist = -1;

        for (const enemy of enemiesRef.current) {
          const dist = tower.position.distanceTo(enemy.position);
          if (dist <= config.range) {
            // First targeting priority (furthest traveled)
            if (enemy.distanceTraveled > maxDist) {
              maxDist = enemy.distanceTraveled;
              target = enemy;
            }
          }
        }

        if (target) {
          // Fire!
          tower.lastFired = now;

          // Special case for Tack Shooter: 8 projectiles
          if (tower.type === TowerType.TACK_SHOOTER) {
             for (let i = 0; i < 8; i++) {
                const angle = (i / 8) * Math.PI * 2;
                const vel = new Vector3(Math.cos(angle), 0, Math.sin(angle)).multiplyScalar(config.projectileSpeed);
                projectilesRef.current.push({
                    id: Math.random().toString(),
                    position: tower.position.clone().add(new Vector3(0, 0.5, 0)),
                    targetId: null, // Non-homing
                    velocity: vel,
                    damage: config.damage,
                    speed: config.projectileSpeed,
                    pierce: 1, // Basic pierce
                    color: 'black'
                });
             }
          } else {
            // Standard aimed projectile
            const dir = new Vector3().subVectors(target.position, tower.position).normalize();
            projectilesRef.current.push({
                id: Math.random().toString(),
                position: tower.position.clone().add(new Vector3(0, 1, 0)),
                targetId: target.id,
                velocity: dir.multiplyScalar(config.projectileSpeed),
                damage: config.damage,
                speed: config.projectileSpeed,
                pierce: 1 + (tower.type === TowerType.SNIPER_MONKEY ? 1 : 0),
                color: tower.type === TowerType.SNIPER_MONKEY ? 'yellow' : 'brown'
            });
          }
        }
      }
    });

    // 4. Projectile Movement & Collision
    const survivingProjectiles: ProjectileEntity[] = [];
    const newEnemies: BloonEntity[] = [];

    projectilesRef.current.forEach(proj => {
      // Sniper is hit-scan (instant), logic handled differently usually, but let's simulate very fast projectile for simplicity
      // Or just standard movement
      const moveDist = proj.speed * delta;

      // Update position
      const oldPos = proj.position.clone();
      proj.position.add(proj.velocity.clone().multiplyScalar(delta));

      // Collision Detection
      let hit = false;

      // Simple sphere collision
      for (let i = 0; i < enemiesRef.current.length; i++) {
        const enemy = enemiesRef.current[i];
        if (enemy.distanceTraveled >= 999999) continue; // Already dead/escaped this frame

        // Check distance to enemy
        const dist = proj.position.distanceTo(enemy.position);
        // Also check if we passed through it (for fast projectiles)
        const passed = new THREE.Line3(oldPos, proj.position).closestPointToPoint(enemy.position, true).distanceTo(enemy.position);

        if (dist < BLOONS[enemy.type].radius + 0.5 || passed < BLOONS[enemy.type].radius + 0.2) {
            // HIT!
            hit = true;
            proj.pierce--;

            // Damage Logic
            const bloonCfg = BLOONS[enemy.type];

            // Check immunity (Simplified)
            // e.g. Lead needs explosive or heat. Simplified here.
            if (bloonCfg.type === BloonType.LEAD && proj.damage < 2) {
                 // Bounce off (no damage if damage is low/sharp, simulated check)
                 // For MVP, simplify: Sniper (dmg 2) breaks lead. Dart (dmg 1) doesn't.
                 hit = false; 
                 proj.pierce++; // Refund pierce
                 continue;
            }

            // Pop Bloon
            onMoneyChange(1);

            // Spawn children
            const children = bloonCfg.children;
            if (children.length > 0) {
                // Spacing children slightly
                children.forEach((childType, idx) => {
                    newEnemies.push({
                        id: Math.random().toString(),
                        type: childType,
                        position: enemy.position.clone(), // Should offset slightly backwards based on velocity
                        waypointIndex: enemy.waypointIndex,
                        progress: enemy.progress - (idx * 0.01), // Slight stagger
                        distanceTraveled: enemy.distanceTraveled - (idx * 0.1),
                        frozen: false
                    });
                });
            }

            // Remove parent (mark for deletion)
            enemy.distanceTraveled = 999999; 

            if (proj.pierce <= 0) break; // Projectile destroyed
        }
      }

      // Keep projectile if it has pierce and hasn't flown too far
      if (proj.pierce > 0 && proj.position.length() < 100) {
        survivingProjectiles.push(proj);
      }
    });

    // Cleanup dead enemies and add new ones
    enemiesRef.current = enemiesRef.current.filter(e => e.distanceTraveled < 999999).concat(newEnemies);
    projectilesRef.current = survivingProjectiles;

  });

  // Handle Input
  const handlePlaneClick = (e: ThreeEvent<MouseEvent>) => {
    if (!selectedTower) return;

    // Check cost
    const cost = TOWERS[selectedTower].cost;
    if (money < cost) return;

    const pos = e.point.clone();
    pos.y = 0; // Snap to ground

    // Check collision with path (Simplified: just check distance to lines)
    let valid = true;
    for (let i = 0; i < PATH_POINTS.length - 1; i++) {
        const p1 = PATH_POINTS[i];
        const p2 = PATH_POINTS[i+1];
        const line = new THREE.Line3(p1, p2);
        const closest = new Vector3();
        line.closestPointToPoint(pos, true, closest);
        if (closest.distanceTo(pos) < 1.5) { // 1.5 radius buffer from path
            valid = false;
            break;
        }
    }

    // Check collision with other towers
    if (valid) {
        for(const t of towersRef.current) {
            if (t.position.distanceTo(pos) < 1.0) {
                valid = false;
                break;
            }
        }
    }

    if (valid) {
        const newTower: TowerEntity = {
            id: Math.random().toString(),
            type: selectedTower,
            position: pos,
            lastFired: 0,
            range: TOWERS[selectedTower].range
        };
        towersRef.current.push(newTower);
        onPlaceTower(cost);
    }
  };

  const handlePointerMove = (e: ThreeEvent<PointerEvent>) => {
      setHoverPos(e.point.clone());
  };

  return (
    <>
      <ambientLight intensity={0.7} />
      <directionalLight position={[10, 20, 5]} intensity={1.5} castShadow />

      {/* MAP / GROUND */}
      <mesh 
        rotation={[-Math.PI / 2, 0, 0]} 
        position={[0, -0.1, 0]} 
        receiveShadow
        onClick={handlePlaneClick}
        onPointerMove={handlePointerMove}
      >
        <planeGeometry args={[60, 60]} />
        <meshStandardMaterial color="#4ade80" />
      </mesh>

      {/* PATH VISUALIZATION */}
      <Line 
        points={PATH_POINTS} 
        color="#d2b48c" 
        lineWidth={10} 
        position={[0, 0.05, 0]}
      />

      {/* START & END MARKERS */}
      <Text position={[PATH_POINTS[0].x, 1, PATH_POINTS[0].z]} fontSize={1} color="white" anchorX="center" anchorY="middle">
        START
      </Text>
      <Text position={[PATH_POINTS[PATH_POINTS.length-1].x, 1, PATH_POINTS[PATH_POINTS.length-1].z]} fontSize={1} color="red" anchorX="center" anchorY="middle">
        EXIT
      </Text>

      {/* ENEMIES */}
      {enemiesRef.current.map(enemy => (
        <mesh key={enemy.id} position={enemy.position}>
          <sphereGeometry args={[BLOONS[enemy.type].radius, 16, 16]} />
          <meshStandardMaterial color={BLOONS[enemy.type].color} />
        </mesh>
      ))}

      {/* TOWERS */}
      {towersRef.current.map(tower => (
        <group key={tower.id} position={tower.position}>
            {/* Base */}
            <mesh position={[0, 0.5, 0]}>
                <cylinderGeometry args={[0.5, 0.6, 1, 8]} />
                <meshStandardMaterial color={TOWERS[tower.type].color} />
            </mesh>
             {/* Head (indicator of type) */}
            <mesh position={[0, 1.0, 0]}>
                 <boxGeometry args={[0.4, 0.4, 0.4]} />
                 <meshStandardMaterial color="#333" />
            </mesh>
        </group>
      ))}

      {/* PROJECTILES */}
      {projectilesRef.current.map(proj => (
        <mesh key={proj.id} position={proj.position}>
           <sphereGeometry args={[0.15, 8, 8]} />
           <meshBasicMaterial color={proj.color} />
        </mesh>
      ))}

      {/* PLACEMENT PREVIEW */}
      {selectedTower && hoverPos && (
        <group position={[hoverPos.x, 0, hoverPos.z]}>
            {/* Range Circle */}
            <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, 0.05, 0]}>
                <ringGeometry args={[TOWERS[selectedTower].range - 0.1, TOWERS[selectedTower].range, 32]} />
                <meshBasicMaterial color="white" opacity={0.5} transparent />
            </mesh>
            <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, 0.05, 0]}>
                <circleGeometry args={[TOWERS[selectedTower].range, 32]} />
                <meshBasicMaterial color="white" opacity={0.1} transparent />
            </mesh>
            {/* Ghost Tower */}
            <mesh position={[0, 0.5, 0]}>
                <cylinderGeometry args={[0.5, 0.6, 1, 8]} />
                <meshStandardMaterial color={TOWERS[selectedTower].color} opacity={0.6} transparent />
            </mesh>
        </group>
      )}

      <OrbitControls 
        makeDefault 
        minDistance={10} 
        maxDistance={40} 
        maxPolarAngle={Math.PI / 3} // Prevent going under ground
        enableDamping
      />
    </>
  );
};

import React from 'react';
import { GameState, TowerType } from '../types';
import { TOWERS } from '../constants';

interface UIOverlayProps {
  gameState: GameState;
  selectedTower: TowerType | null;
  onSelectTower: (tower: TowerType | null) => void;
  onStartRound: () => void;
  onRestart: () => void;
}

export const UIOverlay: React.FC<UIOverlayProps> = ({
  gameState,
  selectedTower,
  onSelectTower,
  onStartRound,
  onRestart
}) => {
  return (
    <div className="absolute inset-0 pointer-events-none flex flex-col justify-between p-4 font-sans select-none">

      {/* TOP BAR: STATS */}
      <div className="flex justify-between items-start">
        <div className="bg-gray-900/80 text-white p-3 rounded-lg border-2 border-gray-700 shadow-xl pointer-events-auto">
          <div className="flex gap-6 text-xl font-bold">
            <div className="flex items-center gap-2 text-red-500">
              <span>❤️</span>
              <span>{gameState.lives}</span>
            </div>
            <div className="flex items-center gap-2 text-green-400">
              <span>💰</span>
              <span>${gameState.money}</span>
            </div>
            <div className="flex items-center gap-2 text-blue-300">
              <span>🌊</span>
              <span>Round {gameState.round}</span>
            </div>
          </div>
        </div>

        {/* Start Button */}
        {!gameState.isPlaying && !gameState.isGameOver && !gameState.gameWon && (
          <button 
            onClick={onStartRound}
            className="pointer-events-auto bg-green-600 hover:bg-green-500 text-white font-bold py-3 px-8 rounded-full border-4 border-green-800 shadow-lg text-xl transform transition hover:scale-105 active:scale-95"
          >
            Start Round
          </button>
        )}
      </div>

      {/* GAME OVER / WIN MODAL */}
      {(gameState.isGameOver || gameState.gameWon) && (
        <div className="absolute inset-0 flex items-center justify-center bg-black/60 z-50 pointer-events-auto">
          <div className="bg-gray-800 p-8 rounded-2xl border-4 border-gray-600 text-center max-w-md">
            <h1 className={`text-5xl font-extrabold mb-4 ${gameState.gameWon ? 'text-yellow-400' : 'text-red-500'}`}>
              {gameState.gameWon ? 'VICTORY!' : 'GAME OVER'}
            </h1>
            <p className="text-gray-300 text-lg mb-8">
              {gameState.gameWon 
                ? "You've defended the monkey lands!" 
                : `The Bloons leaked through on round ${gameState.round}.`}
            </p>
            <button 
              onClick={onRestart}
              className="bg-blue-600 hover:bg-blue-500 text-white font-bold py-3 px-8 rounded-xl shadow-lg w-full text-xl"
            >
              Restart Game
            </button>
          </div>
        </div>
      )}

      {/* BOTTOM BAR: TOWERS */}
      <div className="flex justify-center items-end pointer-events-auto">
        <div className="bg-gray-900/90 p-4 rounded-xl border-t-4 border-gray-700 flex gap-4 overflow-x-auto shadow-2xl">
          {Object.values(TOWERS).map((tower) => {
             const key = Object.keys(TOWERS).find(k => TOWERS[k as TowerType] === tower) as TowerType;
             const isSelected = selectedTower === key;
             const canAfford = gameState.money >= tower.cost;

             return (
               <button
                 key={key}
                 onClick={() => onSelectTower(isSelected ? null : key)}
                 disabled={!canAfford}
                 className={`
                    relative flex flex-col items-center p-2 rounded-lg w-24 transition-all
                    ${isSelected ? 'bg-yellow-500/20 ring-2 ring-yellow-400' : 'hover:bg-gray-700'}
                    ${!canAfford ? 'opacity-50 grayscale cursor-not-allowed' : 'cursor-pointer'}
                 `}
               >
                 <div 
                    className="w-12 h-12 rounded-full mb-2 shadow-inner border-2 border-gray-600"
                    style={{ backgroundColor: tower.color }} 
                 />
                 <span className="text-xs font-bold text-gray-200">{tower.name}</span>
                 <span className={`text-sm font-extrabold ${canAfford ? 'text-green-400' : 'text-red-400'}`}>
                   ${tower.cost}
                 </span>

                 {/* Tooltip on hover could go here, keeping it simple for now */}
               </button>
             );
          })}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { Canvas } from '@react-three/fiber';
import { GameScene } from './components/GameScene';
import { UIOverlay } from './components/UIOverlay';
import { GameState, TowerType } from './types';
import { WAVES } from './constants';

const INITIAL_MONEY = 650;
const INITIAL_LIVES = 150; // Medium difficulty

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>({
    money: INITIAL_MONEY,
    lives: INITIAL_LIVES,
    round: 1,
    isPlaying: false,
    isGameOver: false,
    gameWon: false,
  });

  const [selectedTower, setSelectedTower] = useState<TowerType | null>(null);

  const handleStartRound = useCallback(() => {
    setGameState(prev => ({ ...prev, isPlaying: true }));
  }, []);

  const handleRoundComplete = useCallback(() => {
    setGameState(prev => {
        const nextRound = prev.round + 1;
        const won = nextRound > WAVES.length;
        return {
            ...prev,
            isPlaying: false,
            round: won ? prev.round : nextRound,
            money: prev.money + 100 + prev.round, // Round bonus
            gameWon: won
        };
    });
  }, []);

  const handleGameOver = useCallback(() => {
    setGameState(prev => ({ ...prev, isPlaying: false, isGameOver: true }));
  }, []);

  const handleMoneyChange = useCallback((amount: number) => {
    setGameState(prev => ({ ...prev, money: prev.money + amount }));
  }, []);

  const handleLivesChange = useCallback((amount: number) => {
    setGameState(prev => {
        const newLives = prev.lives + amount;
        if (newLives <= 0) {
            return { ...prev, lives: 0, isPlaying: false, isGameOver: true };
        }
        return { ...prev, lives: newLives };
    });
  }, []);

  const handlePlaceTower = useCallback((cost: number) => {
    setGameState(prev => ({ ...prev, money: prev.money - cost }));
    setSelectedTower(null); // Deselect after placement
  }, []);

  const handleRestart = useCallback(() => {
    setGameState({
        money: INITIAL_MONEY,
        lives: INITIAL_LIVES,
        round: 1,
        isPlaying: false,
        isGameOver: false,
        gameWon: false
    });
  }, []);

  return (
    <div className="w-full h-screen relative bg-gray-900 overflow-hidden">
      <Canvas shadows camera={{ position: [0, 25, 20], fov: 45 }}>
        <GameScene 
            round={gameState.round}
            isPlaying={gameState.isPlaying}
            money={gameState.money}
            onMoneyChange={handleMoneyChange}
            onLivesChange={handleLivesChange}
            onRoundComplete={handleRoundComplete}
            onGameOver={handleGameOver}
            selectedTower={selectedTower}
            onPlaceTower={handlePlaceTower}
            gameState={{ isGameOver: gameState.isGameOver, gameWon: gameState.gameWon }}
        />
      </Canvas>

      <UIOverlay 
        gameState={gameState}
        selectedTower={selectedTower}
        onSelectTower={setSelectedTower}
        onStartRound={handleStartRound}
        onRestart={handleRestart}
      />
    </div>
  );
};

export default App;

