// Helper to get position along path segments
const getPositionOnPath = (startIdx: number, progress: number): Vector3 => {
  if (startIdx >= PATH_POINTS.length - 1) return PATH_POINTS[PATH_POINTS.length - 1];
  const p1 = PATH_POINTS[startIdx];
  const p2 = PATH_POINTS[startIdx + 1];
  return new Vector3().lerpVectors(p1, p2, progress);
};

const getDistanceBetweenPoints = (idx1: number, idx2: number): number => {
    if (idx1 < 0 || idx1 >= PATH_POINTS.length || idx2 < 0 || idx2 >= PATH_POINTS.length) return 0;
    return PATH_POINTS[idx1].distanceTo(PATH_POINTS[idx2]);
};

