// Helper: Distance from point P to segment AB
const getDistanceFromPointToSegment = (P: Vector3, A: Vector3, B: Vector3): number => {
    const AP = new Vector3().copy(P).sub(A);
    const AB = new Vector3().copy(B).sub(A);
    const magAB2 = AB.lengthSq();
    if (magAB2 === 0) return P.distanceTo(A);
    const t = Math.max(0, Math.min(1, AP.dot(AB) / magAB2));
    const closest = A.clone().add(AB.multiplyScalar(t));
    return P.distanceTo(closest);
};

// Helper to get position along path segments
const getPositionOnPath = (startIdx: number, progress: number): Vector3 => {
  if (startIdx >= PATH_POINTS.length - 1) return PATH_POINTS[PATH_POINTS.length - 1];
  const p1 = PATH_POINTS[startIdx];
  const p2 = PATH_POINTS[startIdx + 1];
  // Replace lerpVectors with copy().lerp() to avoid any potential prototype issues
  return new Vector3().copy(p1).lerp(p2, progress);
};

const getDistanceBetweenPoints = (idx1: number, idx2: number): number => {
    if (idx1 < 0 || idx1 >= PATH_POINTS.length || idx2 < 0 || idx2 >= PATH_POINTS.length) return 0;
    return PATH_POINTS[idx1].distanceTo(PATH_POINTS[idx2]);
};

