          // Bloon escaped
          onLivesChange(-config.rbe);
          enemy.distanceTraveled = 999999; // Mark for deletion
        } else {
          // Snap to new start
          enemy.position.copy(PATH_POINTS[enemy.waypointIndex]);
        }
      } else {
        // Interpolate
        enemy.position.copy(getPositionOnPath(enemy.waypointIndex, enemy.progress));
      }
    });

    // Remove escaped enemies
    enemiesRef.current = enemiesRef.current.filter(e => e.distanceTraveled < 999999);

    // 3. Tower Targeting & Firing
    const now = state.clock.elapsedTime;
    towersRef.current.forEach(tower => {
      const config = TOWERS[tower.type];

      if (now - tower.lastFired >= config.attackSpeed) {
        // Find Target: First (Furthest) Enemy in Range
        let target: BloonEntity | null = null;
        let maxDist = -1;

        for (const enemy of enemiesRef.current) {
          const dist = tower.position.distanceTo(enemy.position);
          if (dist <= config.range) {
            // First targeting priority (furthest traveled)
            if (enemy.distanceTraveled > maxDist) {
              maxDist = enemy.distanceTraveled;
              target = enemy;
            }
          }
        }

        if (target) {
          // Fire!
          tower.lastFired = now;

          // Special case for Tack Shooter: 8 projectiles
          if (tower.type === TowerType.TACK_SHOOTER) {
             for (let i = 0; i < 8; i++) {
                const angle = (i / 8) * Math.PI * 2;
                const vel = new Vector3(Math.cos(angle), 0, Math.sin(angle)).multiplyScalar(config.projectileSpeed);
                projectilesRef.current.push({
                    id: Math.random().toString(),
                    position: tower.position.clone().add(new Vector3(0, 0.5, 0)),
                    targetId: null, // Non-homing
                    velocity: vel,
                    damage: config.damage,
                    speed: config.projectileSpeed,
                    pierce: 1, // Basic pierce
                    color: 'black'
                });
             }
          } else {
            // Standard aimed projectile
            if (target.position && tower.position) {
              const dir = new Vector3().copy(target.position).sub(tower.position).normalize();
              projectilesRef.current.push({
                  id: Math.random().toString(),
                  position: tower.position.clone().add(new Vector3(0, 1, 0)),
                  targetId: target.id,
                  velocity: dir.multiplyScalar(config.projectileSpeed),
                  damage: config.damage,
                  speed: config.projectileSpeed,
                  pierce: 1 + (tower.type === TowerType.SNIPER_MONKEY ? 1 : 0),
                  color: tower.type === TowerType.SNIPER_MONKEY ? 'yellow' : 'brown'
              });
            }
          }
        }
      }
    });

    // 4. Projectile Movement & Collision
    const survivingProjectiles: ProjectileEntity[] = [];
    const newEnemies: BloonEntity[] = [];

    projectilesRef.current.forEach(proj => {
      // Sniper is hit-scan (instant), logic handled differently usually, but let's simulate very fast projectile for simplicity
      const moveDist = proj.speed * delta;

      // Update position
      const oldPos = proj.position.clone();
      proj.position.add(proj.velocity.clone().multiplyScalar(delta));

      // Collision Detection
      let hit = false;

      // Simple sphere collision
      for (let i = 0; i < enemiesRef.current.length; i++) {
        const enemy = enemiesRef.current[i];
        if (enemy.distanceTraveled >= 999999) continue; // Already dead/escaped this frame

        // Check distance to enemy
        const dist = proj.position.distanceTo(enemy.position);

        // Manual Line Segment collision check to avoid Line3 dependency
        const passedDist = getDistanceFromPointToSegment(enemy.position, oldPos, proj.position);

        if (dist < BLOONS[enemy.type].radius + 0.5 || passedDist < BLOONS[enemy.type].radius + 0.2) {
            // HIT!
            hit = true;
            proj.pierce--;

            // Damage Logic
            const bloonCfg = BLOONS[enemy.type];

            // Check immunity (Simplified)
            if (bloonCfg.type === BloonType.LEAD && proj.damage < 2) {
                 hit = false; 
                 proj.pierce++; // Refund pierce
                 continue;
            }

            // Pop Bloon
            onMoneyChange(1);

            // Spawn children
            const children = bloonCfg.children;
            if (children.length > 0) {
                // Spacing children slightly
                children.forEach((childType, idx) => {
                    newEnemies.push({
                        id: Math.random().toString(),
                        type: childType,
                        position: enemy.position.clone(),
                        waypointIndex: enemy.waypointIndex,
                        progress: enemy.progress - (idx * 0.01), // Slight stagger
                        distanceTraveled: enemy.distanceTraveled - (idx * 0.1),
                        frozen: false
                    });
                });
            }

            // Remove parent (mark for deletion)
            enemy.distanceTraveled = 999999; 

            if (proj.pierce <= 0) break; // Projectile destroyed
        }
      }

      // Keep projectile if it has pierce and hasn't flown too far
      if (proj.pierce > 0 && proj.position.length() < 100) {
        survivingProjectiles.push(proj);
      }
    });

    // Cleanup dead enemies and add new ones
    enemiesRef.current = enemiesRef.current.filter(e => e.distanceTraveled < 999999).concat(newEnemies);
    projectilesRef.current = survivingProjectiles;

  });

  // Handle Input
  const handlePlaneClick = (e: ThreeEvent<MouseEvent>) => {
    if (!selectedTower) return;

    // Check cost
    const cost = TOWERS[selectedTower].cost;
    if (money < cost) return;

    const pos = e.point.clone();
    pos.y = 0; // Snap to ground

    // Check collision with path
    let valid = true;
    for (let i = 0; i < PATH_POINTS.length - 1; i++) {
        const p1 = PATH_POINTS[i];
        const p2 = PATH_POINTS[i+1];
        // Manual distance check instead of Line3
        const dist = getDistanceFromPointToSegment(pos, p1, p2);

        if (dist < 1.5) { // 1.5 radius buffer from path
            valid = false;
            break;
        }
    }

    // Check collision with other towers
    if (valid) {
        for(const t of towersRef.current) {
            if (t.position.distanceTo(pos) < 1.0) {
                valid = false;
                break;
            }
        }
    }

    if (valid) {
        const newTower: TowerEntity = {
            id: Math.random().toString(),
            type: selectedTower,
            position: pos,
            lastFired: 0,
            range: TOWERS[selectedTower].range
        };
        towersRef.current.push(newTower);
        onPlaceTower(cost);
    }
  };

  const handlePointerMove = (e: ThreeEvent<PointerEvent>) => {
      setHoverPos(e.point.clone());
  };

  return (
    <>
      <ambientLight intensity={0.7} />
      <directionalLight position={[10, 20, 5]} intensity={1.5} castShadow />

      {/* MAP / GROUND */}
      <mesh 
        rotation={[-Math.PI / 2, 0, 0]} 
        position={[0, -0.1, 0]} 
        receiveShadow
        onClick={handlePlaneClick}
        onPointerMove={handlePointerMove}
      >
        <planeGeometry args={[60, 60]} />
        <meshStandardMaterial color="#4ade80" />
      </mesh>

      {/* PATH VISUALIZATION */}
      <Line 
        points={PATH_POINTS} 
        color="#d2b48c" 
        lineWidth={10} 
        position={[0, 0.05, 0]}
      />

      {/* START & END MARKERS */}
      <Text position={[PATH_POINTS[0].x, 1, PATH_POINTS[0].z]} fontSize={1} color="white" anchorX="center" anchorY="middle">
        START
      </Text>
      <Text position={[PATH_POINTS[PATH_POINTS.length-1].x, 1, PATH_POINTS[PATH_POINTS.length-1].z]} fontSize={1} color="red" anchorX="center" anchorY="middle">
        EXIT
      </Text>

      {/* ENEMIES */}
      {enemiesRef.current.map(enemy => (
        <mesh key={enemy.id} position={enemy.position}>
          <sphereGeometry args={[BLOONS[enemy.type].radius, 16, 16]} />
          <meshStandardMaterial color={BLOONS[enemy.type].color} />
        </mesh>
      ))}

      {/* TOWERS */}
      {towersRef.current.map(tower => (
        <group key={tower.id} position={tower.position}>
            {/* Base */}
            <mesh position={[0, 0.5, 0]}>
                <cylinderGeometry args={[0.5, 0.6, 1, 8]} />
                <meshStandardMaterial color={TOWERS[tower.type].color} />
            </mesh>
             {/* Head (indicator of type) */}
            <mesh position={[0, 1.0, 0]}>
                 <boxGeometry args={[0.4, 0.4, 0.4]} />
                 <meshStandardMaterial color="#333" />
            </mesh>
        </group>
      ))}

      {/* PROJECTILES */}
      {projectilesRef.current.map(proj => (
        <mesh key={proj.id} position={proj.position}>
           <sphereGeometry args={[0.15, 8, 8]} />
           <meshBasicMaterial color={proj.color} />
        </mesh>
      ))}

      {/* PLACEMENT PREVIEW */}
      {selectedTower && hoverPos && (
        <group position={[hoverPos.x, 0, hoverPos.z]}>
            {/* Range Circle */}
            <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, 0.05, 0]}>
                <ringGeometry args={[TOWERS[selectedTower].range - 0.1, TOWERS[selectedTower].range, 32]} />
                <meshBasicMaterial color="white" opacity={0.5} transparent />
            </mesh>
            <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, 0.05, 0]}>
                <circleGeometry args={[TOWERS[selectedTower].range, 32]} />
                <meshBasicMaterial color="white" opacity={0.1} transparent />
            </mesh>
            {/* Ghost Tower */}
            <mesh position={[0, 0.5, 0]}>
                <cylinderGeometry args={[0.5, 0.6, 1, 8]} />
                <meshStandardMaterial color={TOWERS[selectedTower].color} opacity={0.6} transparent />
            </mesh>
        </group>
      )}

      <OrbitControls 
        makeDefault 
        minDistance={10} 
        maxDistance={40} 
        maxPolarAngle={Math.PI / 3} // Prevent going under ground
        enableDamping
      />
    </>
  );
};

// 角色定义
export interface Character {
  name: string;
  role: 'Protagonist' | 'Antagonist' | 'Support' | 'Mob';
  personality: string; // 性格特征
  background: string; // 背景故事
  goal: string; // 目标
  cheat?: string; // 金手指/特殊能力 (仅主角有)
}

// 世界观设定
export interface WorldSetting {
  theme: string; // 如：赛博修仙、末世重生
  powerSystem: string; // 力量体系
  rules: string; // 世界核心规则
}

// 故事大纲节点
export interface PlotPoint {
  phase: string; // 阶段：开篇、发展、高潮、结尾
  summary: string; // 剧情概括
}

// 章节细纲
export interface ChapterOutline {
  chapterNumber: number;
  title: string;
  summary: string; // 故事梗概
  narrativePulse: string; // 叙事脉络
  coolPoint: string; // 本章爽点 (Cool Point)
  rules: string[]; // 必须遵守的规则/限制
}

// 章节正文
export interface ChapterContent {
  outline: ChapterOutline;
  content: string; // 生成的正文内容
  isGenerated: boolean;
}

// 应用当前的生成步骤
export enum GenerationStep {
  SETUP = 'SETUP',
  CHARACTERS = 'CHARACTERS',
  PLOT = 'PLOT',
  CHAPTER_PLAN = 'CHAPTER_PLAN',
  WRITING = 'WRITING'
}

// 导出的项目数据结构
export interface ProjectData {
  version: number;
  step: GenerationStep;
  bookTitle?: string; // 新增：书名
  prompt: string; // 保存初始脑洞
  world: WorldSetting | null;
  characters: Character[];
  plot: PlotPoint[];
  chapters: ChapterContent[];
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { Character, WorldSetting, PlotPoint, ChapterOutline } from "../types";

// 初始化 Gemini 客户端
// 必须确保环境变量 API_KEY 已设置
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// 使用逻辑推理能力最强的模型，保证故事连贯性
const MODEL_NAME = "gemini-3-pro-preview";

/**
 * 第一步：生成角色和世界观
 * 针对后宫爽文优化：要求生成多位高质量女性角色
 */
export const generateCharactersAndWorld = async (prompt: string): Promise<{ characters: Character[], world: WorldSetting }> => {
  console.log("正在请求 Gemini 生成后宫爽文人设和世界观...");

  const systemInstruction = `
    你是一位专门服务于中国年轻男性的网文大神，最擅长写"重生"、"都市/玄幻后宫"、"无敌流"爽文。
    你的文风要骚气、热血、直白，深谙读者的爽点。

    你的任务是根据用户的脑洞，设计一个极具吸引力的世界观和人物列表。

    【核心要求】
    1. **主角设定**：必须是男性，性格杀伐果断，不圣母，智商在线，拥有绝对逆天的金手指（系统、神器、前世记忆等）。
    2. **后宫团设定**：必须至少设计 3-4 位不同类型的**极品美女**作为主要配角（如：高冷校花、傲娇大小姐、温柔青梅、妩媚女总裁、绝美师尊等）。
       - 每个人物都要有极其惊艳的外貌描写关键词（黑丝、长腿、御姐等）。
       - 每个人物都要有明显的"反差萌"或独特的性格标签。
       - 初始对主角态度可以是鄙视或路人，方便后续攻略。
    3. **反派设定**：反派要嚣张跋扈，富二代或宗门圣子，专门用来给主角打脸，也就是"经验包"。
    4. **世界观**：要有等级森严的制度，方便主角通过升级来打破规则，装逼打脸。
  `;

  // 定义返回的 JSON 结构 Schema
  const responseSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      world: {
        type: Type.OBJECT,
        properties: {
          theme: { type: Type.STRING, description: "故事主题，如：都市重生修仙、校花贴身高手" },
          powerSystem: { type: Type.STRING, description: "力量/财富/地位等级划分，要清晰明确" },
          rules: { type: Type.STRING, description: "世界核心运行规则，或者主角必须遵守的系统规则" },
        },
        required: ["theme", "powerSystem", "rules"],
      },
      characters: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            role: { type: Type.STRING, enum: ["Protagonist", "Antagonist", "Support", "Mob"], description: "如果是后宫女主，请标记为 Support" },
            personality: { type: Type.STRING, description: "详细的性格描写，包括对主角的态度（如：暗恋、鄙视、依赖）" },
            background: { type: Type.STRING, description: "外貌描写（身材、颜值）及身份背景" },
            goal: { type: Type.STRING, description: "角色的核心诉求" },
            cheat: { type: Type.STRING, description: "主角的金手指（如：透视眼、签到系统），其他角色可留空" },
          },
          required: ["name", "role", "personality", "background", "goal"],
        },
      },
    },
    required: ["world", "characters"],
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.9, // 提高创造性，让美女设定更丰富
      },
    });

    const text = response.text;
    if (!text) throw new Error("API 返回为空");
    console.log("角色生成完成:", text);
    return JSON.parse(text);
  } catch (error) {
    console.error("生成角色失败:", error);
    throw error;
  }
};

/**
 * 第二步：生成主线大纲
 * 强调打脸节奏和感情线推进
 */
export const generateMainPlot = async (world: WorldSetting, characters: Character[]): Promise<PlotPoint[]> => {
  console.log("正在请求 Gemini 生成爽文主线大纲...");

  const charContext = characters.map(c => {
    let desc = `${c.name} (${c.role === 'Protagonist' ? '男主' : c.role === 'Antagonist' ? '反派' : '重要配角/女主'}): ${c.background}. 性格: ${c.personality}`;
    if (c.role === 'Support') desc += " [后宫预备/重要盟友]";
    return desc;
  }).join("\n");

  const worldContext = `世界: ${world.theme}. 力量体系: ${world.powerSystem}. 规则: ${world.rules}`;

  const prompt = `
    基于以下设定，生成一个让年轻男性读者热血沸腾的爽文主线大纲。

    【世界设定】
    ${worldContext}

    【人物设定】
    ${charContext}

    要求：
    1. **节奏紧凑**：分为 4-6 个关键大剧情节点。
    2. **核心爽点**：每个阶段必须包含"扮猪吃虎"、"人前显圣"或"强势打脸"的情节。
    3. **感情线**：必须穿插主角收服各路美女（女主）的过程，或者英雄救美、暧昧互动的情节。
    4. **目标明确**：从微末崛起，最终登顶世界巅峰，拥有无尽财富和权力。
  `;

  const responseSchema: Schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        phase: { type: Type.STRING, description: "阶段名称，如：重生归来、校花倾心、世家震怖、登顶巅峰" },
        summary: { type: Type.STRING, description: "该阶段的核心剧情概括，包含具体的打脸对象和收服的女主" },
      },
      required: ["phase", "summary"],
    },
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("API 返回为空");
    return JSON.parse(text);
  } catch (error) {
    console.error("生成大纲失败:", error);
    throw error;
  }
};

/**
 * 第三步：生成具体章节细纲 (批量生成前N章)
 * 增加"爽点"（Cool Point）的具体要求
 */
export const generateChapterOutlines = async (
  world: WorldSetting, 
  characters: Character[], 
  plot: PlotPoint[],
  count: number = 5
): Promise<ChapterOutline[]> => {
  console.log(`正在生成前 ${count} 章的细纲...`);

  const plotContext = plot.map(p => `[${p.phase}] ${p.summary}`).join("\n");
  const charContext = characters.map(c => `${c.name} (${c.role})`).join(", ");

  const prompt = `
    请根据主线大纲，规划前 ${count} 章的详细细纲。

    【主线大纲】
    ${plotContext}

    【人物】
    ${charContext}

    要求：
    1. **黄金三章法则**：
       - 第一章：必须有强烈的冲突（被退婚、被羞辱、重生节点），并结尾觉醒金手指。
       - 第二章：小试牛刀，利用金手指获得初步优势，震惊路人。
       - 第三章：第一个小高潮，打脸反派（或反派的小弟），收获第一位美女的好感。
    2. **爽点密集**：每一章都要有一个明确的"爽点"（Cool Point）或"期待感"（Hook）。
    3. **细致**：summary 字段要包含具体发生的事件，不要只写空话。
  `;

  const responseSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      chapters: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            chapterNumber: { type: Type.INTEGER },
            title: { type: Type.STRING, description: "极具吸引力的标题，如：震惊全场！、校花深夜来访" },
            summary: { type: Type.STRING, description: "详细的故事梗概，包含起承转合" },
            narrativePulse: { type: Type.STRING, description: "本章的情绪脉络：压抑->爆发，或者 暧昧->推倒" },
            coolPoint: { type: Type.STRING, description: "本章核心爽点，如：一拳秒杀、女神倒贴" },
            rules: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: "写作时的注意点，如：不要太啰嗦，多描写女主腿部细节" 
            },
          },
          required: ["chapterNumber", "title", "summary", "narrativePulse", "coolPoint", "rules"],
        },
      }
    },
    required: ["chapters"],
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("API 返回为空");
    const json = JSON.parse(text);
    return json.chapters as ChapterOutline[];
  } catch (error) {
    console.error("生成细纲失败:", error);
    throw error;
  }
};

/**
 * 3.5步：续写后续章节细纲
 */
