/**
 * 额外功能：生成书名
 */
export const generateBookTitles = async (
  promptText: string,
  world?: WorldSetting | null,
  characters?: Character[]
): Promise<string[]> => {
  console.log("正在生成书名...");

  // 构建上下文
  let context = `核心脑洞：${promptText}\n`;
  if (world) {
    context += `世界观主题：${world.theme}\n`;
    context += `力量体系：${world.powerSystem}\n`;
  }
  if (characters && characters.length > 0) {
    const protag = characters.find(c => c.role === 'Protagonist');
    if (protag) {
      context += `主角金手指：${protag.cheat}\n`;
      context += `主角性格：${protag.personality}\n`;
    }
  }

  const prompt = `
    你是一个精通中国网文市场的资深编辑。请根据以下小说设定，想出 10 个极具吸引力、符合"飞卢风"或"起点爽文风"的书名。

    【小说设定】
    ${context}

    【起名要求】
    1. **吸睛**：要包含"重生"、"开局"、"无敌"、"多子多福"、"校花"、"女帝"等热门关键词。
    2. **直白**：书名要能直接体现金手指或核心爽点。
    3. **格式**：不要加书名号，直接返回书名列表。
    4. **风格多样**：有的可以侧重系统，有的侧重后宫，有的侧重无敌。

    例如：
    - 重生都市：开局截胡校花机缘
    - 高武：因为太怕痛所以全点防御力了
    - 让你代管宗门，全成大帝了？
  `;

  const responseSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      titles: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
      },
    },
    required: ["titles"],
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.95,
      },
    });

    const text = response.text;
    if (!text) throw new Error("书名生成返回为空");
    const json = JSON.parse(text);
    return json.titles;
  } catch (error) {
    console.error("书名生成失败:", error);
    // 兜底返回一些通用书名
    return ["重生之逆天改命", "都市之最强仙尊", "开局一把刀", "我的系统太强了"];
  }
};

import React, { useState, useEffect } from 'react';
import { ChapterContent, Character, WorldSetting } from '../types';
import { streamChapterContent } from '../services/geminiService';
import ChapterReader from './ChapterReader';
import { FileText, Play, CheckCircle, Menu, X, Edit, Save, PlusCircle, Loader2, Sparkles, ArrowDown, RefreshCw, RotateCcw, CornerDownLeft } from 'lucide-react';

interface Props {
  chapters: ChapterContent[];
  world: WorldSetting;
  characters: Character[];
  onUpdateChapter: (index: number, content: string, isGenerated: boolean) => void;
  onUpdateTitle: (index: number, title: string) => void;
  onLoadMoreChapters: () => void; // 仅生成大纲
  onBatchGenerate: (count: number) => void; // 批量生成大纲+正文
  isLoadingMore: boolean; // 正在生成大纲状态
  batchProgress: string | null; // 批量生成正文进度提示，非空则表示正在生成
}

const StepWriting: React.FC<Props> = ({ 
  chapters, 
  world, 
  characters, 
  onUpdateChapter, 
  onUpdateTitle, 
  onLoadMoreChapters, 
  onBatchGenerate,
  isLoadingMore,
  batchProgress
}) => {
  const [activeChapterIndex, setActiveChapterIndex] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  // 默认设为 false，移动端初始隐藏侧边栏，桌面端通过 CSS (md:translate-x-0) 保持显示
  const [showSidebar, setShowSidebar] = useState(false); 
  const [isEditing, setIsEditing] = useState(false);

  // 重写功能相关状态
  const [showRewriteModal, setShowRewriteModal] = useState(false);
  const [rewriteInstructions, setRewriteInstructions] = useState("");

  // 撤销历史记录: Key为章节索引, Value为重写前的内容
  const [undoHistory, setUndoHistory] = useState<Record<number, string>>({});

  // 章节跳转输入状态
  const [jumpInput, setJumpInput] = useState("");

  const activeChapter = chapters[activeChapterIndex];

  // 切换章节时，滚动到顶部，关闭编辑模式，如果是移动端则关闭侧边栏
  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setIsEditing(false);
  }, [activeChapterIndex]);

  // 原始的生成入口，不带指令
  const handleGenerate = async () => {
    if (isGenerating || activeChapter.isGenerated) return;
    startGeneration();
  };

  // 重写确认入口
  const handleRewrite = async () => {
    if (isGenerating) return;

    // 保存当前内容到历史记录，以便撤销
    if (activeChapter.content) {
      setUndoHistory(prev => ({
        ...prev,
        [activeChapterIndex]: activeChapter.content
      }));
    }

    setShowRewriteModal(false);
    startGeneration(rewriteInstructions);
    setRewriteInstructions(""); // 清空指令
  };

  // 撤销重写
  const handleUndoRewrite = () => {
    const prevContent = undoHistory[activeChapterIndex];
    if (!prevContent) return;

    if (window.confirm("确定要撤销重写，恢复到上一个版本吗？当前版本将丢失。")) {
      onUpdateChapter(activeChapterIndex, prevContent, true);
      // 恢复后清除该章的历史记录，避免无限撤销（或者保留以支持多次切换，这里选择清除表示“已恢复”）
      setUndoHistory(prev => {
        const newState = { ...prev };
        delete newState[activeChapterIndex];
        return newState;
      });
    }
  };

  // 章节跳转逻辑
  const handleJumpToChapter = () => {
    const target = parseInt(jumpInput);
    if (isNaN(target)) return;

    // 检查范围 (输入 1 代表第 1 章，索引为 0)
    if (target < 1 || target > chapters.length) {
      alert(`请输入有效章节号 (1-${chapters.length})`);
      return;
    }

    setActiveChapterIndex(target - 1);
    setJumpInput(""); // 清空输入
    if (window.innerWidth < 768) setShowSidebar(false); // 移动端跳转后关闭侧边栏
  };

  const handleJumpKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleJumpToChapter();
    }
  };

  // 统一的生成/重写逻辑
  const startGeneration = async (instructions?: string) => {
    setIsGenerating(true);
    setIsEditing(false);

    // 移动端生成开始时，自动收起侧边栏以便查看生成过程
    if (window.innerWidth < 768) {
        setShowSidebar(false);
    }

    // 获取上一章的上下文（优先使用正文，其次是大纲摘要）
    // 这样能确保 AI 重写或生成新章节时，能紧密衔接上一章的细节
    let prevContext = "";
    if (activeChapterIndex > 0) {
      const prevChap = chapters[activeChapterIndex - 1];
      prevContext = prevChap.content || prevChap.outline.summary;
    }

    try {
      // 如果是重写，先清空当前内容，让用户看到重新生成的过程
      if (instructions) {
         onUpdateChapter(activeChapterIndex, "", false); 
      }

      let fullText = "";
      // 使用流式接口，体验更好
      await streamChapterContent(
        activeChapter.outline,
        world,
        characters,
        prevContext,
        (textChunk) => {
          fullText += textChunk;
          onUpdateChapter(activeChapterIndex, fullText, false);
        },
        instructions // 传入可选的修订指令
      );

      onUpdateChapter(activeChapterIndex, fullText, true);

    } catch (e) {
      alert("生成中断，请重试");
    } finally {
      setIsGenerating(false);
    }
  };

  if (!activeChapter) return <div>数据加载中...</div>;

  const isBatchGenerating = batchProgress !== null;
  const canUndo = !!undoHistory[activeChapterIndex];

  return (
    <div className="flex h-[calc(100vh-100px)] overflow-hidden rounded-xl border border-gray-800 bg-gray-950 relative">

      {/* 重写设置模态框 */}
      {showRewriteModal && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[60] flex items-center justify-center p-4">
           <div className="bg-gray-900 border border-gray-700 rounded-xl p-6 w-full max-w-lg shadow-2xl animate-in fade-in zoom-in duration-200 flex flex-col max-h-[90vh]">
              <h3 className="text-xl font-bold text-white mb-2 flex items-center gap-2 shrink-0">
                  <RefreshCw className="text-indigo-400" size={20} />
                  重写本章
              </h3>

              <div className="overflow-y-auto mb-4 custom-scrollbar pr-2">
                 {/* 大纲摘要展示区 */}
                 <div className="bg-gray-800/50 rounded-lg p-3 mb-4 border border-gray-700">
                    <span className="text-xs font-bold text-indigo-400 uppercase tracking-wider block mb-1">当前大纲摘要</span>
                    <p className="text-sm text-gray-300 leading-relaxed">
                      {activeChapter.outline.summary}
                    </p>
                 </div>

                 <p className="text-sm text-gray-400 mb-2">
                     AI 将根据上述大纲重新撰写正文。您可以输入具体的修改意见，AI会重点关注。
                 </p>
              </div>

              <textarea 
                  className="w-full h-32 bg-gray-950 border border-gray-700 rounded-lg p-3 text-gray-200 focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none resize-none placeholder-gray-600 text-sm shrink-0" 
                  placeholder="例如：这一章的打斗细节太少了，多描写一下招式；或者，女主的反应再害羞一点..."
                  value={rewriteInstructions}
                  onChange={(e) => setRewriteInstructions(e.target.value)}
                  autoFocus
              />
              <div className="flex justify-end gap-3 mt-6 shrink-0">
                  <button 
                    onClick={() => setShowRewriteModal(false)} 
                    className="px-4 py-2 rounded-lg text-gray-400 hover:text-white hover:bg-gray-800 transition-colors text-sm"
                  >
                    取消
                  </button>
                  <button 
                    onClick={handleRewrite} 
                    className="px-4 py-2 rounded-lg bg-indigo-600 hover:bg-indigo-500 text-white font-bold shadow-lg shadow-indigo-500/20 text-sm flex items-center gap-2"
                  >
                    <RefreshCw size={14} />
                    开始重写
                  </button>
              </div>
           </div>
        </div>
      )}

      {/* 移动端遮罩层：当侧边栏打开时显示，点击关闭 */}
      {showSidebar && (
        <div 
          className="fixed inset-0 bg-black/60 backdrop-blur-sm z-30 md:hidden transition-opacity"
          onClick={() => setShowSidebar(false)}
        />
      )}

      {/* 移动端悬浮菜单按钮 */}
      <button 
        className="md:hidden fixed bottom-6 right-6 z-50 bg-indigo-600 hover:bg-indigo-500 text-white p-4 rounded-full shadow-xl shadow-indigo-900/50 transition-all active:scale-95 flex items-center justify-center"
        onClick={() => setShowSidebar(!showSidebar)}
        title={showSidebar ? "关闭目录" : "打开目录"}
      >
        {showSidebar ? <X size={24} /> : <Menu size={24} />}
      </button>

      {/* Sidebar - Chapter List */}
      <div className={`
        fixed md:relative z-40 w-72 max-w-[80vw] bg-gray-900 border-r border-gray-800 h-full flex flex-col transition-transform duration-300 ease-in-out shadow-2xl md:shadow-none
        ${showSidebar ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
      `}>
        <div className="p-4 border-b border-gray-800 bg-gray-900 font-bold text-gray-200 flex justify-between items-center shrink-0">
          <span>目录 ({chapters.length}章)</span>
          {/* 移动端侧边栏内部关闭按钮 */}
          <button 
            onClick={() => setShowSidebar(false)}
            className="md:hidden text-gray-500 hover:text-white"
          >
            <X size={20} />
          </button>
        </div>

        {/* Jump to Chapter Input */}
        <div className="px-3 py-2 border-b border-gray-800 bg-gray-900/50 shrink-0">
          <div className="flex gap-2">
            <input 
              type="number" 
              className="w-full bg-gray-950 border border-gray-700 rounded text-sm px-2 py-1 text-gray-300 focus:border-indigo-500 outline-none placeholder-gray-600"
              placeholder="前往章节..."
              value={jumpInput}
              onChange={(e) => setJumpInput(e.target.value)}
              onKeyDown={handleJumpKeyDown}
              min={1}
              max={chapters.length}
            />
            <button 
              onClick={handleJumpToChapter}
              disabled={!jumpInput}
              className="bg-gray-800 hover:bg-gray-700 border border-gray-700 text-gray-400 hover:text-white px-2 rounded transition-colors disabled:opacity-50"
              title="跳转"
            >
              <CornerDownLeft size={16} />
            </button>
          </div>
        </div>

        {/* Scrollable List */}
        <div className="overflow-y-auto flex-1 p-2 space-y-2">
          {chapters.map((chap, idx) => (
            <React.Fragment key={idx}>
              <button
                id={`chapter-item-${idx}`} 
                onClick={() => {
                  setActiveChapterIndex(idx);
                  // 选中后在移动端自动关闭侧边栏
                  if (window.innerWidth < 768) setShowSidebar(false);
                }}
                className={`w-full text-left p-3 rounded-lg text-sm transition-all flex items-start gap-2
                  ${activeChapterIndex === idx 
                    ? 'bg-indigo-900/40 border border-indigo-500/30 text-indigo-200' 
                    : 'hover:bg-gray-800 text-gray-400 border border-transparent'}
                `}
              >
                <div className="mt-0.5 shrink-0">
                  {chap.isGenerated ? <CheckCircle size={14} className="text-green-500" /> : <FileText size={14} />}
                </div>
                <div className="min-w-0">
                  <div className="font-semibold truncate">第{chap.outline.chapterNumber}章: {chap.outline.title}</div>
                  <div className="text-xs text-gray-500 mt-1 truncate">{chap.outline.coolPoint}</div>
                </div>
              </button>
            </React.Fragment>
          ))}
        </div>

        {/* Sidebar Footer: Add More Chapters */}
        <div className="p-3 border-t border-gray-800 bg-gray-900 shrink-0 space-y-2">
          {/* 状态提示区域 */}
          {isBatchGenerating && (
             <div className="text-xs text-indigo-400 flex items-center gap-2 bg-indigo-900/20 p-2 rounded mb-2">
                <Loader2 size={12} className="animate-spin" />
                {batchProgress}
             </div>
          )}

          {/* 批量生成按钮 */}
          <button
            onClick={() => onBatchGenerate(5)}
            disabled={isLoadingMore || isBatchGenerating}
            className="w-full py-2.5 rounded-lg bg-indigo-600 hover:bg-indigo-500 text-white shadow-lg shadow-indigo-900/30 transition-all flex items-center justify-center gap-2 text-sm font-bold disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isBatchGenerating ? (
              <>
                <Loader2 size={16} className="animate-spin" />
                自动码字中...
              </>
            ) : (
              <>
                <Sparkles size={16} />
                一键生成后续5章
              </>
            )}
          </button>

           <button
            onClick={onLoadMoreChapters}
            disabled={isLoadingMore || isBatchGenerating}
            className="w-full py-2 rounded-lg border border-dashed border-gray-600 text-gray-400 hover:text-white hover:border-indigo-500 hover:bg-gray-800 transition-all flex items-center justify-center gap-2 text-xs font-medium"
          >
            {isLoadingMore ? (
              <>
                <Loader2 size={14} className="animate-spin" />
                推演中...
              </>
            ) : (
              <>
                <PlusCircle size={14} />
                仅生成后续5章大纲
              </>
            )}
          </button>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col h-full overflow-hidden relative bg-black/20">
        {/* Info Header */}
        <div className="p-4 border-b border-gray-800 bg-gray-850 flex justify-between items-start md:items-center flex-col md:flex-row gap-4 shrink-0">
          <div className="w-full md:w-auto">
             <h3 className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">本章脉络 & 规则</h3>
             <p className="text-sm text-gray-300 line-clamp-2 md:line-clamp-1">
               <span className="text-indigo-400">[{activeChapter.outline.narrativePulse}]</span> {activeChapter.outline.rules.join(" | ")}
             </p>
          </div>

          <div className="flex items-center gap-3 self-end md:self-auto shrink-0">
             {/* Undo Button */}
            {canUndo && !isGenerating && !isBatchGenerating && (
                <button
                    onClick={handleUndoRewrite}
                    className="px-3 py-2 rounded-lg bg-gray-800 hover:bg-gray-700 text-orange-400 border border-orange-500/30 transition-all flex items-center gap-2 text-sm md:text-base font-medium"
                    title="恢复重写前的内容"
                >
                    <RotateCcw size={16} />
                    <span className="hidden sm:inline">撤销重写</span>
                </button>
            )}

            {/* Rewrite Button - Only if generated and not generating */}
            {activeChapter.isGenerated && !isGenerating && !isBatchGenerating && (
                <button
                    onClick={() => setShowRewriteModal(true)}
                    className="px-3 py-2 rounded-lg bg-gray-800 hover:bg-gray-700 text-indigo-300 border border-indigo-500/30 transition-all flex items-center gap-2 text-sm md:text-base font-medium"
                    title="重写本章"
                >
                    <RefreshCw size={16} />
                    <span className="hidden sm:inline">重写</span>
                </button>
            )}

            {/* Edit Toggle Button */}
            {(activeChapter.content || activeChapter.isGenerated) && !isGenerating && !isBatchGenerating && (
              <button
                onClick={() => setIsEditing(!isEditing)}
                className={`px-4 py-2 rounded-lg flex items-center gap-2 font-bold transition-all border text-sm md:text-base
                  ${isEditing 
                    ? 'bg-green-600/20 text-green-400 border-green-500/50 hover:bg-green-600/30' 
                    : 'bg-gray-800 hover:bg-gray-700 text-gray-300 border-gray-700'
                  }`}
              >
                {isEditing ? (
                  <>
                    <Save size={16} />
                    <span className="hidden sm:inline">完成</span>
                  </>
                ) : (
                  <>
                    <Edit size={16} />
                    <span className="hidden sm:inline">修改</span>
                  </>
                )}
              </button>
            )}

            {/* Generate Button */}
            {(!activeChapter.isGenerated && !activeChapter.content) && (
              <button
                onClick={handleGenerate}
                disabled={isGenerating || isBatchGenerating}
                className="px-5 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg flex items-center gap-2 font-bold shadow-lg shadow-indigo-500/20 whitespace-nowrap text-sm md:text-base disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {isGenerating ? '创作中...' : (isBatchGenerating ? '批量任务进行中...' : '生成正文')}
                {!isGenerating && !isBatchGenerating && <Play size={16} fill="currentColor" />}
              </button>
            )}
          </div>
        </div>

        {/* Scrollable Reader / Editor */}
        <div className="flex-1 overflow-y-auto p-4 md:p-8">
          <div className="max-w-3xl mx-auto h-full pb-24">
             {isEditing ? (
               <div className="h-full min-h-[600px] bg-gray-900 p-4 md:p-8 rounded-xl border border-indigo-500/30 shadow-2xl flex flex-col animate-in fade-in duration-300">
                 <div className="mb-4 pb-4 border-b border-gray-800 flex flex-col gap-2">
                    <div className="flex justify-between items-center text-xs text-gray-500 uppercase tracking-wider font-bold">
                        <span>正在编辑: 第{activeChapter.outline.chapterNumber}章</span>
                        <span className={activeChapter.content.length > 2000 ? 'text-green-500' : 'text-gray-500'}>
                            {activeChapter.content.length} 字
                        </span>
                    </div>
                    <input 
                        type="text" 
                        value={activeChapter.outline.title}
                        onChange={(e) => onUpdateTitle(activeChapterIndex, e.target.value)}
                        className="bg-transparent text-xl md:text-2xl font-serif font-bold text-white border-b border-gray-700 focus:border-indigo-500 outline-none py-1 transition-colors placeholder-gray-700"
                        placeholder="输入章节标题..."
                    />
                 </div>
                 <textarea 
                   className="w-full flex-1 bg-transparent border-none outline-none text-gray-200 font-serif text-base md:text-lg leading-loose resize-none focus:ring-0"
                   value={activeChapter.content}
                   onChange={(e) => onUpdateChapter(activeChapterIndex, e.target.value, true)} 
                   placeholder="在此输入章节正文..."
                   spellCheck={false}
                   autoFocus
                 />
               </div>
             ) : (
               <>
                 <ChapterReader 
                   title={`第${activeChapter.outline.chapterNumber}章 ${activeChapter.outline.title}`}
                   content={activeChapter.content}
                   isStreaming={isGenerating && activeChapterIndex === chapters.findIndex(c => c === activeChapter)}
                 />

                 {/* Bottom Actions Area - Always show at bottom of content */}
                 <div className="mt-12 mb-8 text-center space-y-6">
                    {/* Case 1: Not the last chapter -> Next Chapter Button */}
                    {activeChapter.isGenerated && activeChapterIndex < chapters.length - 1 && (
                       <button
                         onClick={() => setActiveChapterIndex(prev => prev + 1)}
                         className="text-gray-400 hover:text-white underline decoration-indigo-500 underline-offset-4 py-4 px-8 text-lg transition-all flex items-center gap-2 mx-auto"
                       >
                         继续下一章
                         <ArrowDown size={16} />
                       </button>
                    )}

                    {/* Case 2: Last Chapter & Generated -> Batch Generate Button */}
                    {activeChapter.isGenerated && activeChapterIndex === chapters.length - 1 && (
                        <div className="flex flex-col items-center justify-center gap-4 py-8 border-t border-gray-800/50">
                            <p className="text-gray-500 text-sm">当前剧情已至最新，是否继续推演后续发展？</p>
                            <button
                                onClick={() => onBatchGenerate(5)}
                                disabled={isLoadingMore || isBatchGenerating}
                                className="px-8 py-4 bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 text-white rounded-xl font-bold shadow-xl shadow-indigo-900/40 flex items-center gap-3 transition-all transform hover:scale-105 disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none"
                            >
                                {isBatchGenerating ? (
                                    <>
                                        <Loader2 size={24} className="animate-spin" />
                                        <span className="text-lg">AI正在疯狂码字中...</span>
                                    </>
                                ) : (
                                    <>
                                        <Sparkles size={24} />
                                        <span className="text-lg">一键生成后续5章 (大纲+正文)</span>
                                    </>
                                )}
                            </button>
                            {!isBatchGenerating && (
                                <p className="text-xs text-gray-600">
                                    * 将根据当前剧情自动规划大纲并撰写正文
                                </p>
                            )}
                        </div>
                    )}
                 </div>
               </>
             )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default StepWriting;

// 角色定义
export interface Character {
  name: string;
  role: 'Protagonist' | 'Antagonist' | 'Support' | 'Mob';
  personality: string; // 性格特征
  background: string; // 背景故事
  goal: string; // 目标
  cheat?: string; // 金手指/特殊能力 (仅主角有)
}

// 世界观设定
export interface WorldSetting {
  theme: string; // 如：赛博修仙、末世重生
  powerSystem: string; // 力量体系
  rules: string; // 世界核心规则
}

// 故事大纲节点
export interface PlotPoint {
  phase: string; // 阶段：开篇、发展、高潮、结尾
  summary: string; // 剧情概括
}

// 章节细纲
export interface ChapterOutline {
  chapterNumber: number;
  title: string;
  summary: string; // 故事梗概
  narrativePulse: string; // 叙事脉络
  coolPoint: string; // 本章爽点 (Cool Point)
  rules: string[]; // 必须遵守的规则/限制
  groupSummary?: string; // 新增：每5章的卷/段落小标题
}

// 章节正文
export interface ChapterContent {
  outline: ChapterOutline;
  content: string; // 生成的正文内容
  isGenerated: boolean;
}

// 应用当前的生成步骤
export enum GenerationStep {
  SETUP = 'SETUP',
  CHARACTERS = 'CHARACTERS',
  PLOT = 'PLOT',
  CHAPTER_PLAN = 'CHAPTER_PLAN',
  WRITING = 'WRITING'
}

// 导出的项目数据结构
export interface ProjectData {
  version: number;
  step: GenerationStep;
  bookTitle?: string; // 新增：书名
  prompt: string; // 保存初始脑洞
  world: WorldSetting | null;
  characters: Character[];
  plot: PlotPoint[];
  chapters: ChapterContent[];
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { Character, WorldSetting, PlotPoint, ChapterOutline } from "../types";

// 初始化 Gemini 客户端
// 必须确保环境变量 API_KEY 已设置
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// 使用逻辑推理能力最强的模型，保证故事连贯性
const MODEL_NAME = "gemini-3-pro-preview";

/**
 * 第一步：生成角色和世界观
 * 针对后宫爽文优化：要求生成多位高质量女性角色
 */
export const generateCharactersAndWorld = async (prompt: string): Promise<{ characters: Character[], world: WorldSetting }> => {
  console.log("正在请求 Gemini 生成后宫爽文人设和世界观...");

  const systemInstruction = `
    你是一位专门服务于中国年轻男性的网文大神，最擅长写"重生"、"都市/玄幻后宫"、"无敌流"爽文。
    你的文风要骚气、热血、直白，深谙读者的爽点。

    你的任务是根据用户的脑洞，设计一个极具吸引力的世界观和人物列表。

    【核心要求】
    1. **主角设定**：必须是男性，性格杀伐果断，不圣母，智商在线，拥有绝对逆天的金手指（系统、神器、前世记忆等）。
    2. **后宫团设定**：必须至少设计 3-4 位不同类型的**极品美女**作为主要配角（如：高冷校花、傲娇大小姐、温柔青梅、妩媚女总裁、绝美师尊等）。
       - 每个人物都要有极其惊艳的外貌描写关键词（黑丝、长腿、御姐等）。
       - 每个人物都要有明显的"反差萌"或独特的性格标签。
       - 初始对主角态度可以是鄙视或路人，方便后续攻略。
    3. **反派设定**：反派要嚣张跋扈，富二代或宗门圣子，专门用来给主角打脸，也就是"经验包"。
    4. **世界观**：要有等级森严的制度，方便主角通过升级来打破规则，装逼打脸。
  `;

  // 定义返回的 JSON 结构 Schema
  const responseSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      world: {
        type: Type.OBJECT,
        properties: {
          theme: { type: Type.STRING, description: "故事主题，如：都市重生修仙、校花贴身高手" },
          powerSystem: { type: Type.STRING, description: "力量/财富/地位等级划分，要清晰明确" },
          rules: { type: Type.STRING, description: "世界核心运行规则，或者主角必须遵守的系统规则" },
        },
        required: ["theme", "powerSystem", "rules"],
      },
      characters: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            role: { type: Type.STRING, enum: ["Protagonist", "Antagonist", "Support", "Mob"], description: "如果是后宫女主，请标记为 Support" },
            personality: { type: Type.STRING, description: "详细的性格描写，包括对主角的态度（如：暗恋、鄙视、依赖）" },
            background: { type: Type.STRING, description: "外貌描写（身材、颜值）及身份背景" },
            goal: { type: Type.STRING, description: "角色的核心诉求" },
            cheat: { type: Type.STRING, description: "主角的金手指（如：透视眼、签到系统），其他角色可留空" },
          },
          required: ["name", "role", "personality", "background", "goal"],
        },
      },
    },
    required: ["world", "characters"],
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.9, // 提高创造性，让美女设定更丰富
      },
    });

    const text = response.text;
    if (!text) throw new Error("API 返回为空");
    console.log("角色生成完成:", text);
    return JSON.parse(text);
  } catch (error) {
    console.error("生成角色失败:", error);
    throw error;
  }
};

/**
 * 第二步：生成主线大纲
 * 强调打脸节奏和感情线推进
 */
export const generateMainPlot = async (world: WorldSetting, characters: Character[]): Promise<PlotPoint[]> => {
  console.log("正在请求 Gemini 生成爽文主线大纲...");

  const charContext = characters.map(c => {
    let desc = `${c.name} (${c.role === 'Protagonist' ? '男主' : c.role === 'Antagonist' ? '反派' : '重要配角/女主'}): ${c.background}. 性格: ${c.personality}`;
    if (c.role === 'Support') desc += " [后宫预备/重要盟友]";
    return desc;
  }).join("\n");

  const worldContext = `世界: ${world.theme}. 力量体系: ${world.powerSystem}. 规则: ${world.rules}`;

  const prompt = `
    基于以下设定，生成一个让年轻男性读者热血沸腾的爽文主线大纲。

    【世界设定】
    ${worldContext}

    【人物设定】
    ${charContext}

    要求：
    1. **节奏紧凑**：分为 4-6 个关键大剧情节点。
    2. **核心爽点**：每个阶段必须包含"扮猪吃虎"、"人前显圣"或"强势打脸"的情节。
    3. **感情线**：必须穿插主角收服各路美女（女主）的过程，或者英雄救美、暧昧互动的情节。
    4. **目标明确**：从微末崛起，最终登顶世界巅峰，拥有无尽财富和权力。
  `;

  const responseSchema: Schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        phase: { type: Type.STRING, description: "阶段名称，如：重生归来、校花倾心、世家震怖、登顶巅峰" },
        summary: { type: Type.STRING, description: "该阶段的核心剧情概括，包含具体的打脸对象和收服的女主" },
      },
      required: ["phase", "summary"],
    },
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("API 返回为空");
    return JSON.parse(text);
  } catch (error) {
    console.error("生成大纲失败:", error);
    throw error;
  }
};

/**
 * 第三步：生成具体章节细纲 (批量生成前N章)
 * 增加"爽点"（Cool Point）的具体要求
 */
export const generateChapterOutlines = async (
  world: WorldSetting, 
  characters: Character[], 
  plot: PlotPoint[],
  count: number = 5
): Promise<ChapterOutline[]> => {
  console.log(`正在生成前 ${count} 章的细纲...`);

  const plotContext = plot.map(p => `[${p.phase}] ${p.summary}`).join("\n");
  const charContext = characters.map(c => `${c.name} (${c.role})`).join(", ");

  const prompt = `
    请根据主线大纲，规划前 ${count} 章的详细细纲。

    【主线大纲】
    ${plotContext}

    【人物】
    ${charContext}

    要求：
    1. **黄金三章法则**：
       - 第一章：必须有强烈的冲突（被退婚、被羞辱、重生节点），并结尾觉醒金手指。
       - 第二章：小试牛刀，利用金手指获得初步优势，震惊路人。
       - 第三章：第一个小高潮，打脸反派（或反派的小弟），收获第一位美女的好感。
    2. **爽点密集**：每一章都要有一个明确的"爽点"（Cool Point）或"期待感"（Hook）。
    3. **细致**：summary 字段要包含具体发生的事件，不要只写空话。
  `;

  const responseSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      chapters: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            chapterNumber: { type: Type.INTEGER },
            title: { type: Type.STRING, description: "极具吸引力的标题，如：震惊全场！、校花深夜来访" },
            summary: { type: Type.STRING, description: "详细的故事梗概，包含起承转合" },
            narrativePulse: { type: Type.STRING, description: "本章的情绪脉络：压抑->爆发，或者 暧昧->推倒" },
            coolPoint: { type: Type.STRING, description: "本章核心爽点，如：一拳秒杀、女神倒贴" },
            rules: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: "写作时的注意点，如：不要太啰嗦，多描写女主腿部细节" 
            },
          },
          required: ["chapterNumber", "title", "summary", "narrativePulse", "coolPoint", "rules"],
        },
      }
    },
    required: ["chapters"],
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("API 返回为空");
    const json = JSON.parse(text);
    return json.chapters as ChapterOutline[];
  } catch (error) {
    console.error("生成细纲失败:", error);
    throw error;
  }
};

/**
 * 3.5步：续写后续章节细纲
 */
export const generateNextChapterOutlines = async (
  world: WorldSetting,
  characters: Character[],
  plot: PlotPoint[],
  lastChapter: ChapterOutline,
  count: number = 5
): Promise<ChapterOutline[]> => {
  const nextStart = lastChapter.chapterNumber + 1;
  console.log(`正在续写第 ${nextStart} - ${nextStart + count - 1} 章的细纲...`);

  const plotContext = plot.map(p => `[${p.phase}] ${p.summary}`).join("\n");

  const prompt = `
    你正在创作一部长篇爽文。目前已完成到第 ${lastChapter.chapterNumber} 章。

    【当前进度】
    上一章标题：${lastChapter.title}
    上一章剧情：${lastChapter.summary}

    【主线大纲】
    ${plotContext}

    请继续规划接下来的 ${count} 章（第 ${nextStart} 章 到 第 ${nextStart + count - 1} 章）的细纲。

    要求：
    1. **承上启下**：紧接上一章的剧情发展，不要断层。
    2. **升级节奏**：主角的能力要逐步体现，遇到的敌人要越来越强（或者背景越来越深）。
    3. **期待感**：每一章结尾都要留钩子。
    4. **后宫互动**：如果没有打斗，就安排暧昧情节。
  `;

  const responseSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      chapters: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            chapterNumber: { type: Type.INTEGER },
            title: { type: Type.STRING },
            summary: { type: Type.STRING },
            narrativePulse: { type: Type.STRING },
            coolPoint: { type: Type.STRING },
            rules: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
            },
          },
          required: ["chapterNumber", "title", "summary", "narrativePulse", "coolPoint", "rules"],
        },
      }
    },
    required: ["chapters"],
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("API 返回为空");
    const json = JSON.parse(text);
    return json.chapters as ChapterOutline[];
  } catch (error) {
    console.error("续写细纲失败:", error);
    throw error;
  }
}

/**
 * 额外功能：生成5章剧情小结标题
 */
