        responseSchema: responseSchema,
        safetySettings: SAFETY_SETTINGS,
      },
    });

    const text = response.text;
    if (!text) throw new Error("API 返回为空");
    const json = JSON.parse(text);
    return json.chapters as ChapterOutline[];
