  console.log("正在生成段落小结标题...");

  const context = chapters.map(c => `第${c.chapterNumber}章：${c.title} - ${c.summary}`).join("\n");

  const prompt = `
    阅读以下 5 个章节的剧情梗概，提炼出一个极具吸引力的“卷标”或“段落小标题”。

    【剧情内容】
    ${context}

    【要求】
