    3. **输出**：直接返回标题字符串，不要加书名号或其他符号。
  `;

  const responseSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      summaryTitle: { type: Type.STRING, description: "20字以内的剧情小结标题" }
    },
    required: ["summaryTitle"]
  };

  try {
    // 关键修复：
    // 1. 切换到 gemini-3-flash-preview 模型，速度快且对简单任务（如总结）的审查不那么敏感
    // 2. 必须加上 safetySettings，否则包含"杀戮"或"后宫"的剧情会被 API 拦截返回空
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview", 
