import React, { useState } from 'react';
import ReactMarkdown from 'react-markdown';
import { Copy, Check } from 'lucide-react';

interface Props {
  title: string;
  content: string;
  isStreaming: boolean;
}

const ChapterReader: React.FC<Props> = ({ title, content, isStreaming }) => {
  const [copied, setCopied] = useState(false);
  const [titleCopied, setTitleCopied] = useState(false);

  const handleCopy = () => {
    if (!content) return;
    // 将连续的换行符(包括多个空行)替换为单个换行符，压缩排版
    const compressedContent = content.replace(/\n+/g, '\n');
    navigator.clipboard.writeText(`${title}\n\n${compressedContent}`);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleCopyTitle = () => {
    navigator.clipboard.writeText(title);
    setTitleCopied(true);
    setTimeout(() => setTitleCopied(false), 2000);
  };

  return (
    <div className="w-full bg-gray-900 min-h-[600px] p-8 rounded-xl shadow-2xl border border-gray-800 relative group">
      {/* 顶部工具栏 */}
      <div className="absolute top-6 right-6 z-10">
        <button
          onClick={handleCopy}
          disabled={!content}
          className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm font-medium transition-all backdrop-blur-md border border-gray-700 
