export default ChapterReader;

import React, { useState, useEffect, useRef } from 'react';
import { GenerationStep, Character, WorldSetting, PlotPoint, ChapterContent, ProjectData } from './types';
import { generateCharactersAndWorld, generateMainPlot, generateChapterOutlines, generateNextChapterOutlines, generateFullChapterContent } from './services/geminiService';
import StepSetup from './components/StepSetup';
import StepCharacters from './components/StepCharacters';
import StepPlot from './components/StepPlot';
import StepWriting from './components/StepWriting';
import TitleGeneratorModal from './components/TitleGeneratorModal';
import { Download, Upload, Save, FileJson, FilePlus, PenLine } from 'lucide-react';

const STORAGE_KEY = 'soulwriter_autosave_v1';

const App: React.FC = () => {
  // 核心状态
  const [step, setStep] = useState<GenerationStep>(GenerationStep.SETUP);
  const [isLoading, setIsLoading] = useState(false);
  const [isLoadedFromStorage, setIsLoadedFromStorage] = useState(false);
  const [batchProgress, setBatchProgress] = useState<string | null>(null); // null表示不在批量生成中

  // Data State
  const [prompt, setPrompt] = useState("重生回到十年前，觉醒了'万物增幅'系统，这一世我要在这个赛博朋克与古武并存的世界成为最强。");
  const [bookTitle, setBookTitle] = useState("");
  const [world, setWorld] = useState<WorldSetting | null>(null);
  const [characters, setCharacters] = useState<Character[]>([]);
  const [plot, setPlot] = useState<PlotPoint[]>([]);
  const [chapters, setChapters] = useState<ChapterContent[]>([]);

  // UI State
  const [showTitleModal, setShowTitleModal] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- 自动保存与恢复逻辑 ---

  // 1. 初始化时加载数据
  useEffect(() => {
    const savedData = localStorage.getItem(STORAGE_KEY);
    if (savedData) {
      try {
        const parsed: ProjectData = JSON.parse(savedData);
        // 简单的版本检查
        if (parsed.version === 1) {
          console.log("检测到自动保存进度，正在恢复...");
          setStep(parsed.step);
          setPrompt(parsed.prompt || "");
          setBookTitle(parsed.bookTitle || "");
          setWorld(parsed.world);
          setCharacters(parsed.characters);
          setPlot(parsed.plot);
          setChapters(parsed.chapters);
        }
      } catch (e) {
        console.error("读取自动保存失败:", e);
      }
    }
    setIsLoadedFromStorage(true); // 标记加载尝试已完成
  }, []);

  // 2. 数据变化时自动保存
  useEffect(() => {
    // 只有在初始化加载完成后才开始保存，防止覆盖
    if (!isLoadedFromStorage) return;

    const data: ProjectData = {
      version: 1,
      step,
      prompt,
      bookTitle,
      world,
      characters,
      plot,
      chapters
    };

    // 使用 debounce 或直接保存，这里数据量不大直接保存
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    console.log("进度已自动保存");

  }, [step, prompt, bookTitle, world, characters, plot, chapters, isLoadedFromStorage]);

  // 新建项目 (重置)
  const handleNewProject = () => {
    if (window.confirm("确定要新建项目吗？这将清除当前的自动保存进度，且无法恢复。")) {
      // 清除本地存储
      localStorage.removeItem(STORAGE_KEY);

      // 强制刷新页面以重置所有状态为默认值
      // 这样可以确保 autosave 逻辑不会意外保存旧状态，并且让用户回到带有默认提示文案的初始界面
      window.location.reload();
    }
  };

  // --- 业务逻辑 ---

  // Step 1 -> 2: Setup to Characters
  const handleSetupGenerate = async () => {
    setIsLoading(true);
    try {
      const data = await generateCharactersAndWorld(prompt);
      setWorld(data.world);
      setCharacters(data.characters);
      setStep(GenerationStep.CHARACTERS);
    } catch (e) {
      alert("生成失败，请检查API Key或重试");
    } finally {
      setIsLoading(false);
    }
  };

  // Step 2 -> 3: Characters to Plot
  const handleConfirmCharacters = async (updatedWorld: WorldSetting, updatedCharacters: Character[]) => {
    if (!updatedWorld || updatedCharacters.length === 0) return;

    setWorld(updatedWorld);
    setCharacters(updatedCharacters);

    setIsLoading(true);
    try {
      const data = await generateMainPlot(updatedWorld, updatedCharacters);
      setPlot(data);
      setStep(GenerationStep.PLOT);
    } catch (e) {
      alert("生成大纲失败");
    } finally {
      setIsLoading(false);
    }
  };

  // Step 3 -> 4: Plot to Chapter Outlines -> Writing
  const handleConfirmPlot = async () => {
    if (!world || characters.length === 0 || plot.length === 0) return;
    setIsLoading(true);
    try {
      const outlineData = await generateChapterOutlines(world, characters, plot, 5);
      const initialChapters: ChapterContent[] = outlineData.map(o => ({
        outline: o,
        content: '',
        isGenerated: false
      }));
      setChapters(initialChapters);
      setStep(GenerationStep.WRITING);
    } catch (e) {
      alert("生成细纲失败");
    } finally {
      setIsLoading(false);
    }
  };

  // 仅续写后续章节大纲
  const handleAddChaptersOutline = async (count: number = 5) => {
    if (!world || characters.length === 0 || plot.length === 0 || chapters.length === 0) return;

    setIsLoading(true);
    try {
      const lastChapter = chapters[chapters.length - 1];
      const newOutlines = await generateNextChapterOutlines(world, characters, plot, lastChapter.outline, count);

      const newChapters: ChapterContent[] = newOutlines.map(o => ({
        outline: o,
        content: '',
        isGenerated: false
      }));

      setChapters(prev => [...prev, ...newChapters]);
    } catch (e) {
      console.error(e);
      alert("续写章节大纲失败");
    } finally {
      setIsLoading(false);
    }
  };

  /**
   * 批量生成后续章节（大纲 + 正文）
   * 逻辑：
   * 1. 调用大纲生成接口，规划后续 N 章。
   * 2. 将空章节加入 State。
   * 3. 循环遍历新章节，串行调用正文生成接口（保证上下文连贯）。
   */
  const handleBatchGenerateChapters = async (count: number = 5) => {
    if (!world || characters.length === 0 || plot.length === 0 || chapters.length === 0) return;
    if (batchProgress) return; // 防止重复点击

    try {
      // 1. 生成大纲
      setBatchProgress("正在规划后续剧情大纲...");
      const lastChapter = chapters[chapters.length - 1];
      const newOutlines = await generateNextChapterOutlines(world, characters, plot, lastChapter.outline, count);

      // 2. 创建占位章节并添加到状态
      const newChaptersPlaceholder: ChapterContent[] = newOutlines.map(o => ({
        outline: o,
        content: '',
        isGenerated: false
      }));

      // 先保存当前的章节数量，作为后续更新的起始索引
      const startIndex = chapters.length;

      // 更新 UI 显示出新的空章节
      setChapters(prev => [...prev, ...newChaptersPlaceholder]);

      // 3. 串行生成每一章的正文
      // 注意：这里我们不能直接用 chapters 状态，因为它是旧的闭包。
      // 我们需要构建一个临时的上下文链。
      let previousContent = lastChapter.content || lastChapter.outline.summary; 

      for (let i = 0; i < newChaptersPlaceholder.length; i++) {
        const currentChapterIndex = startIndex + i;
        const currentChapter = newChaptersPlaceholder[i];

        setBatchProgress(`正在撰写第 ${currentChapter.outline.chapterNumber} 章... (${i + 1}/${count})`);

        // 调用非流式生成接口
        const generatedContent = await generateFullChapterContent(
          currentChapter.outline,
          world,
          characters,
          previousContent
        );

        // 更新单个章节状态
        handleUpdateChapter(currentChapterIndex, generatedContent, true);

        // 更新上下文，为下一章做准备
        previousContent = generatedContent;
      }

      setBatchProgress(null);

    } catch (e) {
      console.error(e);
      alert("批量生成过程中断，请重试");
      setBatchProgress(null);
    }
  };


  // 更新章节内容
  const handleUpdateChapter = (index: number, content: string, isGenerated: boolean) => {
    setChapters(prev => {
      const newChapters = [...prev];
      if (newChapters[index]) {
        newChapters[index] = {
          ...newChapters[index],
          content,
          isGenerated
        };
      }
      return newChapters;
    });
  };

  // 更新章节标题
  const handleUpdateChapterTitle = (index: number, title: string) => {
    setChapters(prev => {
      const newChapters = [...prev];
      if (newChapters[index]) {
        newChapters[index] = {
          ...newChapters[index],
          outline: {
            ...newChapters[index].outline,
            title
          }
        };
      }
      return newChapters;
    });
  };

  // 更新分组小结
  const handleUpdateGroupSummary = (index: number, summary: string) => {
      setChapters(prev => {
          const newChapters = [...prev];
          if (newChapters[index]) {
              newChapters[index] = {
                  ...newChapters[index],
                  outline: {
                      ...newChapters[index].outline,
                      groupSummary: summary
                  }
              }
          }
          return newChapters;
      })
  }

  // 删除分组小结
  const handleDeleteGroupSummary = (index: number) => {
     if (window.confirm("确定要删除这个卷/段落标题吗？")) {
         handleUpdateGroupSummary(index, "");
     }
  };

  // 删除章节
  const handleDeleteChapter = (index: number) => {
      if (chapters.length <= 1) {
          alert("无法删除：至少需要保留一个章节。");
          return;
      }

      if (window.confirm(`确定要删除第 ${chapters[index].outline.chapterNumber} 章吗？\n删除后无法恢复，且后续章节序号会自动前移。`)) {
          setChapters(prev => {
              // 1. 过滤掉删除的章节
              const newChapters = prev.filter((_, i) => i !== index);

              // 2. 重新编排章节号，保证连续性
              return newChapters.map((chap, i) => ({
                  ...chap,
                  outline: {
                      ...chap.outline,
                      chapterNumber: i + 1
                  }
              }));
          });
      }
  };

  // 导出项目
  const handleExport = () => {
    const data: ProjectData = {
      version: 1,
      step,
      prompt,
      bookTitle,
      world,
      characters,
      plot,
      chapters
    };

    const jsonString = JSON.stringify(data, null, 2);
    const blob = new Blob([jsonString], { type: "application/json" });
    const url = URL.createObjectURL(blob);

    const link = document.createElement('a');
    link.href = url;
    link.download = `${bookTitle || 'soulwriter-project'}-${new Date().toISOString().slice(0, 10)}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  // 导入项目触发
  const triggerImport = () => {
    fileInputRef.current?.click();
  };

  // 处理文件读取
  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (json.version && json.step) {
          const data = json as ProjectData;
          setStep(data.step);
          setPrompt(data.prompt || "");
          setBookTitle(data.bookTitle || "");
          setWorld(data.world);
          setCharacters(data.characters);
          setPlot(data.plot);
          setChapters(data.chapters);
          alert("项目导入成功！");
        } else {
          alert("无效的项目文件格式");
        }
      } catch (error) {
        console.error("Import error", error);
        alert("文件解析失败");
      }
    };
    reader.readAsText(file);
    e.target.value = ''; 
  };

  return (
    <div className="min-h-screen bg-[#0d1117] text-gray-100 font-sans selection:bg-indigo-500/30">
      <header className="border-b border-gray-800 bg-[#0d1117]/80 backdrop-blur sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-4">
             {/* Logo */}
             <div className="font-bold text-xl tracking-tight bg-gradient-to-r from-indigo-400 to-cyan-400 bg-clip-text text-transparent flex items-center gap-2 cursor-pointer shrink-0" onClick={() => setStep(GenerationStep.SETUP)}>
                <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center text-white">
                  <FileJson size={20} />
                </div>
                <span className="hidden sm:inline">SoulWriter AI</span>
              </div>

              {/* Divider */}
              <div className="h-6 w-px bg-gray-700 mx-2 hidden sm:block"></div>

              {/* Book Title */}
              <button 
                onClick={() => setShowTitleModal(true)}
                className="flex items-center gap-2 px-3 py-1.5 rounded-lg hover:bg-gray-800 transition-colors group max-w-[150px] sm:max-w-xs"
                title="点击修改书名"
              >
                <div className="text-sm font-bold text-gray-200 truncate">
                   {bookTitle || "未命名作品"}
                </div>
                <PenLine size={14} className="text-gray-500 group-hover:text-indigo-400 shrink-0" />
              </button>
          </div>


          <div className="flex items-center gap-4">
            {/* Steps Indicator (Desktop) */}
            <div className="hidden lg:flex gap-2 text-xs font-mono text-gray-500 mr-4">
              <span className={step === GenerationStep.SETUP ? 'text-indigo-400' : ''}>01.设定</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.CHARACTERS ? 'text-indigo-400' : ''}>02.人物</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.PLOT ? 'text-indigo-400' : ''}>03.大纲</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.WRITING ? 'text-indigo-400' : ''}>04.正文</span>
            </div>

            {/* Actions */}
            <div className="flex items-center gap-2 border-l border-gray-700 pl-4">
              <input 
                type="file" 
                ref={fileInputRef} 
                className="hidden" 
                accept=".json" 
                onChange={handleImport}
              />

              {/* 新建项目按钮 */}
              <button 
                onClick={handleNewProject}
                className="p-2 text-gray-400 hover:text-white hover:bg-gray-800 rounded-lg transition-colors flex items-center gap-2 text-sm"
                title="新建项目 (清空进度)"
              >
                <FilePlus size={18} />
                <span className="hidden sm:inline">新建项目</span>
              </button>

              <button 
                onClick={triggerImport}
                className="p-2 text-gray-400 hover:text-white hover:bg-gray-800 rounded-lg transition-colors flex items-center gap-2 text-sm"
                title="导入项目"
              >
                <Upload size={18} />
                <span className="hidden sm:inline">导入</span>
              </button>

              <button 
                onClick={handleExport}
                className="px-3 py-1.5 bg-gray-800 hover:bg-gray-700 text-indigo-300 border border-indigo-500/30 rounded-lg transition-colors flex items-center gap-2 text-sm font-medium"
                title="导出项目"
              >
                <Save size={18} />
                <span className="hidden sm:inline">保存</span>
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8">
        {step === GenerationStep.SETUP && (
          <StepSetup 
            prompt={prompt}
            setPrompt={setPrompt}
            onGenerate={handleSetupGenerate} 
            isLoading={isLoading} 
          />
        )}

        {step === GenerationStep.CHARACTERS && world && (
          <StepCharacters 
            world={world} 
            characters={characters} 
            onConfirm={handleConfirmCharacters}
            isLoading={isLoading}
          />
        )}

        {step === GenerationStep.PLOT && (
          <StepPlot 
            plot={plot}
            onConfirm={handleConfirmPlot}
            isLoading={isLoading}
          />
        )}

        {step === GenerationStep.WRITING && world && (
          <StepWriting 
            chapters={chapters}
            world={world}
            characters={characters}
            onUpdateChapter={handleUpdateChapter}
            onUpdateTitle={handleUpdateChapterTitle}
            onUpdateGroupSummary={handleUpdateGroupSummary}
            onDeleteChapter={handleDeleteChapter}
            onDeleteGroupSummary={handleDeleteGroupSummary}
            onLoadMoreChapters={handleAddChaptersOutline}
            onBatchGenerate={handleBatchGenerateChapters}
            isLoadingMore={isLoading}
            batchProgress={batchProgress}
          />
        )}
      </main>

      {/* Modals */}
      {showTitleModal && (
        <TitleGeneratorModal 
           currentTitle={bookTitle}
           onSelect={(t) => setBookTitle(t)}
           onClose={() => setShowTitleModal(false)}
           contextData={{ prompt, world, characters }}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ChapterContent, Character, WorldSetting } from '../types';
import { streamChapterContent, generateBatchSummary } from '../services/geminiService';
import ChapterReader from './ChapterReader';
import { FileText, Play, CheckCircle, Menu, X, Edit, Save, PlusCircle, Loader2, Sparkles, ArrowDown, RefreshCw, RotateCcw, CornerDownLeft, Bookmark, Copy, Check, Trash2 } from 'lucide-react';

interface Props {
  chapters: ChapterContent[];
  world: WorldSetting;
  characters: Character[];
  onUpdateChapter: (index: number, content: string, isGenerated: boolean) => void;
  onUpdateTitle: (index: number, title: string) => void;
  onUpdateGroupSummary: (index: number, summary: string) => void; 
  onDeleteChapter: (index: number) => void; // 新增：删除章节
  onDeleteGroupSummary: (index: number) => void; // 新增：删除卷标
  onLoadMoreChapters: () => void;
  onBatchGenerate: (count: number) => void;
  isLoadingMore: boolean;
  batchProgress: string | null;
}

const CopyBtn = ({ text, className = "" }: { text: string, className?: string }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = (e: React.MouseEvent) => {
    e.stopPropagation();
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <button 
      onClick={handleCopy} 
      className={`p-1 rounded-md hover:bg-gray-700/50 transition-colors inline-flex items-center justify-center shrink-0 ${copied ? 'text-green-400' : 'text-gray-500 hover:text-indigo-400'} ${className}`}
      title="复制内容"
    >
      {copied ? <Check size={12} /> : <Copy size={12} />}
    </button>
  );
};

const StepWriting: React.FC<Props> = ({ 
  chapters, 
  world, 
  characters, 
  onUpdateChapter, 
  onUpdateTitle, 
  onUpdateGroupSummary,
  onDeleteChapter,
  onDeleteGroupSummary,
  onLoadMoreChapters, 
  onBatchGenerate,
  isLoadingMore,
  batchProgress
}) => {
  const [activeChapterIndex, setActiveChapterIndex] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [showSidebar, setShowSidebar] = useState(false); 
  const [isEditing, setIsEditing] = useState(false);

  // Loading state specifically for generating group summaries
  // Key is the starting index of the group
  const [generatingSummaryIndices, setGeneratingSummaryIndices] = useState<number[]>([]);

  // 重写功能相关状态
  const [showRewriteModal, setShowRewriteModal] = useState(false);
  const [rewriteInstructions, setRewriteInstructions] = useState("");

  // 撤销历史记录
  const [undoHistory, setUndoHistory] = useState<Record<number, string>>({});

  // 章节跳转输入状态
  const [jumpInput, setJumpInput] = useState("");

  // 确保 activeChapterIndex 不越界
  useEffect(() => {
      if (chapters.length > 0 && activeChapterIndex >= chapters.length) {
          setActiveChapterIndex(Math.max(0, chapters.length - 1));
      }
  }, [chapters.length, activeChapterIndex]);

  const activeChapter = chapters[activeChapterIndex] || chapters[0]; // 防御性处理

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setIsEditing(false);
  }, [activeChapterIndex]);

  const handleGenerate = async () => {
    if (isGenerating || activeChapter.isGenerated) return;
    startGeneration();
  };

  const handleRewrite = async () => {
    if (isGenerating) return;

    if (activeChapter.content) {
      setUndoHistory(prev => ({
        ...prev,
        [activeChapterIndex]: activeChapter.content
      }));
    }

    setShowRewriteModal(false);
    startGeneration(rewriteInstructions);
    setRewriteInstructions("");
  };

  const handleUndoRewrite = () => {
    const prevContent = undoHistory[activeChapterIndex];
    if (!prevContent) return;

    if (window.confirm("确定要撤销重写，恢复到上一个版本吗？当前版本将丢失。")) {
      onUpdateChapter(activeChapterIndex, prevContent, true);
      setUndoHistory(prev => {
        const newState = { ...prev };
        delete newState[activeChapterIndex];
        return newState;
      });
    }
  };

  const handleJumpToChapter = () => {
    const target = parseInt(jumpInput);
    if (isNaN(target)) return;

    if (target < 1 || target > chapters.length) {
      alert(`请输入有效章节号 (1-${chapters.length})`);
      return;
    }

    setActiveChapterIndex(target - 1);
    setJumpInput("");
    if (window.innerWidth < 768) setShowSidebar(false);
  };

  const handleJumpKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleJumpToChapter();
    }
  };

  // 生成分组标题的逻辑
  const handleGenerateGroupSummary = async (startIndex: number) => {
    if (generatingSummaryIndices.includes(startIndex)) return;

    // 获取这5章
    const groupChapters = chapters.slice(startIndex, startIndex + 5).map(c => c.outline);
    if (groupChapters.length === 0) return;

    setGeneratingSummaryIndices(prev => [...prev, startIndex]);

    try {
        const summary = await generateBatchSummary(groupChapters);
        onUpdateGroupSummary(startIndex, summary);
    } catch (e) {
        console.error("生成卷标出错详情:", e);
        alert("生成卷标失败，请查看控制台日志以获取更多信息");
    } finally {
        setGeneratingSummaryIndices(prev => prev.filter(i => i !== startIndex));
    }
  };

  const startGeneration = async (instructions?: string) => {
    setIsGenerating(true);
    setIsEditing(false);

    if (window.innerWidth < 768) {
        setShowSidebar(false);
    }

    let prevContext = "";
    if (activeChapterIndex > 0) {
      const prevChap = chapters[activeChapterIndex - 1];
      prevContext = prevChap.content || prevChap.outline.summary;
    }

    try {
      if (instructions) {
         onUpdateChapter(activeChapterIndex, "", false); 
      }

      let fullText = "";
      await streamChapterContent(
        activeChapter.outline,
        world,
        characters,
        prevContext,
        (textChunk) => {
          fullText += textChunk;
          onUpdateChapter(activeChapterIndex, fullText, false);
        },
        instructions
      );

      onUpdateChapter(activeChapterIndex, fullText, true);

    } catch (e) {
      alert("生成中断，请重试");
    } finally {
      setIsGenerating(false);
    }
  };

  if (!activeChapter) return <div>数据加载中...</div>;

  const isBatchGenerating = batchProgress !== null;
  const canUndo = !!undoHistory[activeChapterIndex];

  return (
    <div className="flex h-[calc(100vh-100px)] overflow-hidden rounded-xl border border-gray-800 bg-gray-950 relative">

      {/* 重写设置模态框 */}
      {showRewriteModal && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[60] flex items-center justify-center p-4">
           <div className="bg-gray-900 border border-gray-700 rounded-xl p-6 w-full max-w-lg shadow-2xl animate-in fade-in zoom-in duration-200 flex flex-col max-h-[90vh]">
              <h3 className="text-xl font-bold text-white mb-2 flex items-center gap-2 shrink-0">
                  <RefreshCw className="text-indigo-400" size={20} />
                  重写本章
              </h3>

              <div className="overflow-y-auto mb-4 custom-scrollbar pr-2">
                 <div className="bg-gray-800/50 rounded-lg p-3 mb-4 border border-gray-700">
                    <span className="text-xs font-bold text-indigo-400 uppercase tracking-wider block mb-1">当前大纲摘要</span>
                    <p className="text-sm text-gray-300 leading-relaxed">
                      {activeChapter.outline.summary}
                    </p>
                 </div>

                 <p className="text-sm text-gray-400 mb-2">
                     AI 将根据上述大纲重新撰写正文。您可以输入具体的修改意见，AI会重点关注。
                 </p>
              </div>

              <textarea 
                  className="w-full h-32 bg-gray-950 border border-gray-700 rounded-lg p-3 text-gray-200 focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none resize-none placeholder-gray-600 text-sm shrink-0" 
                  placeholder="例如：这一章的打斗细节太少了，多描写一下招式；或者，女主的反应再害羞一点..."
                  value={rewriteInstructions}
                  onChange={(e) => setRewriteInstructions(e.target.value)}
                  autoFocus
              />
              <div className="flex justify-end gap-3 mt-6 shrink-0">
                  <button 
                    onClick={() => setShowRewriteModal(false)} 
                    className="px-4 py-2 rounded-lg text-gray-400 hover:text-white hover:bg-gray-800 transition-colors text-sm"
                  >
                    取消
                  </button>
                  <button 
                    onClick={handleRewrite} 
                    className="px-4 py-2 rounded-lg bg-indigo-600 hover:bg-indigo-500 text-white font-bold shadow-lg shadow-indigo-500/20 text-sm flex items-center gap-2"
                  >
                    <RefreshCw size={14} />
                    开始重写
                  </button>
              </div>
           </div>
        </div>
      )}

      {showSidebar && (
        <div 
          className="fixed inset-0 bg-black/60 backdrop-blur-sm z-30 md:hidden transition-opacity"
          onClick={() => setShowSidebar(false)}
        />
      )}

      <button 
        className="md:hidden fixed bottom-6 right-6 z-50 bg-indigo-600 hover:bg-indigo-500 text-white p-4 rounded-full shadow-xl shadow-indigo-900/50 transition-all active:scale-95 flex items-center justify-center"
        onClick={() => setShowSidebar(!showSidebar)}
        title={showSidebar ? "关闭目录" : "打开目录"}
      >
        {showSidebar ? <X size={24} /> : <Menu size={24} />}
      </button>

      {/* Sidebar - Chapter List */}
      <div className={`
        fixed md:relative z-40 w-72 max-w-[80vw] bg-gray-900 border-r border-gray-800 h-full flex flex-col transition-transform duration-300 ease-in-out shadow-2xl md:shadow-none
        ${showSidebar ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
      `}>
        <div className="p-4 border-b border-gray-800 bg-gray-900 font-bold text-gray-200 flex justify-between items-center shrink-0">
          <span>目录 ({chapters.length}章)</span>
          <button 
            onClick={() => setShowSidebar(false)}
            className="md:hidden text-gray-500 hover:text-white"
          >
            <X size={20} />
          </button>
        </div>

        <div className="px-3 py-2 border-b border-gray-800 bg-gray-900/50 shrink-0">
          <div className="flex gap-2">
            <input 
              type="number" 
              className="w-full bg-gray-950 border border-gray-700 rounded text-sm px-2 py-1 text-gray-300 focus:border-indigo-500 outline-none placeholder-gray-600"
              placeholder="前往章节..."
              value={jumpInput}
              onChange={(e) => setJumpInput(e.target.value)}
              onKeyDown={handleJumpKeyDown}
              min={1}
              max={chapters.length}
            />
            <button 
              onClick={handleJumpToChapter}
              disabled={!jumpInput}
              className="bg-gray-800 hover:bg-gray-700 border border-gray-700 text-gray-400 hover:text-white px-2 rounded transition-colors disabled:opacity-50"
              title="跳转"
            >
              <CornerDownLeft size={16} />
            </button>
          </div>
        </div>

        {/* Scrollable List */}
        <div className="overflow-y-auto flex-1 p-2 space-y-2">
          {chapters.map((chap, idx) => (
            <React.Fragment key={idx}>
              {/* Group Summary Header (Every 5 chapters) */}
              {idx % 5 === 0 && (
                  <div className="mb-2 mt-4 first:mt-0">
                      <div className="bg-gray-800/80 border border-gray-700 rounded-lg p-2 flex items-center justify-between gap-2 shadow-sm group/header">
                          {chap.outline.groupSummary ? (
                              <>
                                <div className="flex items-center gap-2 flex-1 min-w-0">
                                    <Bookmark size={14} className="text-yellow-500 shrink-0" />
                                    <span className="text-xs font-bold text-yellow-100/90 truncate" title={chap.outline.groupSummary}>
                                        {chap.outline.groupSummary}
                                    </span>
                                    <CopyBtn text={chap.outline.groupSummary} />
                                </div>
                                <button
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        onDeleteGroupSummary(idx);
                                    }}
                                    className="text-gray-500 hover:text-red-400 p-1 rounded hover:bg-red-900/20 transition-colors shrink-0"
                                    title="删除卷标"
                                >
                                    <Trash2 size={12} />
                                </button>
                              </>
                          ) : (
                              <span className="text-xs text-gray-500 font-medium pl-1">第 {chap.outline.chapterNumber}-{Math.min(chap.outline.chapterNumber + 4, chapters[chapters.length-1].outline.chapterNumber)} 章</span>
                          )}

                          <button
                              onClick={(e) => {
                                  e.stopPropagation();
                                  handleGenerateGroupSummary(idx);
                              }}
                              disabled={generatingSummaryIndices.includes(idx)}
                              className="text-gray-500 hover:text-indigo-400 p-1 rounded hover:bg-gray-700/50 transition-colors shrink-0"
                              title={chap.outline.groupSummary ? "重新生成卷标" : "生成卷标"}
                          >
                              {generatingSummaryIndices.includes(idx) ? (
                                  <Loader2 size={12} className="animate-spin" />
                              ) : (
                                  <Sparkles size={12} />
                              )}
                          </button>
                      </div>
                  </div>
              )}

              <div
                id={`chapter-item-${idx}`} 
                role="button"
                tabIndex={0}
                onClick={() => {
                  setActiveChapterIndex(idx);
                  if (window.innerWidth < 768) setShowSidebar(false);
                }}
                onKeyDown={(e) => {
                   if (e.key === 'Enter' || e.key === ' ') {
                      setActiveChapterIndex(idx);
                      if (window.innerWidth < 768) setShowSidebar(false);
                   }
                }}
                className={`w-full text-left p-3 rounded-lg text-sm transition-all flex items-start gap-2 cursor-pointer group/item
                  ${activeChapterIndex === idx 
                    ? 'bg-indigo-900/40 border border-indigo-500/30 text-indigo-200' 
                    : 'hover:bg-gray-800 text-gray-400 border border-transparent'}
                `}
              >
                <div className="mt-0.5 shrink-0">
                  {chap.isGenerated ? <CheckCircle size={14} className="text-green-500" /> : <FileText size={14} />}
                </div>
                <div className="min-w-0 flex-1">
                  <div className="flex items-center justify-between gap-2">
                      <div className="font-semibold truncate">第{chap.outline.chapterNumber}章: {chap.outline.title}</div>
                      <div className="flex items-center gap-1 shrink-0">
                         <CopyBtn 
                            text={`第${chap.outline.chapterNumber}章 ${chap.outline.title}`} 
                            className="shrink-0"
                         />
                         <button
                            onClick={(e) => {
                                e.stopPropagation();
                                onDeleteChapter(idx);
                            }}
                            className="p-1 rounded-md text-gray-500 hover:text-red-400 hover:bg-red-900/20 transition-all opacity-0 group-hover/item:opacity-100"
                            title="删除本章"
                         >
                            <Trash2 size={12} />
                         </button>
                      </div>
                  </div>
                  <div className="text-xs text-gray-500 mt-1 truncate">{chap.outline.coolPoint}</div>
                </div>
              </div>
            </React.Fragment>
          ))}
        </div>

        <div className="p-3 border-t border-gray-800 bg-gray-900 shrink-0 space-y-2">
          {isBatchGenerating && (
             <div className="text-xs text-indigo-400 flex items-center gap-2 bg-indigo-900/20 p-2 rounded mb-2">
                <Loader2 size={12} className="animate-spin" />
                {batchProgress}
             </div>
          )}

          <button
            onClick={() => onBatchGenerate(5)}
            disabled={isLoadingMore || isBatchGenerating}
            className="w-full py-2.5 rounded-lg bg-indigo-600 hover:bg-indigo-500 text-white shadow-lg shadow-indigo-900/30 transition-all flex items-center justify-center gap-2 text-sm font-bold disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isBatchGenerating ? (
              <>
                <Loader2 size={16} className="animate-spin" />
                自动码字中...
              </>
            ) : (
              <>
                <Sparkles size={16} />
                一键生成后续5章
              </>
            )}
          </button>

           <button
            onClick={onLoadMoreChapters}
            disabled={isLoadingMore || isBatchGenerating}
            className="w-full py-2 rounded-lg border border-dashed border-gray-600 text-gray-400 hover:text-white hover:border-indigo-500 hover:bg-gray-800 transition-all flex items-center justify-center gap-2 text-xs font-medium"
          >
            {isLoadingMore ? (
              <>
                <Loader2 size={14} className="animate-spin" />
                推演中...
              </>
            ) : (
              <>
                <PlusCircle size={14} />
                仅生成后续5章大纲
              </>
            )}
          </button>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col h-full overflow-hidden relative bg-black/20">
        <div className="p-4 border-b border-gray-800 bg-gray-850 flex justify-between items-start md:items-center flex-col md:flex-row gap-4 shrink-0">
          <div className="w-full md:w-auto">
             <h3 className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">本章脉络 & 规则</h3>
             <p className="text-sm text-gray-300 line-clamp-2 md:line-clamp-1">
               <span className="text-indigo-400">[{activeChapter.outline.narrativePulse}]</span> {activeChapter.outline.rules.join(" | ")}
             </p>
          </div>

          <div className="flex items-center gap-3 self-end md:self-auto shrink-0">
            {canUndo && !isGenerating && !isBatchGenerating && (
                <button
                    onClick={handleUndoRewrite}
                    className="px-3 py-2 rounded-lg bg-gray-800 hover:bg-gray-700 text-orange-400 border border-orange-500/30 transition-all flex items-center gap-2 text-sm md:text-base font-medium"
                    title="恢复重写前的内容"
                >
                    <RotateCcw size={16} />
                    <span className="hidden sm:inline">撤销重写</span>
                </button>
            )}

            {activeChapter.isGenerated && !isGenerating && !isBatchGenerating && (
                <button
                    onClick={() => setShowRewriteModal(true)}
                    className="px-3 py-2 rounded-lg bg-gray-800 hover:bg-gray-700 text-indigo-300 border border-indigo-500/30 transition-all flex items-center gap-2 text-sm md:text-base font-medium"
                    title="重写本章"
                >
                    <RefreshCw size={16} />
                    <span className="hidden sm:inline">重写</span>
                </button>
            )}

            {(activeChapter.content || activeChapter.isGenerated) && !isGenerating && !isBatchGenerating && (
              <button
                onClick={() => setIsEditing(!isEditing)}
                className={`px-4 py-2 rounded-lg flex items-center gap-2 font-bold transition-all border text-sm md:text-base
                  ${isEditing 
                    ? 'bg-green-600/20 text-green-400 border-green-500/50 hover:bg-green-600/30' 
                    : 'bg-gray-800 hover:bg-gray-700 text-gray-300 border-gray-700'
                  }`}
              >
                {isEditing ? (
                  <>
                    <Save size={16} />
                    <span className="hidden sm:inline">完成</span>
                  </>
                ) : (
                  <>
                    <Edit size={16} />
                    <span className="hidden sm:inline">修改</span>
                  </>
                )}
              </button>
            )}

            {(!activeChapter.isGenerated && !activeChapter.content) && (
              <button
                onClick={handleGenerate}
                disabled={isGenerating || isBatchGenerating}
                className="px-5 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg flex items-center gap-2 font-bold shadow-lg shadow-indigo-500/20 whitespace-nowrap text-sm md:text-base disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {isGenerating ? '创作中...' : (isBatchGenerating ? '批量任务进行中...' : '生成正文')}
                {!isGenerating && !isBatchGenerating && <Play size={16} fill="currentColor" />}
              </button>
            )}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4 md:p-8">
          <div className="max-w-3xl mx-auto h-full pb-24">
             {isEditing ? (
               <div className="h-full min-h-[600px] bg-gray-900 p-4 md:p-8 rounded-xl border border-indigo-500/30 shadow-2xl flex flex-col animate-in fade-in duration-300">
                 <div className="mb-4 pb-4 border-b border-gray-800 flex flex-col gap-2">
                    <div className="flex justify-between items-center text-xs text-gray-500 uppercase tracking-wider font-bold">
                        <span>正在编辑: 第{activeChapter.outline.chapterNumber}章</span>
                        <span className={activeChapter.content.length > 2000 ? 'text-green-500' : 'text-gray-500'}>
                            {activeChapter.content.length} 字
                        </span>
                    </div>
                    <input 
                        type="text" 
                        value={activeChapter.outline.title}
                        onChange={(e) => onUpdateTitle(activeChapterIndex, e.target.value)}
                        className="bg-transparent text-xl md:text-2xl font-serif font-bold text-white border-b border-gray-700 focus:border-indigo-500 outline-none py-1 transition-colors placeholder-gray-700"
                        placeholder="输入章节标题..."
                    />
                 </div>
                 <textarea 
                   className="w-full flex-1 bg-transparent border-none outline-none text-gray-200 font-serif text-base md:text-lg leading-loose resize-none focus:ring-0"
                   value={activeChapter.content}
                   onChange={(e) => onUpdateChapter(activeChapterIndex, e.target.value, true)} 
                   placeholder="在此输入章节正文..."
                   spellCheck={false}
                   autoFocus
                 />
               </div>
             ) : (
               <>
                 <ChapterReader 
                   title={`第${activeChapter.outline.chapterNumber}章 ${activeChapter.outline.title}`}
                   content={activeChapter.content}
                   isStreaming={isGenerating && activeChapterIndex === chapters.findIndex(c => c === activeChapter)}
                 />

                 <div className="mt-12 mb-8 text-center space-y-6">
                    {activeChapter.isGenerated && activeChapterIndex < chapters.length - 1 && (
                       <button
                         onClick={() => setActiveChapterIndex(prev => prev + 1)}
                         className="text-gray-400 hover:text-white underline decoration-indigo-500 underline-offset-4 py-4 px-8 text-lg transition-all flex items-center gap-2 mx-auto"
                       >
                         继续下一章
                         <ArrowDown size={16} />
                       </button>
                    )}

                    {activeChapter.isGenerated && activeChapterIndex === chapters.length - 1 && (
                        <div className="flex flex-col items-center justify-center gap-4 py-8 border-t border-gray-800/50">
                            <p className="text-gray-500 text-sm">当前剧情已至最新，是否继续推演后续发展？</p>
                            <button
                                onClick={() => onBatchGenerate(5)}
                                disabled={isLoadingMore || isBatchGenerating}
                                className="px-8 py-4 bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 text-white rounded-xl font-bold shadow-xl shadow-indigo-900/40 flex items-center gap-3 transition-all transform hover:scale-105 disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none"
                            >
                                {isBatchGenerating ? (
                                    <>
                                        <Loader2 size={24} className="animate-spin" />
                                        <span className="text-lg">AI正在疯狂码字中...</span>
                                    </>
                                ) : (
                                    <>
                                        <Sparkles size={24} />
                                        <span className="text-lg">一键生成后续5章 (大纲+正文)</span>
                                    </>
                                )}
                            </button>
                            {!isBatchGenerating && (
                                <p className="text-xs text-gray-600">
                                    * 将根据当前剧情自动规划大纲并撰写正文
                                </p>
                            )}
                        </div>
                    )}
                 </div>
               </>
             )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default StepWriting;

import React, { useState, useEffect } from 'react';
import { ChapterContent, Character, WorldSetting } from '../types';
import { streamChapterContent, generateBatchSummary } from '../services/geminiService';
import ChapterReader from './ChapterReader';
import { FileText, Play, CheckCircle, Menu, X, Edit, Save, PlusCircle, Loader2, Sparkles, ArrowDown, RefreshCw, RotateCcw, CornerDownLeft, Bookmark, Copy, Check, Trash2 } from 'lucide-react';

interface Props {
  chapters: ChapterContent[];
  world: WorldSetting;
  characters: Character[];
  onUpdateChapter: (index: number, content: string, isGenerated: boolean) => void;
  onUpdateTitle: (index: number, title: string) => void;
  onUpdateGroupSummary: (index: number, summary: string) => void; 
  onDeleteChapter: (index: number) => void; // 新增：删除章节
  onDeleteGroupSummary: (index: number) => void; // 新增：删除卷标
  onLoadMoreChapters: () => void;
  onBatchGenerate: (count: number) => void;
  isLoadingMore: boolean;
  batchProgress: string | null;
}

const CopyBtn = ({ text, className = "" }: { text: string, className?: string }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = (e: React.MouseEvent) => {
    e.stopPropagation();
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <button 
      onClick={handleCopy} 
      className={`p-1 rounded-md hover:bg-gray-700/50 transition-colors inline-flex items-center justify-center shrink-0 ${copied ? 'text-green-400' : 'text-gray-500 hover:text-indigo-400'} ${className}`}
      title="复制内容"
    >
      {copied ? <Check size={12} /> : <Copy size={12} />}
    </button>
  );
};

const StepWriting: React.FC<Props> = ({ 
  chapters, 
  world, 
  characters, 
  onUpdateChapter, 
  onUpdateTitle, 
  onUpdateGroupSummary,
  onDeleteChapter,
  onDeleteGroupSummary,
  onLoadMoreChapters, 
  onBatchGenerate,
  isLoadingMore,
  batchProgress
}) => {
  const [activeChapterIndex, setActiveChapterIndex] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [showSidebar, setShowSidebar] = useState(false); 
  const [isEditing, setIsEditing] = useState(false);

  // Loading state specifically for generating group summaries
  // Key is the starting index of the group
  const [generatingSummaryIndices, setGeneratingSummaryIndices] = useState<number[]>([]);

  // 重写功能相关状态
  const [showRewriteModal, setShowRewriteModal] = useState(false);
  const [rewriteInstructions, setRewriteInstructions] = useState("");

  // 撤销历史记录
  const [undoHistory, setUndoHistory] = useState<Record<number, string>>({});

  // 章节跳转输入状态
  const [jumpInput, setJumpInput] = useState("");

  // 确保 activeChapterIndex 不越界
  useEffect(() => {
      if (chapters.length > 0 && activeChapterIndex >= chapters.length) {
          setActiveChapterIndex(Math.max(0, chapters.length - 1));
      }
  }, [chapters.length, activeChapterIndex]);

  const activeChapter = chapters[activeChapterIndex] || chapters[0]; // 防御性处理

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setIsEditing(false);
  }, [activeChapterIndex]);

  const handleGenerate = async () => {
    if (isGenerating || activeChapter.isGenerated) return;
    startGeneration();
  };

  const handleRewrite = async () => {
    if (isGenerating) return;

    if (activeChapter.content) {
      setUndoHistory(prev => ({
        ...prev,
        [activeChapterIndex]: activeChapter.content
      }));
    }

    setShowRewriteModal(false);
    startGeneration(rewriteInstructions);
    setRewriteInstructions("");
  };

  const handleUndoRewrite = () => {
    const prevContent = undoHistory[activeChapterIndex];
    if (!prevContent) return;

    if (window.confirm("确定要撤销重写，恢复到上一个版本吗？当前版本将丢失。")) {
      onUpdateChapter(activeChapterIndex, prevContent, true);
      setUndoHistory(prev => {
        const newState = { ...prev };
        delete newState[activeChapterIndex];
        return newState;
      });
    }
  };

  const handleJumpToChapter = () => {
    const target = parseInt(jumpInput);
    if (isNaN(target)) return;

    if (target < 1 || target > chapters.length) {
      alert(`请输入有效章节号 (1-${chapters.length})`);
      return;
    }

    setActiveChapterIndex(target - 1);
    setJumpInput("");
    if (window.innerWidth < 768) setShowSidebar(false);
  };

  const handleJumpKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleJumpToChapter();
    }
  };

  // 生成分组标题的逻辑
  const handleGenerateGroupSummary = async (startIndex: number) => {
    if (generatingSummaryIndices.includes(startIndex)) return;

    // 获取这5章
    const groupChapters = chapters.slice(startIndex, startIndex + 5).map(c => c.outline);
    if (groupChapters.length === 0) return;

    setGeneratingSummaryIndices(prev => [...prev, startIndex]);

    try {
        const summary = await generateBatchSummary(groupChapters);
        onUpdateGroupSummary(startIndex, summary);
    } catch (e) {
        console.error("生成卷标出错详情:", e);
        alert("生成卷标失败，请查看控制台日志以获取更多信息");
    } finally {
        setGeneratingSummaryIndices(prev => prev.filter(i => i !== startIndex));
    }
  };

  const startGeneration = async (instructions?: string) => {
    setIsGenerating(true);
    setIsEditing(false);

    if (window.innerWidth < 768) {
        setShowSidebar(false);
    }

    let prevContext = "";
    if (activeChapterIndex > 0) {
      const prevChap = chapters[activeChapterIndex - 1];
      prevContext = prevChap.content || prevChap.outline.summary;
    }

    try {
      if (instructions) {
         onUpdateChapter(activeChapterIndex, "", false); 
      }

      let fullText = "";
      await streamChapterContent(
        activeChapter.outline,
        world,
        characters,
        prevContext,
        (textChunk) => {
          fullText += textChunk;
          onUpdateChapter(activeChapterIndex, fullText, false);
        },
        instructions
      );

      onUpdateChapter(activeChapterIndex, fullText, true);

    } catch (e) {
      alert("生成中断，请重试");
    } finally {
      setIsGenerating(false);
    }
  };

  if (!activeChapter) return <div>数据加载中...</div>;

  const isBatchGenerating = batchProgress !== null;
  const canUndo = !!undoHistory[activeChapterIndex];

  return (
    <div className="flex h-[calc(100vh-100px)] overflow-hidden rounded-xl border border-gray-800 bg-gray-950 relative">

      {/* 重写设置模态框 */}
      {showRewriteModal && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[60] flex items-center justify-center p-4">
           <div className="bg-gray-900 border border-gray-700 rounded-xl p-6 w-full max-w-lg shadow-2xl animate-in fade-in zoom-in duration-200 flex flex-col max-h-[90vh]">
              <h3 className="text-xl font-bold text-white mb-2 flex items-center gap-2 shrink-0">
                  <RefreshCw className="text-indigo-400" size={20} />
                  重写本章
              </h3>

              <div className="overflow-y-auto mb-4 custom-scrollbar pr-2">
                 <div className="bg-gray-800/50 rounded-lg p-3 mb-4 border border-gray-700">
                    <span className="text-xs font-bold text-indigo-400 uppercase tracking-wider block mb-1">当前大纲摘要</span>
                    <p className="text-sm text-gray-300 leading-relaxed">
                      {activeChapter.outline.summary}
                    </p>
                 </div>

                 <p className="text-sm text-gray-400 mb-2">
                     AI 将根据上述大纲重新撰写正文。您可以输入具体的修改意见，AI会重点关注。
                 </p>
              </div>

              <textarea 
                  className="w-full h-32 bg-gray-950 border border-gray-700 rounded-lg p-3 text-gray-200 focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none resize-none placeholder-gray-600 text-sm shrink-0" 
                  placeholder="例如：这一章的打斗细节太少了，多描写一下招式；或者，女主的反应再害羞一点..."
                  value={rewriteInstructions}
                  onChange={(e) => setRewriteInstructions(e.target.value)}
                  autoFocus
              />
              <div className="flex justify-end gap-3 mt-6 shrink-0">
                  <button 
                    onClick={() => setShowRewriteModal(false)} 
                    className="px-4 py-2 rounded-lg text-gray-400 hover:text-white hover:bg-gray-800 transition-colors text-sm"
                  >
                    取消
                  </button>
                  <button 
                    onClick={handleRewrite} 
                    className="px-4 py-2 rounded-lg bg-indigo-600 hover:bg-indigo-500 text-white font-bold shadow-lg shadow-indigo-500/20 text-sm flex items-center gap-2"
                  >
                    <RefreshCw size={14} />
                    开始重写
                  </button>
              </div>
           </div>
        </div>
      )}

      {showSidebar && (
        <div 
          className="fixed inset-0 bg-black/60 backdrop-blur-sm z-30 md:hidden transition-opacity"
          onClick={() => setShowSidebar(false)}
        />
      )}

      <button 
        className="md:hidden fixed bottom-6 right-6 z-50 bg-indigo-600 hover:bg-indigo-500 text-white p-4 rounded-full shadow-xl shadow-indigo-900/50 transition-all active:scale-95 flex items-center justify-center"
        onClick={() => setShowSidebar(!showSidebar)}
        title={showSidebar ? "关闭目录" : "打开目录"}
      >
        {showSidebar ? <X size={24} /> : <Menu size={24} />}
      </button>

      {/* Sidebar - Chapter List */}
      <div className={`
        fixed md:relative z-40 w-72 max-w-[80vw] bg-gray-900 border-r border-gray-800 h-full flex flex-col transition-transform duration-300 ease-in-out shadow-2xl md:shadow-none
        ${showSidebar ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
      `}>
        <div className="p-4 border-b border-gray-800 bg-gray-900 font-bold text-gray-200 flex justify-between items-center shrink-0">
          <span>目录 ({chapters.length}章)</span>
          <button 
            onClick={() => setShowSidebar(false)}
            className="md:hidden text-gray-500 hover:text-white"
          >
            <X size={20} />
          </button>
        </div>

        <div className="px-3 py-2 border-b border-gray-800 bg-gray-900/50 shrink-0">
          <div className="flex gap-2">
            <input 
              type="number" 
              className="w-full bg-gray-950 border border-gray-700 rounded text-sm px-2 py-1 text-gray-300 focus:border-indigo-500 outline-none placeholder-gray-600"
              placeholder="前往章节..."
              value={jumpInput}
              onChange={(e) => setJumpInput(e.target.value)}
              onKeyDown={handleJumpKeyDown}
              min={1}
              max={chapters.length}
            />
            <button 
              onClick={handleJumpToChapter}
              disabled={!jumpInput}
              className="bg-gray-800 hover:bg-gray-700 border border-gray-700 text-gray-400 hover:text-white px-2 rounded transition-colors disabled:opacity-50"
              title="跳转"
            >
              <CornerDownLeft size={16} />
            </button>
          </div>
        </div>

        {/* Scrollable List */}
        <div className="overflow-y-auto flex-1 p-2 space-y-2">
          {chapters.map((chap, idx) => (
            <React.Fragment key={idx}>
              {/* Group Summary Header (Every 5 chapters) */}
              {idx % 5 === 0 && (
                  <div className="mb-2 mt-4 first:mt-0">
                      <div className="bg-gray-800/80 border border-gray-700 rounded-lg p-2 flex items-center justify-between gap-2 shadow-sm group/header">
                          {chap.outline.groupSummary ? (
                              <>
                                <div className="flex items-center gap-2 flex-1 min-w-0">
                                    <Bookmark size={14} className="text-yellow-500 shrink-0" />
                                    <span className="text-xs font-bold text-yellow-100/90 truncate" title={chap.outline.groupSummary}>
                                        {chap.outline.groupSummary}
                                    </span>
                                    <CopyBtn text={chap.outline.groupSummary} />
                                </div>
                                <button
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        onDeleteGroupSummary(idx);
                                    }}
                                    className="text-gray-500 hover:text-red-400 p-1 rounded hover:bg-red-900/20 transition-colors shrink-0"
                                    title="删除卷标"
                                >
                                    <Trash2 size={12} />
                                </button>
                              </>
                          ) : (
                              <span className="text-xs text-gray-500 font-medium pl-1">第 {chap.outline.chapterNumber}-{Math.min(chap.outline.chapterNumber + 4, chapters[chapters.length-1].outline.chapterNumber)} 章</span>
                          )}

                          <button
                              onClick={(e) => {
                                  e.stopPropagation();
                                  handleGenerateGroupSummary(idx);
                              }}
                              disabled={generatingSummaryIndices.includes(idx)}
                              className="text-gray-500 hover:text-indigo-400 p-1 rounded hover:bg-gray-700/50 transition-colors shrink-0"
                              title={chap.outline.groupSummary ? "重新生成卷标" : "生成卷标"}
                          >
                              {generatingSummaryIndices.includes(idx) ? (
                                  <Loader2 size={12} className="animate-spin" />
                              ) : (
                                  <Sparkles size={12} />
                              )}
                          </button>
                      </div>
                  </div>
              )}

              <div
                id={`chapter-item-${idx}`} 
                role="button"
                tabIndex={0}
                onClick={() => {
                  setActiveChapterIndex(idx);
                  if (window.innerWidth < 768) setShowSidebar(false);
                }}
                onKeyDown={(e) => {
                   if (e.key === 'Enter' || e.key === ' ') {
                      setActiveChapterIndex(idx);
                      if (window.innerWidth < 768) setShowSidebar(false);
                   }
                }}
                className={`w-full text-left p-3 rounded-lg text-sm transition-all flex items-start gap-2 cursor-pointer group/item
                  ${activeChapterIndex === idx 
                    ? 'bg-indigo-900/40 border border-indigo-500/30 text-indigo-200' 
                    : 'hover:bg-gray-800 text-gray-400 border border-transparent'}
                `}
              >
                <div className="mt-0.5 shrink-0">
                  {chap.isGenerated ? <CheckCircle size={14} className="text-green-500" /> : <FileText size={14} />}
                </div>
                <div className="min-w-0 flex-1">
                  <div className="flex items-center justify-between gap-2">
                      <div className="font-semibold truncate">第{chap.outline.chapterNumber}章: {chap.outline.title}</div>
                      <div className="flex items-center gap-1 shrink-0">
                         <CopyBtn 
                            text={`第${chap.outline.chapterNumber}章 ${chap.outline.title}`} 
                            className="shrink-0"
                         />
                         <button
                            onClick={(e) => {
                                e.stopPropagation();
                                onDeleteChapter(idx);
                            }}
                            className="p-1.5 md:p-1 rounded-md text-gray-500 hover:text-red-400 hover:bg-red-900/20 transition-all opacity-100 md:opacity-0 md:group-hover/item:opacity-100"
                            title="删除本章"
                         >
                            <Trash2 size={14} className="md:w-3 md:h-3" />
                         </button>
                      </div>
                  </div>
                  <div className="text-xs text-gray-500 mt-1 truncate">{chap.outline.coolPoint}</div>
                </div>
              </div>
            </React.Fragment>
          ))}
        </div>

        <div className="p-3 border-t border-gray-800 bg-gray-900 shrink-0 space-y-2">
          {isBatchGenerating && (
             <div className="text-xs text-indigo-400 flex items-center gap-2 bg-indigo-900/20 p-2 rounded mb-2">
                <Loader2 size={12} className="animate-spin" />
                {batchProgress}
             </div>
          )}

          <button
            onClick={() => onBatchGenerate(5)}
            disabled={isLoadingMore || isBatchGenerating}
            className="w-full py-2.5 rounded-lg bg-indigo-600 hover:bg-indigo-500 text-white shadow-lg shadow-indigo-900/30 transition-all flex items-center justify-center gap-2 text-sm font-bold disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isBatchGenerating ? (
              <>
                <Loader2 size={16} className="animate-spin" />
                自动码字中...
              </>
            ) : (
              <>
                <Sparkles size={16} />
                一键生成后续5章
              </>
            )}
          </button>

           <button
            onClick={onLoadMoreChapters}
            disabled={isLoadingMore || isBatchGenerating}
            className="w-full py-2 rounded-lg border border-dashed border-gray-600 text-gray-400 hover:text-white hover:border-indigo-500 hover:bg-gray-800 transition-all flex items-center justify-center gap-2 text-xs font-medium"
          >
            {isLoadingMore ? (
              <>
                <Loader2 size={14} className="animate-spin" />
                推演中...
              </>
            ) : (
              <>
                <PlusCircle size={14} />
                仅生成后续5章大纲
              </>
            )}
          </button>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col h-full overflow-hidden relative bg-black/20">
        <div className="p-4 border-b border-gray-800 bg-gray-850 flex justify-between items-start md:items-center flex-col md:flex-row gap-4 shrink-0">
          <div className="w-full md:w-auto">
             <h3 className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">本章脉络 & 规则</h3>
             <p className="text-sm text-gray-300 line-clamp-2 md:line-clamp-1">
               <span className="text-indigo-400">[{activeChapter.outline.narrativePulse}]</span> {activeChapter.outline.rules.join(" | ")}
             </p>
          </div>

          <div className="flex items-center gap-3 self-end md:self-auto shrink-0">
            {canUndo && !isGenerating && !isBatchGenerating && (
                <button
                    onClick={handleUndoRewrite}
                    className="px-3 py-2 rounded-lg bg-gray-800 hover:bg-gray-700 text-orange-400 border border-orange-500/30 transition-all flex items-center gap-2 text-sm md:text-base font-medium"
                    title="恢复重写前的内容"
                >
                    <RotateCcw size={16} />
                    <span className="hidden sm:inline">撤销重写</span>
                </button>
            )}

            {activeChapter.isGenerated && !isGenerating && !isBatchGenerating && (
                <button
                    onClick={() => setShowRewriteModal(true)}
                    className="px-3 py-2 rounded-lg bg-gray-800 hover:bg-gray-700 text-indigo-300 border border-indigo-500/30 transition-all flex items-center gap-2 text-sm md:text-base font-medium"
                    title="重写本章"
                >
                    <RefreshCw size={16} />
                    <span className="hidden sm:inline">重写</span>
                </button>
            )}

            {(activeChapter.content || activeChapter.isGenerated) && !isGenerating && !isBatchGenerating && (
              <button
                onClick={() => setIsEditing(!isEditing)}
                className={`px-4 py-2 rounded-lg flex items-center gap-2 font-bold transition-all border text-sm md:text-base
                  ${isEditing 
                    ? 'bg-green-600/20 text-green-400 border-green-500/50 hover:bg-green-600/30' 
                    : 'bg-gray-800 hover:bg-gray-700 text-gray-300 border-gray-700'
                  }`}
              >
                {isEditing ? (
                  <>
                    <Save size={16} />
                    <span className="hidden sm:inline">完成</span>
                  </>
                ) : (
                  <>
                    <Edit size={16} />
                    <span className="hidden sm:inline">修改</span>
                  </>
                )}
              </button>
            )}

            {(!activeChapter.isGenerated && !activeChapter.content) && (
              <button
                onClick={handleGenerate}
                disabled={isGenerating || isBatchGenerating}
                className="px-5 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg flex items-center gap-2 font-bold shadow-lg shadow-indigo-500/20 whitespace-nowrap text-sm md:text-base disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {isGenerating ? '创作中...' : (isBatchGenerating ? '批量任务进行中...' : '生成正文')}
                {!isGenerating && !isBatchGenerating && <Play size={16} fill="currentColor" />}
              </button>
            )}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4 md:p-8">
          <div className="max-w-3xl mx-auto h-full pb-24">
             {isEditing ? (
               <div className="h-full min-h-[600px] bg-gray-900 p-4 md:p-8 rounded-xl border border-indigo-500/30 shadow-2xl flex flex-col animate-in fade-in duration-300">
                 <div className="mb-4 pb-4 border-b border-gray-800 flex flex-col gap-2">
                    <div className="flex justify-between items-center text-xs text-gray-500 uppercase tracking-wider font-bold">
                        <span>正在编辑: 第{activeChapter.outline.chapterNumber}章</span>
                        <span className={activeChapter.content.length > 2000 ? 'text-green-500' : 'text-gray-500'}>
                            {activeChapter.content.length} 字
                        </span>
                    </div>
                    <input 
                        type="text" 
                        value={activeChapter.outline.title}
                        onChange={(e) => onUpdateTitle(activeChapterIndex, e.target.value)}
                        className="bg-transparent text-xl md:text-2xl font-serif font-bold text-white border-b border-gray-700 focus:border-indigo-500 outline-none py-1 transition-colors placeholder-gray-700"
                        placeholder="输入章节标题..."
                    />
                 </div>
                 <textarea 
                   className="w-full flex-1 bg-transparent border-none outline-none text-gray-200 font-serif text-base md:text-lg leading-loose resize-none focus:ring-0"
                   value={activeChapter.content}
                   onChange={(e) => onUpdateChapter(activeChapterIndex, e.target.value, true)} 
                   placeholder="在此输入章节正文..."
                   spellCheck={false}
                   autoFocus
                 />
               </div>
             ) : (
               <>
                 <ChapterReader 
                   title={`第${activeChapter.outline.chapterNumber}章 ${activeChapter.outline.title}`}
                   content={activeChapter.content}
                   isStreaming={isGenerating && activeChapterIndex === chapters.findIndex(c => c === activeChapter)}
                 />

                 <div className="mt-12 mb-8 text-center space-y-6">
                    {activeChapter.isGenerated && activeChapterIndex < chapters.length - 1 && (
                       <button
                         onClick={() => setActiveChapterIndex(prev => prev + 1)}
                         className="text-gray-400 hover:text-white underline decoration-indigo-500 underline-offset-4 py-4 px-8 text-lg transition-all flex items-center gap-2 mx-auto"
                       >
                         继续下一章
                         <ArrowDown size={16} />
                       </button>
                    )}

                    {activeChapter.isGenerated && activeChapterIndex === chapters.length - 1 && (
                        <div className="flex flex-col items-center justify-center gap-4 py-8 border-t border-gray-800/50">
                            <p className="text-gray-500 text-sm">当前剧情已至最新，是否继续推演后续发展？</p>
                            <button
                                onClick={() => onBatchGenerate(5)}
                                disabled={isLoadingMore || isBatchGenerating}
                                className="px-8 py-4 bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 text-white rounded-xl font-bold shadow-xl shadow-indigo-900/40 flex items-center gap-3 transition-all transform hover:scale-105 disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none"
                            >
                                {isBatchGenerating ? (
                                    <>
                                        <Loader2 size={24} className="animate-spin" />
                                        <span className="text-lg">AI正在疯狂码字中...</span>
                                    </>
                                ) : (
                                    <>
                                        <Sparkles size={24} />
                                        <span className="text-lg">一键生成后续5章 (大纲+正文)</span>
                                    </>
                                )}
                            </button>
                            {!isBatchGenerating && (
                                <p className="text-xs text-gray-600">
                                    * 将根据当前剧情自动规划大纲并撰写正文
                                </p>
                            )}
                        </div>
                    )}
                 </div>
               </>
             )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default StepWriting;

import React, { useState, useEffect, useRef } from 'react';
import { GenerationStep, Character, WorldSetting, PlotPoint, ChapterContent, ProjectData } from './types';
import { generateCharactersAndWorld, generateMainPlot, generateChapterOutlines, generateNextChapterOutlines, generateFullChapterContent } from './services/geminiService';
import StepSetup from './components/StepSetup';
import StepCharacters from './components/StepCharacters';
import StepPlot from './components/StepPlot';
import StepWriting from './components/StepWriting';
import TitleGeneratorModal from './components/TitleGeneratorModal';
import { Download, Upload, Save, FileJson, FilePlus, PenLine } from 'lucide-react';

const STORAGE_KEY = 'soulwriter_autosave_v1';

const App: React.FC = () => {
  // 核心状态
  const [step, setStep] = useState<GenerationStep>(GenerationStep.SETUP);
  const [isLoading, setIsLoading] = useState(false);
  const [isLoadedFromStorage, setIsLoadedFromStorage] = useState(false);
  const [batchProgress, setBatchProgress] = useState<string | null>(null); // null表示不在批量生成中

  // Data State
  const [prompt, setPrompt] = useState("重生回到十年前，觉醒了'万物增幅'系统，这一世我要在这个赛博朋克与古武并存的世界成为最强。");
  const [bookTitle, setBookTitle] = useState("");
  const [world, setWorld] = useState<WorldSetting | null>(null);
  const [characters, setCharacters] = useState<Character[]>([]);
  const [plot, setPlot] = useState<PlotPoint[]>([]);
  const [chapters, setChapters] = useState<ChapterContent[]>([]);

  // UI State
  const [showTitleModal, setShowTitleModal] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- 自动保存与恢复逻辑 ---

  // 1. 初始化时加载数据
  useEffect(() => {
    const savedData = localStorage.getItem(STORAGE_KEY);
    if (savedData) {
      try {
        const parsed: ProjectData = JSON.parse(savedData);
        // 简单的版本检查
        if (parsed.version === 1) {
          console.log("检测到自动保存进度，正在恢复...");
          setStep(parsed.step);
          setPrompt(parsed.prompt || "");
          setBookTitle(parsed.bookTitle || "");
          setWorld(parsed.world);
          setCharacters(parsed.characters);
          setPlot(parsed.plot);
          setChapters(parsed.chapters);
        }
      } catch (e) {
        console.error("读取自动保存失败:", e);
      }
    }
    setIsLoadedFromStorage(true); // 标记加载尝试已完成
  }, []);

  // 2. 数据变化时自动保存
  useEffect(() => {
    // 只有在初始化加载完成后才开始保存，防止覆盖
    if (!isLoadedFromStorage) return;

    const data: ProjectData = {
      version: 1,
      step,
      prompt,
      bookTitle,
      world,
      characters,
      plot,
      chapters
    };

    // 使用 debounce 或直接保存，这里数据量不大直接保存
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    console.log("进度已自动保存");

  }, [step, prompt, bookTitle, world, characters, plot, chapters, isLoadedFromStorage]);

  // 新建项目 (重置)
  const handleNewProject = () => {
    if (window.confirm("确定要新建项目吗？这将清除当前的自动保存进度，且无法恢复。")) {
      // 清除本地存储
      localStorage.removeItem(STORAGE_KEY);

      // 强制刷新页面以重置所有状态为默认值
      // 这样可以确保 autosave 逻辑不会意外保存旧状态，并且让用户回到带有默认提示文案的初始界面
      window.location.reload();
    }
  };

  // --- 业务逻辑 ---

  // Step 1 -> 2: Setup to Characters
  const handleSetupGenerate = async () => {
    setIsLoading(true);
    try {
      const data = await generateCharactersAndWorld(prompt);
      setWorld(data.world);
      setCharacters(data.characters);
      setStep(GenerationStep.CHARACTERS);
    } catch (e) {
      alert("生成失败，请检查API Key或重试");
    } finally {
      setIsLoading(false);
    }
  };

  // Step 2 -> 3: Characters to Plot
  const handleConfirmCharacters = async (updatedWorld: WorldSetting, updatedCharacters: Character[]) => {
    if (!updatedWorld || updatedCharacters.length === 0) return;

    setWorld(updatedWorld);
    setCharacters(updatedCharacters);

    setIsLoading(true);
    try {
      const data = await generateMainPlot(updatedWorld, updatedCharacters);
      setPlot(data);
      setStep(GenerationStep.PLOT);
    } catch (e) {
      alert("生成大纲失败");
    } finally {
      setIsLoading(false);
    }
  };

  // Step 3 -> 4: Plot to Chapter Outlines -> Writing
  const handleConfirmPlot = async () => {
    if (!world || characters.length === 0 || plot.length === 0) return;
    setIsLoading(true);
    try {
      const outlineData = await generateChapterOutlines(world, characters, plot, 5);
      const initialChapters: ChapterContent[] = outlineData.map(o => ({
        outline: o,
        content: '',
        isGenerated: false
      }));
      setChapters(initialChapters);
      setStep(GenerationStep.WRITING);
    } catch (e) {
      alert("生成细纲失败");
    } finally {
      setIsLoading(false);
    }
  };

  // 仅续写后续章节大纲
  const handleAddChaptersOutline = async (count: number = 5) => {
    if (!world || characters.length === 0 || plot.length === 0 || chapters.length === 0) return;

    setIsLoading(true);
    try {
      const lastChapter = chapters[chapters.length - 1];
      const newOutlines = await generateNextChapterOutlines(world, characters, plot, lastChapter.outline, count);

      const newChapters: ChapterContent[] = newOutlines.map(o => ({
        outline: o,
        content: '',
        isGenerated: false
      }));

      setChapters(prev => [...prev, ...newChapters]);
    } catch (e) {
      console.error(e);
      alert("续写章节大纲失败");
    } finally {
      setIsLoading(false);
    }
  };

  /**
   * 批量生成后续章节（大纲 + 正文）
   * 逻辑：
   * 1. 调用大纲生成接口，规划后续 N 章。
   * 2. 将空章节加入 State。
   * 3. 循环遍历新章节，串行调用正文生成接口（保证上下文连贯）。
   */
  const handleBatchGenerateChapters = async (count: number = 5) => {
    if (!world || characters.length === 0 || plot.length === 0 || chapters.length === 0) return;
    if (batchProgress) return; // 防止重复点击

    try {
      // 1. 生成大纲
      setBatchProgress("正在规划后续剧情大纲...");
      const lastChapter = chapters[chapters.length - 1];
      const newOutlines = await generateNextChapterOutlines(world, characters, plot, lastChapter.outline, count);

      // 2. 创建占位章节并添加到状态
      const newChaptersPlaceholder: ChapterContent[] = newOutlines.map(o => ({
        outline: o,
        content: '',
        isGenerated: false
      }));

      // 先保存当前的章节数量，作为后续更新的起始索引
      const startIndex = chapters.length;

      // 更新 UI 显示出新的空章节
      setChapters(prev => [...prev, ...newChaptersPlaceholder]);

      // 3. 串行生成每一章的正文
      // 注意：这里我们不能直接用 chapters 状态，因为它是旧的闭包。
      // 我们需要构建一个临时的上下文链。
      let previousContent = lastChapter.content || lastChapter.outline.summary; 

      for (let i = 0; i < newChaptersPlaceholder.length; i++) {
        const currentChapterIndex = startIndex + i;
        const currentChapter = newChaptersPlaceholder[i];

        setBatchProgress(`正在撰写第 ${currentChapter.outline.chapterNumber} 章... (${i + 1}/${count})`);

        // 调用非流式生成接口
        const generatedContent = await generateFullChapterContent(
          currentChapter.outline,
          world,
          characters,
          previousContent
        );

        // 更新单个章节状态
        handleUpdateChapter(currentChapterIndex, generatedContent, true);

        // 更新上下文，为下一章做准备
        previousContent = generatedContent;
      }

      setBatchProgress(null);

    } catch (e) {
      console.error(e);
      alert("批量生成过程中断，请重试");
      setBatchProgress(null);
    }
  };


  // 更新章节内容
  const handleUpdateChapter = (index: number, content: string, isGenerated: boolean) => {
    setChapters(prev => {
      const newChapters = [...prev];
      if (newChapters[index]) {
        newChapters[index] = {
          ...newChapters[index],
          content,
          isGenerated
        };
      }
      return newChapters;
    });
  };

  // 更新章节标题
  const handleUpdateChapterTitle = (index: number, title: string) => {
    setChapters(prev => {
      const newChapters = [...prev];
      if (newChapters[index]) {
        newChapters[index] = {
          ...newChapters[index],
          outline: {
            ...newChapters[index].outline,
            title
          }
        };
      }
      return newChapters;
    });
  };

  // 更新分组小结
  const handleUpdateGroupSummary = (index: number, summary: string) => {
      setChapters(prev => {
          const newChapters = [...prev];
          if (newChapters[index]) {
              newChapters[index] = {
                  ...newChapters[index],
                  outline: {
                      ...newChapters[index].outline,
                      groupSummary: summary
                  }
              }
          }
          return newChapters;
      })
  }

  // 删除分组小结
  const handleDeleteGroupSummary = (index: number) => {
      handleUpdateGroupSummary(index, "");
  };

  // 删除章节
  const handleDeleteChapter = (index: number) => {
      if (chapters.length <= 1) {
          alert("无法删除：至少需要保留一个章节。");
          return;
      }

      setChapters(prev => {
          // 1. 过滤掉删除的章节
          const newChapters = prev.filter((_, i) => i !== index);

          // 2. 重新编排章节号，保证连续性
          return newChapters.map((chap, i) => ({
              ...chap,
              outline: {
                  ...chap.outline,
                  chapterNumber: i + 1
              }
          }));
      });
  };

  // 导出项目
  const handleExport = () => {
    const data: ProjectData = {
      version: 1,
      step,
      prompt,
      bookTitle,
      world,
      characters,
      plot,
      chapters
    };

    const jsonString = JSON.stringify(data, null, 2);
    const blob = new Blob([jsonString], { type: "application/json" });
    const url = URL.createObjectURL(blob);

    const link = document.createElement('a');
    link.href = url;
    link.download = `${bookTitle || 'soulwriter-project'}-${new Date().toISOString().slice(0, 10)}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  // 导入项目触发
  const triggerImport = () => {
    fileInputRef.current?.click();
  };

  // 处理文件读取
  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (json.version && json.step) {
          const data = json as ProjectData;
          setStep(data.step);
          setPrompt(data.prompt || "");
          setBookTitle(data.bookTitle || "");
          setWorld(data.world);
          setCharacters(data.characters);
          setPlot(data.plot);
          setChapters(data.chapters);
          alert("项目导入成功！");
        } else {
          alert("无效的项目文件格式");
        }
      } catch (error) {
        console.error("Import error", error);
        alert("文件解析失败");
      }
    };
    reader.readAsText(file);
    e.target.value = ''; 
  };

  return (
    <div className="min-h-screen bg-[#0d1117] text-gray-100 font-sans selection:bg-indigo-500/30">
      <header className="border-b border-gray-800 bg-[#0d1117]/80 backdrop-blur sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-4">
             {/* Logo */}
             <div className="font-bold text-xl tracking-tight bg-gradient-to-r from-indigo-400 to-cyan-400 bg-clip-text text-transparent flex items-center gap-2 cursor-pointer shrink-0" onClick={() => setStep(GenerationStep.SETUP)}>
                <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center text-white">
                  <FileJson size={20} />
                </div>
                <span className="hidden sm:inline">SoulWriter AI</span>
              </div>

              {/* Divider */}
              <div className="h-6 w-px bg-gray-700 mx-2 hidden sm:block"></div>

              {/* Book Title */}
              <button 
                onClick={() => setShowTitleModal(true)}
                className="flex items-center gap-2 px-3 py-1.5 rounded-lg hover:bg-gray-800 transition-colors group max-w-[150px] sm:max-w-xs"
                title="点击修改书名"
              >
                <div className="text-sm font-bold text-gray-200 truncate">
                   {bookTitle || "未命名作品"}
                </div>
                <PenLine size={14} className="text-gray-500 group-hover:text-indigo-400 shrink-0" />
              </button>
          </div>


          <div className="flex items-center gap-4">
            {/* Steps Indicator (Desktop) */}
            <div className="hidden lg:flex gap-2 text-xs font-mono text-gray-500 mr-4">
              <span className={step === GenerationStep.SETUP ? 'text-indigo-400' : ''}>01.设定</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.CHARACTERS ? 'text-indigo-400' : ''}>02.人物</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.PLOT ? 'text-indigo-400' : ''}>03.大纲</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.WRITING ? 'text-indigo-400' : ''}>04.正文</span>
            </div>

            {/* Actions */}
            <div className="flex items-center gap-2 border-l border-gray-700 pl-4">
              <input 
                type="file" 
                ref={fileInputRef} 
                className="hidden" 
                accept=".json" 
                onChange={handleImport}
              />

              {/* 新建项目按钮 */}
              <button 
                onClick={handleNewProject}
                className="p-2 text-gray-400 hover:text-white hover:bg-gray-800 rounded-lg transition-colors flex items-center gap-2 text-sm"
                title="新建项目 (清空进度)"
              >
                <FilePlus size={18} />
                <span className="hidden sm:inline">新建项目</span>
              </button>

              <button 
                onClick={triggerImport}
                className="p-2 text-gray-400 hover:text-white hover:bg-gray-800 rounded-lg transition-colors flex items-center gap-2 text-sm"
                title="导入项目"
              >
                <Upload size={18} />
                <span className="hidden sm:inline">导入</span>
              </button>

              <button 
                onClick={handleExport}
                className="px-3 py-1.5 bg-gray-800 hover:bg-gray-700 text-indigo-300 border border-indigo-500/30 rounded-lg transition-colors flex items-center gap-2 text-sm font-medium"
                title="导出项目"
              >
                <Save size={18} />
                <span className="hidden sm:inline">保存</span>
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8">
        {step === GenerationStep.SETUP && (
          <StepSetup 
            prompt={prompt}
            setPrompt={setPrompt}
            onGenerate={handleSetupGenerate} 
            isLoading={isLoading} 
          />
        )}

        {step === GenerationStep.CHARACTERS && world && (
          <StepCharacters 
            world={world} 
            characters={characters} 
            onConfirm={handleConfirmCharacters}
            isLoading={isLoading}
          />
        )}

        {step === GenerationStep.PLOT && (
          <StepPlot 
            plot={plot}
            onConfirm={handleConfirmPlot}
            isLoading={isLoading}
          />
        )}

        {step === GenerationStep.WRITING && world && (
          <StepWriting 
            chapters={chapters}
            world={world}
            characters={characters}
            onUpdateChapter={handleUpdateChapter}
            onUpdateTitle={handleUpdateChapterTitle}
            onUpdateGroupSummary={handleUpdateGroupSummary}
            onDeleteChapter={handleDeleteChapter}
            onDeleteGroupSummary={handleDeleteGroupSummary}
            onLoadMoreChapters={handleAddChaptersOutline}
            onBatchGenerate={handleBatchGenerateChapters}
            isLoadingMore={isLoading}
            batchProgress={batchProgress}
          />
        )}
      </main>

      {/* Modals */}
      {showTitleModal && (
        <TitleGeneratorModal 
           currentTitle={bookTitle}
           onSelect={(t) => setBookTitle(t)}
           onClose={() => setShowTitleModal(false)}
           contextData={{ prompt, world, characters }}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ChapterContent, Character, WorldSetting } from '../types';
import { streamChapterContent, generateBatchSummary } from '../services/geminiService';
import ChapterReader from './ChapterReader';
import { FileText, Play, CheckCircle, Menu, X, Edit, Save, PlusCircle, Loader2, Sparkles, ArrowDown, RefreshCw, RotateCcw, CornerDownLeft, Bookmark, Copy, Check, Trash2, AlertTriangle } from 'lucide-react';

interface Props {
  chapters: ChapterContent[];
  world: WorldSetting;
  characters: Character[];
  onUpdateChapter: (index: number, content: string, isGenerated: boolean) => void;
  onUpdateTitle: (index: number, title: string) => void;
  onUpdateGroupSummary: (index: number, summary: string) => void; 
  onDeleteChapter: (index: number) => void; // 新增：删除章节
  onDeleteGroupSummary: (index: number) => void; // 新增：删除卷标
  onLoadMoreChapters: () => void;
  onBatchGenerate: (count: number) => void;
  isLoadingMore: boolean;
  batchProgress: string | null;
}

const CopyBtn = ({ text, className = "" }: { text: string, className?: string }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = (e: React.MouseEvent) => {
    e.stopPropagation();
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <button 
      onClick={handleCopy} 
      className={`p-1 rounded-md hover:bg-gray-700/50 transition-colors inline-flex items-center justify-center shrink-0 ${copied ? 'text-green-400' : 'text-gray-500 hover:text-indigo-400'} ${className}`}
      title="复制内容"
    >
      {copied ? <Check size={12} /> : <Copy size={12} />}
    </button>
  );
};

const StepWriting: React.FC<Props> = ({ 
  chapters, 
  world, 
  characters, 
  onUpdateChapter, 
  onUpdateTitle, 
  onUpdateGroupSummary,
  onDeleteChapter,
  onDeleteGroupSummary,
  onLoadMoreChapters, 
  onBatchGenerate,
  isLoadingMore,
  batchProgress
}) => {
  const [activeChapterIndex, setActiveChapterIndex] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [showSidebar, setShowSidebar] = useState(false); 
  const [isEditing, setIsEditing] = useState(false);

  // Loading state specifically for generating group summaries
  // Key is the starting index of the group
  const [generatingSummaryIndices, setGeneratingSummaryIndices] = useState<number[]>([]);

  // 重写功能相关状态
  const [showRewriteModal, setShowRewriteModal] = useState(false);
  const [rewriteInstructions, setRewriteInstructions] = useState("");

  // 删除确认弹窗状态
  const [deleteConfirm, setDeleteConfirm] = useState<{
    isOpen: boolean;
    type: 'chapter' | 'summary';
    index: number;
    title?: string;
  }>({ isOpen: false, type: 'chapter', index: -1 });

  // 撤销历史记录
  const [undoHistory, setUndoHistory] = useState<Record<number, string>>({});

  // 章节跳转输入状态
  const [jumpInput, setJumpInput] = useState("");

  // 确保 activeChapterIndex 不越界
  useEffect(() => {
      if (chapters.length > 0 && activeChapterIndex >= chapters.length) {
          setActiveChapterIndex(Math.max(0, chapters.length - 1));
      }
  }, [chapters.length, activeChapterIndex]);

  const activeChapter = chapters[activeChapterIndex] || chapters[0]; // 防御性处理

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setIsEditing(false);
  }, [activeChapterIndex]);

  const handleGenerate = async () => {
    if (isGenerating || activeChapter.isGenerated) return;
    startGeneration();
  };

  const handleRewrite = async () => {
    if (isGenerating) return;

    if (activeChapter.content) {
      setUndoHistory(prev => ({
        ...prev,
        [activeChapterIndex]: activeChapter.content
      }));
    }

    setShowRewriteModal(false);
    startGeneration(rewriteInstructions);
    setRewriteInstructions("");
  };

  const handleUndoRewrite = () => {
    const prevContent = undoHistory[activeChapterIndex];
    if (!prevContent) return;

    if (window.confirm("确定要撤销重写，恢复到上一个版本吗？当前版本将丢失。")) {
      onUpdateChapter(activeChapterIndex, prevContent, true);
      setUndoHistory(prev => {
        const newState = { ...prev };
        delete newState[activeChapterIndex];
        return newState;
      });
    }
  };

  const handleJumpToChapter = () => {
    const target = parseInt(jumpInput);
    if (isNaN(target)) return;

    if (target < 1 || target > chapters.length) {
      alert(`请输入有效章节号 (1-${chapters.length})`);
      return;
    }

    setActiveChapterIndex(target - 1);
    setJumpInput("");
    if (window.innerWidth < 768) setShowSidebar(false);
  };

  const handleJumpKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleJumpToChapter();
    }
  };

  // 生成分组标题的逻辑
  const handleGenerateGroupSummary = async (startIndex: number) => {
    if (generatingSummaryIndices.includes(startIndex)) return;

    // 获取这5章
    const groupChapters = chapters.slice(startIndex, startIndex + 5).map(c => c.outline);
    if (groupChapters.length === 0) return;

    setGeneratingSummaryIndices(prev => [...prev, startIndex]);

    try {
        const summary = await generateBatchSummary(groupChapters);
        onUpdateGroupSummary(startIndex, summary);
    } catch (e) {
        console.error("生成卷标出错详情:", e);
        alert("生成卷标失败，请查看控制台日志以获取更多信息");
    } finally {
        setGeneratingSummaryIndices(prev => prev.filter(i => i !== startIndex));
    }
  };

  const startGeneration = async (instructions?: string) => {
    setIsGenerating(true);
    setIsEditing(false);

    if (window.innerWidth < 768) {
        setShowSidebar(false);
    }

    let prevContext = "";
    if (activeChapterIndex > 0) {
      const prevChap = chapters[activeChapterIndex - 1];
      prevContext = prevChap.content || prevChap.outline.summary;
    }

    try {
      if (instructions) {
         onUpdateChapter(activeChapterIndex, "", false); 
      }

      let fullText = "";
      await streamChapterContent(
        activeChapter.outline,
        world,
        characters,
        prevContext,
        (textChunk) => {
          fullText += textChunk;
          onUpdateChapter(activeChapterIndex, fullText, false);
        },
        instructions
      );

      onUpdateChapter(activeChapterIndex, fullText, true);

    } catch (e) {
      alert("生成中断，请重试");
    } finally {
      setIsGenerating(false);
    }
  };

  // --- 删除确认逻辑 ---
  const requestDeleteChapter = (index: number) => {
      setDeleteConfirm({
          isOpen: true,
          type: 'chapter',
          index: index,
          title: `第 ${chapters[index].outline.chapterNumber} 章`
      });
  };

  const requestDeleteSummary = (index: number, summary: string) => {
      setDeleteConfirm({
          isOpen: true,
          type: 'summary',
          index: index,
          title: summary || "当前卷标"
      });
  };

  const executeDelete = () => {
      if (deleteConfirm.type === 'chapter') {
          onDeleteChapter(deleteConfirm.index);
          // 如果删除的是当前选中的章节，且不是第一章，需要更新 activeIndex
          if (activeChapterIndex === deleteConfirm.index && activeChapterIndex > 0) {
              setActiveChapterIndex(Math.max(0, activeChapterIndex - 1));
          }
      } else {
          onDeleteGroupSummary(deleteConfirm.index);
      }
      setDeleteConfirm({ ...deleteConfirm, isOpen: false });
  };

  if (!activeChapter) return <div>数据加载中...</div>;

  const isBatchGenerating = batchProgress !== null;
  const canUndo = !!undoHistory[activeChapterIndex];

  return (
    <div className="flex h-[calc(100vh-100px)] overflow-hidden rounded-xl border border-gray-800 bg-gray-950 relative">

      {/* 统一的删除确认模态框 */}
      {deleteConfirm.isOpen && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[70] flex items-center justify-center p-4 animate-in fade-in duration-200">
           <div className="bg-gray-900 border border-red-500/30 rounded-xl p-6 w-full max-w-sm shadow-2xl flex flex-col items-center text-center">
              <div className="w-12 h-12 bg-red-900/20 rounded-full flex items-center justify-center mb-4 text-red-500">
                  <AlertTriangle size={24} />
              </div>
              <h3 className="text-xl font-bold text-white mb-2">
                  确定要删除吗？
              </h3>
              <p className="text-gray-400 text-sm mb-6 leading-relaxed">
                  您即将删除 <span className="text-white font-bold">{deleteConfirm.title}</span>。
                  {deleteConfirm.type === 'chapter' && (
                      <span className="block mt-1 text-red-400 text-xs">注意：删除章节后，后续章节序号将自动前移，且无法撤销。</span>
                  )}
              </p>

              <div className="flex gap-3 w-full">
                  <button 
                    onClick={() => setDeleteConfirm({ ...deleteConfirm, isOpen: false })} 
                    className="flex-1 px-4 py-3 rounded-lg bg-gray-800 hover:bg-gray-700 text-gray-300 font-medium transition-colors"
                  >
                    取消
                  </button>
                  <button 
                    onClick={executeDelete} 
                    className="flex-1 px-4 py-3 rounded-lg bg-red-600 hover:bg-red-500 text-white font-bold shadow-lg shadow-red-900/30 transition-colors"
                  >
                    确认删除
                  </button>
              </div>
           </div>
        </div>
      )}

      {/* 重写设置模态框 */}
      {showRewriteModal && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[60] flex items-center justify-center p-4">
           <div className="bg-gray-900 border border-gray-700 rounded-xl p-6 w-full max-w-lg shadow-2xl animate-in fade-in zoom-in duration-200 flex flex-col max-h-[90vh]">
              <h3 className="text-xl font-bold text-white mb-2 flex items-center gap-2 shrink-0">
                  <RefreshCw className="text-indigo-400" size={20} />
                  重写本章
              </h3>

              <div className="overflow-y-auto mb-4 custom-scrollbar pr-2">
                 <div className="bg-gray-800/50 rounded-lg p-3 mb-4 border border-gray-700">
                    <span className="text-xs font-bold text-indigo-400 uppercase tracking-wider block mb-1">当前大纲摘要</span>
                    <p className="text-sm text-gray-300 leading-relaxed">
                      {activeChapter.outline.summary}
                    </p>
                 </div>

                 <p className="text-sm text-gray-400 mb-2">
                     AI 将根据上述大纲重新撰写正文。您可以输入具体的修改意见，AI会重点关注。
                 </p>
              </div>

              <textarea 
                  className="w-full h-32 bg-gray-950 border border-gray-700 rounded-lg p-3 text-gray-200 focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none resize-none placeholder-gray-600 text-sm shrink-0" 
                  placeholder="例如：这一章的打斗细节太少了，多描写一下招式；或者，女主的反应再害羞一点..."
                  value={rewriteInstructions}
                  onChange={(e) => setRewriteInstructions(e.target.value)}
                  autoFocus
              />
              <div className="flex justify-end gap-3 mt-6 shrink-0">
                  <button 
                    onClick={() => setShowRewriteModal(false)} 
                    className="px-4 py-2 rounded-lg text-gray-400 hover:text-white hover:bg-gray-800 transition-colors text-sm"
                  >
                    取消
                  </button>
                  <button 
                    onClick={handleRewrite} 
                    className="px-4 py-2 rounded-lg bg-indigo-600 hover:bg-indigo-500 text-white font-bold shadow-lg shadow-indigo-500/20 text-sm flex items-center gap-2"
                  >
                    <RefreshCw size={14} />
                    开始重写
                  </button>
              </div>
           </div>
        </div>
      )}

      {showSidebar && (
        <div 
          className="fixed inset-0 bg-black/60 backdrop-blur-sm z-30 md:hidden transition-opacity"
          onClick={() => setShowSidebar(false)}
        />
      )}

      <button 
        className="md:hidden fixed bottom-6 right-6 z-50 bg-indigo-600 hover:bg-indigo-500 text-white p-4 rounded-full shadow-xl shadow-indigo-900/50 transition-all active:scale-95 flex items-center justify-center"
        onClick={() => setShowSidebar(!showSidebar)}
        title={showSidebar ? "关闭目录" : "打开目录"}
      >
        {showSidebar ? <X size={24} /> : <Menu size={24} />}
      </button>

      {/* Sidebar - Chapter List */}
      <div className={`
        fixed md:relative z-40 w-72 max-w-[80vw] bg-gray-900 border-r border-gray-800 h-full flex flex-col transition-transform duration-300 ease-in-out shadow-2xl md:shadow-none
        ${showSidebar ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
      `}>
        <div className="p-4 border-b border-gray-800 bg-gray-900 font-bold text-gray-200 flex justify-between items-center shrink-0">
          <span>目录 ({chapters.length}章)</span>
          <button 
            onClick={() => setShowSidebar(false)}
            className="md:hidden text-gray-500 hover:text-white"
          >
            <X size={20} />
          </button>
        </div>

        <div className="px-3 py-2 border-b border-gray-800 bg-gray-900/50 shrink-0">
          <div className="flex gap-2">
            <input 
              type="number" 
              className="w-full bg-gray-950 border border-gray-700 rounded text-sm px-2 py-1 text-gray-300 focus:border-indigo-500 outline-none placeholder-gray-600"
              placeholder="前往章节..."
              value={jumpInput}
              onChange={(e) => setJumpInput(e.target.value)}
              onKeyDown={handleJumpKeyDown}
              min={1}
              max={chapters.length}
            />
            <button 
              onClick={handleJumpToChapter}
              disabled={!jumpInput}
              className="bg-gray-800 hover:bg-gray-700 border border-gray-700 text-gray-400 hover:text-white px-2 rounded transition-colors disabled:opacity-50"
              title="跳转"
            >
              <CornerDownLeft size={16} />
            </button>
          </div>
        </div>

        {/* Scrollable List */}
        <div className="overflow-y-auto flex-1 p-2 space-y-2">
          {chapters.map((chap, idx) => (
            <React.Fragment key={idx}>
              {/* Group Summary Header (Every 5 chapters) */}
              {idx % 5 === 0 && (
                  <div className="mb-2 mt-4 first:mt-0">
                      <div className="bg-gray-800/80 border border-gray-700 rounded-lg p-2 flex items-center justify-between gap-2 shadow-sm group/header">
                          {chap.outline.groupSummary ? (
                              <>
                                <div className="flex items-center gap-2 flex-1 min-w-0">
                                    <Bookmark size={14} className="text-yellow-500 shrink-0" />
                                    <span className="text-xs font-bold text-yellow-100/90 truncate" title={chap.outline.groupSummary}>
                                        {chap.outline.groupSummary}
                                    </span>
                                    <CopyBtn text={chap.outline.groupSummary} />
                                </div>
                                <button
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        requestDeleteSummary(idx, chap.outline.groupSummary || "");
                                    }}
                                    className="text-gray-500 hover:text-red-400 p-1 rounded hover:bg-red-900/20 transition-colors shrink-0"
                                    title="删除卷标"
                                >
                                    <Trash2 size={12} />
                                </button>
                              </>
                          ) : (
                              <span className="text-xs text-gray-500 font-medium pl-1">第 {chap.outline.chapterNumber}-{Math.min(chap.outline.chapterNumber + 4, chapters[chapters.length-1].outline.chapterNumber)} 章</span>
                          )}

                          <button
                              onClick={(e) => {
                                  e.stopPropagation();
                                  handleGenerateGroupSummary(idx);
                              }}
                              disabled={generatingSummaryIndices.includes(idx)}
                              className="text-gray-500 hover:text-indigo-400 p-1 rounded hover:bg-gray-700/50 transition-colors shrink-0"
                              title={chap.outline.groupSummary ? "重新生成卷标" : "生成卷标"}
                          >
                              {generatingSummaryIndices.includes(idx) ? (
                                  <Loader2 size={12} className="animate-spin" />
                              ) : (
                                  <Sparkles size={12} />
                              )}
                          </button>
                      </div>
                  </div>
              )}

              <div
                id={`chapter-item-${idx}`} 
                role="button"
                tabIndex={0}
                onClick={() => {
                  setActiveChapterIndex(idx);
                  if (window.innerWidth < 768) setShowSidebar(false);
                }}
                onKeyDown={(e) => {
                   if (e.key === 'Enter' || e.key === ' ') {
                      setActiveChapterIndex(idx);
                      if (window.innerWidth < 768) setShowSidebar(false);
                   }
                }}
                className={`w-full text-left p-3 rounded-lg text-sm transition-all flex items-start gap-2 cursor-pointer group/item
                  ${activeChapterIndex === idx 
                    ? 'bg-indigo-900/40 border border-indigo-500/30 text-indigo-200' 
                    : 'hover:bg-gray-800 text-gray-400 border border-transparent'}
                `}
              >
                <div className="mt-0.5 shrink-0">
                  {chap.isGenerated ? <CheckCircle size={14} className="text-green-500" /> : <FileText size={14} />}
                </div>
                <div className="min-w-0 flex-1">
                  <div className="flex items-center justify-between gap-2">
                      <div className="font-semibold truncate">第{chap.outline.chapterNumber}章: {chap.outline.title}</div>
                      <div className="flex items-center gap-1 shrink-0">
                         <CopyBtn 
                            text={`第${chap.outline.chapterNumber}章 ${chap.outline.title}`} 
                            className="shrink-0"
                         />
                         <button
                            onClick={(e) => {
                                e.stopPropagation();
                                requestDeleteChapter(idx);
                            }}
                            className="p-1.5 md:p-1 rounded-md text-gray-500 hover:text-red-400 hover:bg-red-900/20 transition-all opacity-100 md:opacity-0 md:group-hover/item:opacity-100"
                            title="删除本章"
                         >
                            <Trash2 size={14} className="md:w-3 md:h-3" />
                         </button>
                      </div>
                  </div>
                  <div className="text-xs text-gray-500 mt-1 truncate">{chap.outline.coolPoint}</div>
                </div>
              </div>
            </React.Fragment>
          ))}
        </div>

        <div className="p-3 border-t border-gray-800 bg-gray-900 shrink-0 space-y-2">
          {isBatchGenerating && (
             <div className="text-xs text-indigo-400 flex items-center gap-2 bg-indigo-900/20 p-2 rounded mb-2">
                <Loader2 size={12} className="animate-spin" />
                {batchProgress}
             </div>
          )}

          <button
            onClick={() => onBatchGenerate(5)}
            disabled={isLoadingMore || isBatchGenerating}
            className="w-full py-2.5 rounded-lg bg-indigo-600 hover:bg-indigo-500 text-white shadow-lg shadow-indigo-900/30 transition-all flex items-center justify-center gap-2 text-sm font-bold disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isBatchGenerating ? (
              <>
                <Loader2 size={16} className="animate-spin" />
                自动码字中...
              </>
            ) : (
              <>
                <Sparkles size={16} />
                一键生成后续5章
              </>
            )}
          </button>

           <button
            onClick={onLoadMoreChapters}
            disabled={isLoadingMore || isBatchGenerating}
            className="w-full py-2 rounded-lg border border-dashed border-gray-600 text-gray-400 hover:text-white hover:border-indigo-500 hover:bg-gray-800 transition-all flex items-center justify-center gap-2 text-xs font-medium"
          >
            {isLoadingMore ? (
              <>
                <Loader2 size={14} className="animate-spin" />
                推演中...
              </>
            ) : (
              <>
                <PlusCircle size={14} />
                仅生成后续5章大纲
              </>
            )}
          </button>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col h-full overflow-hidden relative bg-black/20">
        <div className="p-4 border-b border-gray-800 bg-gray-850 flex justify-between items-start md:items-center flex-col md:flex-row gap-4 shrink-0">
          <div className="w-full md:w-auto">
             <h3 className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">本章脉络 & 规则</h3>
             <p className="text-sm text-gray-300 line-clamp-2 md:line-clamp-1">
               <span className="text-indigo-400">[{activeChapter.outline.narrativePulse}]</span> {activeChapter.outline.rules.join(" | ")}
             </p>
          </div>

          <div className="flex items-center gap-3 self-end md:self-auto shrink-0">
            {canUndo && !isGenerating && !isBatchGenerating && (
                <button
                    onClick={handleUndoRewrite}
                    className="px-3 py-2 rounded-lg bg-gray-800 hover:bg-gray-700 text-orange-400 border border-orange-500/30 transition-all flex items-center gap-2 text-sm md:text-base font-medium"
                    title="恢复重写前的内容"
                >
                    <RotateCcw size={16} />
                    <span className="hidden sm:inline">撤销重写</span>
                </button>
            )}

            {activeChapter.isGenerated && !isGenerating && !isBatchGenerating && (
                <button
                    onClick={() => setShowRewriteModal(true)}
                    className="px-3 py-2 rounded-lg bg-gray-800 hover:bg-gray-700 text-indigo-300 border border-indigo-500/30 transition-all flex items-center gap-2 text-sm md:text-base font-medium"
                    title="重写本章"
                >
                    <RefreshCw size={16} />
                    <span className="hidden sm:inline">重写</span>
                </button>
            )}

            {(activeChapter.content || activeChapter.isGenerated) && !isGenerating && !isBatchGenerating && (
              <button
                onClick={() => setIsEditing(!isEditing)}
                className={`px-4 py-2 rounded-lg flex items-center gap-2 font-bold transition-all border text-sm md:text-base
                  ${isEditing 
                    ? 'bg-green-600/20 text-green-400 border-green-500/50 hover:bg-green-600/30' 
                    : 'bg-gray-800 hover:bg-gray-700 text-gray-300 border-gray-700'
                  }`}
              >
                {isEditing ? (
                  <>
                    <Save size={16} />
                    <span className="hidden sm:inline">完成</span>
                  </>
                ) : (
                  <>
                    <Edit size={16} />
                    <span className="hidden sm:inline">修改</span>
                  </>
                )}
              </button>
            )}

            {(!activeChapter.isGenerated && !activeChapter.content) && (
              <button
                onClick={handleGenerate}
                disabled={isGenerating || isBatchGenerating}
                className="px-5 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg flex items-center gap-2 font-bold shadow-lg shadow-indigo-500/20 whitespace-nowrap text-sm md:text-base disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {isGenerating ? '创作中...' : (isBatchGenerating ? '批量任务进行中...' : '生成正文')}
                {!isGenerating && !isBatchGenerating && <Play size={16} fill="currentColor" />}
              </button>
            )}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4 md:p-8">
          <div className="max-w-3xl mx-auto h-full pb-24">
             {isEditing ? (
               <div className="h-full min-h-[600px] bg-gray-900 p-4 md:p-8 rounded-xl border border-indigo-500/30 shadow-2xl flex flex-col animate-in fade-in duration-300">
                 <div className="mb-4 pb-4 border-b border-gray-800 flex flex-col gap-2">
                    <div className="flex justify-between items-center text-xs text-gray-500 uppercase tracking-wider font-bold">
                        <span>正在编辑: 第{activeChapter.outline.chapterNumber}章</span>
                        <span className={activeChapter.content.length > 2000 ? 'text-green-500' : 'text-gray-500'}>
                            {activeChapter.content.length} 字
                        </span>
                    </div>
                    <input 
                        type="text" 
                        value={activeChapter.outline.title}
                        onChange={(e) => onUpdateTitle(activeChapterIndex, e.target.value)}
                        className="bg-transparent text-xl md:text-2xl font-serif font-bold text-white border-b border-gray-700 focus:border-indigo-500 outline-none py-1 transition-colors placeholder-gray-700"
                        placeholder="输入章节标题..."
                    />
                 </div>
                 <textarea 
                   className="w-full flex-1 bg-transparent border-none outline-none text-gray-200 font-serif text-base md:text-lg leading-loose resize-none focus:ring-0"
                   value={activeChapter.content}
                   onChange={(e) => onUpdateChapter(activeChapterIndex, e.target.value, true)} 
                   placeholder="在此输入章节正文..."
                   spellCheck={false}
                   autoFocus
                 />
               </div>
             ) : (
               <>
                 <ChapterReader 
                   title={`第${activeChapter.outline.chapterNumber}章 ${activeChapter.outline.title}`}
                   content={activeChapter.content}
                   isStreaming={isGenerating && activeChapterIndex === chapters.findIndex(c => c === activeChapter)}
                 />

                 <div className="mt-12 mb-8 text-center space-y-6">
                    {activeChapter.isGenerated && activeChapterIndex < chapters.length - 1 && (
                       <button
                         onClick={() => setActiveChapterIndex(prev => prev + 1)}
                         className="text-gray-400 hover:text-white underline decoration-indigo-500 underline-offset-4 py-4 px-8 text-lg transition-all flex items-center gap-2 mx-auto"
                       >
                         继续下一章
                         <ArrowDown size={16} />
                       </button>
                    )}

                    {activeChapter.isGenerated && activeChapterIndex === chapters.length - 1 && (
                        <div className="flex flex-col items-center justify-center gap-4 py-8 border-t border-gray-800/50">
                            <p className="text-gray-500 text-sm">当前剧情已至最新，是否继续推演后续发展？</p>
                            <button
                                onClick={() => onBatchGenerate(5)}
                                disabled={isLoadingMore || isBatchGenerating}
                                className="px-8 py-4 bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 text-white rounded-xl font-bold shadow-xl shadow-indigo-900/40 flex items-center gap-3 transition-all transform hover:scale-105 disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none"
                            >
                                {isBatchGenerating ? (
                                    <>
                                        <Loader2 size={24} className="animate-spin" />
                                        <span className="text-lg">AI正在疯狂码字中...</span>
                                    </>
                                ) : (
                                    <>
                                        <Sparkles size={24} />
                                        <span className="text-lg">一键生成后续5章 (大纲+正文)</span>
                                    </>
                                )}
                            </button>
                            {!isBatchGenerating && (
                                <p className="text-xs text-gray-600">
                                    * 将根据当前剧情自动规划大纲并撰写正文
                                </p>
                            )}
                        </div>
                    )}
                 </div>
               </>
             )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default StepWriting;

// 角色定义
export interface Character {
  name: string;
  role: 'Protagonist' | 'Antagonist' | 'Support' | 'Mob';
  personality: string; // 性格特征
  background: string; // 背景故事
  goal: string; // 目标
  cheat?: string; // 金手指/特殊能力 (仅主角有)
}

// 世界观设定
export interface WorldSetting {
  theme: string; // 如：赛博修仙、末世重生
  powerSystem: string; // 力量体系
  rules: string; // 世界核心规则
}

// 故事大纲节点
export interface PlotPoint {
  phase: string; // 阶段：开篇、发展、高潮、结尾
  summary: string; // 剧情概括
}

// 章节细纲
export interface ChapterOutline {
  chapterNumber: number;
  title: string;
  summary: string; // 故事梗概
  narrativePulse: string; // 叙事脉络
  coolPoint: string; // 本章爽点 (Cool Point)
  rules: string[]; // 必须遵守的规则/限制
  groupSummary?: string; // 新增：每5章的卷/段落小标题
}

// 章节正文
export interface ChapterContent {
  outline: ChapterOutline;
  content: string; // 生成的正文内容
  isGenerated: boolean;
}

// 应用当前的生成步骤
export enum GenerationStep {
  SETUP = 'SETUP',
  CHARACTERS = 'CHARACTERS',
  PLOT = 'PLOT',
  CHAPTER_PLAN = 'CHAPTER_PLAN',
  WRITING = 'WRITING'
}

// 导出的项目数据结构
export interface ProjectData {
  version: number;
  step: GenerationStep;
  bookTitle?: string; // 新增：书名
  prompt: string; // 保存初始脑洞
  world: WorldSetting | null;
  characters: Character[];
  plot: PlotPoint[];
  chapters: ChapterContent[];
  batchSize?: number; // 新增：批量生成数量配置
}

import React, { useState } from 'react';
import { Settings, X, Save, AlertTriangle } from 'lucide-react';

interface Props {
  batchSize: number;
  onSave: (size: number) => void;
  onClose: () => void;
}

const SettingsModal: React.FC<Props> = ({ batchSize, onSave, onClose }) => {
  const [size, setSize] = useState(batchSize);

  const handleSave = () => {
    onSave(size);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4 animate-in fade-in duration-200">
      <div className="bg-gray-900 border border-gray-700 rounded-xl w-full max-w-sm shadow-2xl flex flex-col">
        {/* Header */}
        <div className="flex justify-between items-center p-4 border-b border-gray-800">
          <h3 className="text-lg font-bold text-white flex items-center gap-2">
            <Settings className="text-indigo-400" size={20} />
            生成设置
          </h3>
          <button onClick={onClose} className="text-gray-500 hover:text-white transition-colors">
            <X size={20} />
          </button>
        </div>

        {/* Body */}
        <div className="p-6 space-y-6">
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <label className="text-sm font-medium text-gray-300">
                批量生成章节数量
              </label>
              <span className="text-indigo-400 font-bold text-lg">{size} 章</span>
            </div>

            <input 
              type="range" 
              min="1" 
              max="10" 
              step="1"
              value={size}
              onChange={(e) => setSize(parseInt(e.target.value))}
              className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-indigo-500 hover:accent-indigo-400"
            />

            <div className="flex justify-between text-xs text-gray-500 px-1">
              <span>1章</span>
              <span>5章</span>
              <span>10章</span>
            </div>
          </div>

          {size > 5 && (
            <div className="bg-yellow-900/20 border border-yellow-700/50 rounded-lg p-3 flex gap-2 items-start">
              <AlertTriangle size={16} className="text-yellow-500 shrink-0 mt-0.5" />
              <p className="text-xs text-yellow-200/80 leading-relaxed">
                设置过高的生成数量可能会导致 API 请求超时或生成中断。建议设置为 3-5 章。
              </p>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="p-4 border-t border-gray-800 flex justify-end">
          <button 
            onClick={handleSave}
            className="bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2 rounded-lg font-medium transition-colors flex items-center gap-2 shadow-lg shadow-indigo-900/50"
          >
            <Save size={18} />
            保存设置
          </button>
        </div>
      </div>
    </div>
  );
};

export default SettingsModal;

import React, { useState, useEffect, useRef } from 'react';
import { GenerationStep, Character, WorldSetting, PlotPoint, ChapterContent, ProjectData } from './types';
import { generateCharactersAndWorld, generateMainPlot, generateChapterOutlines, generateNextChapterOutlines, generateFullChapterContent } from './services/geminiService';
import StepSetup from './components/StepSetup';
import StepCharacters from './components/StepCharacters';
import StepPlot from './components/StepPlot';
import StepWriting from './components/StepWriting';
import TitleGeneratorModal from './components/TitleGeneratorModal';
import SettingsModal from './components/SettingsModal';
import { Download, Upload, Save, FileJson, FilePlus, PenLine, Settings } from 'lucide-react';

const STORAGE_KEY = 'soulwriter_autosave_v1';

const App: React.FC = () => {
  // 核心状态
  const [step, setStep] = useState<GenerationStep>(GenerationStep.SETUP);
  const [isLoading, setIsLoading] = useState(false);
  const [isLoadedFromStorage, setIsLoadedFromStorage] = useState(false);
  const [batchProgress, setBatchProgress] = useState<string | null>(null); // null表示不在批量生成中

  // Data State
  const [prompt, setPrompt] = useState("重生回到十年前，觉醒了'万物增幅'系统，这一世我要在这个赛博朋克与古武并存的世界成为最强。");
  const [bookTitle, setBookTitle] = useState("");
  const [world, setWorld] = useState<WorldSetting | null>(null);
  const [characters, setCharacters] = useState<Character[]>([]);
  const [plot, setPlot] = useState<PlotPoint[]>([]);
  const [chapters, setChapters] = useState<ChapterContent[]>([]);
  const [batchSize, setBatchSize] = useState(5); // 默认批量生成5章

  // UI State
  const [showTitleModal, setShowTitleModal] = useState(false);
  const [showSettingsModal, setShowSettingsModal] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- 自动保存与恢复逻辑 ---

  // 1. 初始化时加载数据
  useEffect(() => {
    const savedData = localStorage.getItem(STORAGE_KEY);
    if (savedData) {
      try {
        const parsed: ProjectData = JSON.parse(savedData);
        // 简单的版本检查
        if (parsed.version === 1) {
          console.log("检测到自动保存进度，正在恢复...");
          setStep(parsed.step);
          setPrompt(parsed.prompt || "");
          setBookTitle(parsed.bookTitle || "");
          setWorld(parsed.world);
          setCharacters(parsed.characters);
          setPlot(parsed.plot);
          setChapters(parsed.chapters);
          if (parsed.batchSize) setBatchSize(parsed.batchSize);
        }
      } catch (e) {
        console.error("读取自动保存失败:", e);
      }
    }
    setIsLoadedFromStorage(true); // 标记加载尝试已完成
  }, []);

  // 2. 数据变化时自动保存
  useEffect(() => {
    // 只有在初始化加载完成后才开始保存，防止覆盖
    if (!isLoadedFromStorage) return;

    const data: ProjectData = {
      version: 1,
      step,
      prompt,
      bookTitle,
      world,
      characters,
      plot,
      chapters,
      batchSize
    };

    // 使用 debounce 或直接保存，这里数据量不大直接保存
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    console.log("进度已自动保存");

  }, [step, prompt, bookTitle, world, characters, plot, chapters, batchSize, isLoadedFromStorage]);

  // 新建项目 (重置)
  const handleNewProject = () => {
    if (window.confirm("确定要新建项目吗？这将清除当前的自动保存进度，且无法恢复。")) {
      // 清除本地存储
      localStorage.removeItem(STORAGE_KEY);

      // 强制刷新页面以重置所有状态为默认值
      // 这样可以确保 autosave 逻辑不会意外保存旧状态，并且让用户回到带有默认提示文案的初始界面
      window.location.reload();
    }
  };

  // --- 业务逻辑 ---

  // Step 1 -> 2: Setup to Characters
  const handleSetupGenerate = async () => {
    setIsLoading(true);
    try {
      const data = await generateCharactersAndWorld(prompt);
      setWorld(data.world);
      setCharacters(data.characters);
      setStep(GenerationStep.CHARACTERS);
    } catch (e) {
      alert("生成失败，请检查API Key或重试");
    } finally {
      setIsLoading(false);
    }
  };

  // Step 2 -> 3: Characters to Plot
  const handleConfirmCharacters = async (updatedWorld: WorldSetting, updatedCharacters: Character[]) => {
    if (!updatedWorld || updatedCharacters.length === 0) return;

    setWorld(updatedWorld);
    setCharacters(updatedCharacters);

    setIsLoading(true);
    try {
      const data = await generateMainPlot(updatedWorld, updatedCharacters);
      setPlot(data);
      setStep(GenerationStep.PLOT);
    } catch (e) {
      alert("生成大纲失败");
    } finally {
      setIsLoading(false);
    }
  };

  // Step 3 -> 4: Plot to Chapter Outlines -> Writing
  const handleConfirmPlot = async () => {
    if (!world || characters.length === 0 || plot.length === 0) return;
    setIsLoading(true);
    try {
      // 初始生成数量也使用 batchSize
      const outlineData = await generateChapterOutlines(world, characters, plot, batchSize);
      const initialChapters: ChapterContent[] = outlineData.map(o => ({
        outline: o,
        content: '',
        isGenerated: false
      }));
      setChapters(initialChapters);
      setStep(GenerationStep.WRITING);
    } catch (e) {
      alert("生成细纲失败");
    } finally {
      setIsLoading(false);
    }
  };

  // 仅续写后续章节大纲
  const handleAddChaptersOutline = async (count: number = 5) => {
    if (!world || characters.length === 0 || plot.length === 0 || chapters.length === 0) return;

    setIsLoading(true);
    try {
      const lastChapter = chapters[chapters.length - 1];
      const newOutlines = await generateNextChapterOutlines(world, characters, plot, lastChapter.outline, count);

      const newChapters: ChapterContent[] = newOutlines.map(o => ({
        outline: o,
        content: '',
        isGenerated: false
      }));

      setChapters(prev => [...prev, ...newChapters]);
    } catch (e) {
      console.error(e);
      alert("续写章节大纲失败");
    } finally {
      setIsLoading(false);
    }
  };

  /**
   * 批量生成后续章节（大纲 + 正文）
   * 逻辑：
   * 1. 调用大纲生成接口，规划后续 N 章。
   * 2. 将空章节加入 State。
   * 3. 循环遍历新章节，串行调用正文生成接口（保证上下文连贯）。
   */
  const handleBatchGenerateChapters = async (count: number = 5) => {
    if (!world || characters.length === 0 || plot.length === 0 || chapters.length === 0) return;
    if (batchProgress) return; // 防止重复点击

    try {
      // 1. 生成大纲
      setBatchProgress("正在规划后续剧情大纲...");
      const lastChapter = chapters[chapters.length - 1];
      const newOutlines = await generateNextChapterOutlines(world, characters, plot, lastChapter.outline, count);

      // 2. 创建占位章节并添加到状态
      const newChaptersPlaceholder: ChapterContent[] = newOutlines.map(o => ({
        outline: o,
        content: '',
        isGenerated: false
      }));

      // 先保存当前的章节数量，作为后续更新的起始索引
      const startIndex = chapters.length;

      // 更新 UI 显示出新的空章节
      setChapters(prev => [...prev, ...newChaptersPlaceholder]);

      // 3. 串行生成每一章的正文
      // 注意：这里我们不能直接用 chapters 状态，因为它是旧的闭包。
      // 我们需要构建一个临时的上下文链。
      let previousContent = lastChapter.content || lastChapter.outline.summary; 

      for (let i = 0; i < newChaptersPlaceholder.length; i++) {
        const currentChapterIndex = startIndex + i;
        const currentChapter = newChaptersPlaceholder[i];

        setBatchProgress(`正在撰写第 ${currentChapter.outline.chapterNumber} 章... (${i + 1}/${count})`);

        // 调用非流式生成接口
        const generatedContent = await generateFullChapterContent(
          currentChapter.outline,
          world,
          characters,
          previousContent
        );

        // 更新单个章节状态
        handleUpdateChapter(currentChapterIndex, generatedContent, true);

        // 更新上下文，为下一章做准备
        previousContent = generatedContent;
      }

      setBatchProgress(null);

    } catch (e) {
      console.error(e);
      alert("批量生成过程中断，请重试");
      setBatchProgress(null);
    }
  };


  // 更新章节内容
  const handleUpdateChapter = (index: number, content: string, isGenerated: boolean) => {
    setChapters(prev => {
      const newChapters = [...prev];
      if (newChapters[index]) {
        newChapters[index] = {
          ...newChapters[index],
          content,
          isGenerated
        };
      }
      return newChapters;
    });
  };

  // 更新章节标题
  const handleUpdateChapterTitle = (index: number, title: string) => {
    setChapters(prev => {
      const newChapters = [...prev];
      if (newChapters[index]) {
        newChapters[index] = {
          ...newChapters[index],
          outline: {
            ...newChapters[index].outline,
            title
          }
        };
      }
      return newChapters;
    });
  };

  // 更新分组小结
  const handleUpdateGroupSummary = (index: number, summary: string) => {
      setChapters(prev => {
          const newChapters = [...prev];
          if (newChapters[index]) {
              newChapters[index] = {
                  ...newChapters[index],
                  outline: {
                      ...newChapters[index].outline,
                      groupSummary: summary
                  }
              }
          }
          return newChapters;
      })
  }

  // 删除分组小结
  const handleDeleteGroupSummary = (index: number) => {
      handleUpdateGroupSummary(index, "");
  };

  // 删除章节
  const handleDeleteChapter = (index: number) => {
      if (chapters.length <= 1) {
          alert("无法删除：至少需要保留一个章节。");
          return;
      }

      setChapters(prev => {
          // 1. 过滤掉删除的章节
          const newChapters = prev.filter((_, i) => i !== index);

          // 2. 重新编排章节号，保证连续性
          return newChapters.map((chap, i) => ({
              ...chap,
              outline: {
                  ...chap.outline,
                  chapterNumber: i + 1
              }
          }));
      });
  };

  // 导出项目
  const handleExport = () => {
    const data: ProjectData = {
      version: 1,
      step,
      prompt,
      bookTitle,
      world,
      characters,
      plot,
      chapters,
      batchSize
    };

    const jsonString = JSON.stringify(data, null, 2);
    const blob = new Blob([jsonString], { type: "application/json" });
    const url = URL.createObjectURL(blob);

    const link = document.createElement('a');
    link.href = url;
    link.download = `${bookTitle || 'soulwriter-project'}-${new Date().toISOString().slice(0, 10)}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  // 导入项目触发
  const triggerImport = () => {
    fileInputRef.current?.click();
  };

  // 处理文件读取
  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (json.version && json.step) {
          const data = json as ProjectData;
          setStep(data.step);
          setPrompt(data.prompt || "");
          setBookTitle(data.bookTitle || "");
          setWorld(data.world);
          setCharacters(data.characters);
          setPlot(data.plot);
          setChapters(data.chapters);
          if (data.batchSize) setBatchSize(data.batchSize);
          alert("项目导入成功！");
        } else {
          alert("无效的项目文件格式");
        }
      } catch (error) {
        console.error("Import error", error);
        alert("文件解析失败");
      }
    };
    reader.readAsText(file);
    e.target.value = ''; 
  };

  return (
    <div className="min-h-screen bg-[#0d1117] text-gray-100 font-sans selection:bg-indigo-500/30">
      <header className="border-b border-gray-800 bg-[#0d1117]/80 backdrop-blur sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-4">
             {/* Logo */}
             <div className="font-bold text-xl tracking-tight bg-gradient-to-r from-indigo-400 to-cyan-400 bg-clip-text text-transparent flex items-center gap-2 cursor-pointer shrink-0" onClick={() => setStep(GenerationStep.SETUP)}>
                <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center text-white">
                  <FileJson size={20} />
                </div>
                <span className="hidden sm:inline">SoulWriter AI</span>
              </div>

              {/* Divider */}
              <div className="h-6 w-px bg-gray-700 mx-2 hidden sm:block"></div>

              {/* Book Title */}
              <button 
                onClick={() => setShowTitleModal(true)}
                className="flex items-center gap-2 px-3 py-1.5 rounded-lg hover:bg-gray-800 transition-colors group max-w-[150px] sm:max-w-xs"
                title="点击修改书名"
              >
                <div className="text-sm font-bold text-gray-200 truncate">
                   {bookTitle || "未命名作品"}
                </div>
                <PenLine size={14} className="text-gray-500 group-hover:text-indigo-400 shrink-0" />
              </button>
          </div>


          <div className="flex items-center gap-4">
            {/* Steps Indicator (Desktop) */}
            <div className="hidden lg:flex gap-2 text-xs font-mono text-gray-500 mr-4">
              <span className={step === GenerationStep.SETUP ? 'text-indigo-400' : ''}>01.设定</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.CHARACTERS ? 'text-indigo-400' : ''}>02.人物</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.PLOT ? 'text-indigo-400' : ''}>03.大纲</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.WRITING ? 'text-indigo-400' : ''}>04.正文</span>
            </div>

            {/* Actions */}
            <div className="flex items-center gap-2 border-l border-gray-700 pl-4">
              <input 
                type="file" 
                ref={fileInputRef} 
                className="hidden" 
                accept=".json" 
                onChange={handleImport}
              />

              {/* Settings Button - 可见性：所有端可见 */}
              <button 
                onClick={() => setShowSettingsModal(true)}
                className="p-2 text-gray-400 hover:text-white hover:bg-gray-800 rounded-lg transition-colors flex items-center gap-2 text-sm"
                title="设置"
              >
                <Settings size={20} />
              </button>

              {/* 新建项目按钮 */}
              <button 
                onClick={handleNewProject}
                className="p-2 text-gray-400 hover:text-white hover:bg-gray-800 rounded-lg transition-colors flex items-center gap-2 text-sm"
                title="新建项目 (清空进度)"
              >
                <FilePlus size={18} />
                <span className="hidden sm:inline">新建项目</span>
              </button>

              <button 
                onClick={triggerImport}
                className="p-2 text-gray-400 hover:text-white hover:bg-gray-800 rounded-lg transition-colors flex items-center gap-2 text-sm"
                title="导入项目"
              >
                <Upload size={18} />
                <span className="hidden sm:inline">导入</span>
              </button>

              <button 
                onClick={handleExport}
                className="px-3 py-1.5 bg-gray-800 hover:bg-gray-700 text-indigo-300 border border-indigo-500/30 rounded-lg transition-colors flex items-center gap-2 text-sm font-medium"
                title="导出项目"
              >
                <Save size={18} />
                <span className="hidden sm:inline">保存</span>
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8">
        {step === GenerationStep.SETUP && (
          <StepSetup 
            prompt={prompt}
            setPrompt={setPrompt}
            onGenerate={handleSetupGenerate} 
            isLoading={isLoading} 
          />
        )}

        {step === GenerationStep.CHARACTERS && world && (
          <StepCharacters 
            world={world} 
            characters={characters} 
            onConfirm={handleConfirmCharacters}
            isLoading={isLoading}
          />
        )}

        {step === GenerationStep.PLOT && (
          <StepPlot 
            plot={plot}
            onConfirm={handleConfirmPlot}
            isLoading={isLoading}
          />
        )}

        {step === GenerationStep.WRITING && world && (
          <StepWriting 
            chapters={chapters}
            world={world}
            characters={characters}
            onUpdateChapter={handleUpdateChapter}
            onUpdateTitle={handleUpdateChapterTitle}
            onUpdateGroupSummary={handleUpdateGroupSummary}
            onDeleteChapter={handleDeleteChapter}
            onDeleteGroupSummary={handleDeleteGroupSummary}
            onLoadMoreChapters={handleAddChaptersOutline}
            onBatchGenerate={handleBatchGenerateChapters}
            isLoadingMore={isLoading}
            batchProgress={batchProgress}
            batchSize={batchSize}
          />
        )}
      </main>

      {/* Modals */}
      {showTitleModal && (
        <TitleGeneratorModal 
           currentTitle={bookTitle}
           onSelect={(t) => setBookTitle(t)}
           onClose={() => setShowTitleModal(false)}
           contextData={{ prompt, world, characters }}
        />
      )}

      {showSettingsModal && (
        <SettingsModal 
          batchSize={batchSize}
          onSave={setBatchSize}
          onClose={() => setShowSettingsModal(false)}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ChapterContent, Character, WorldSetting } from '../types';
import { streamChapterContent, generateBatchSummary } from '../services/geminiService';
import ChapterReader from './ChapterReader';
import { FileText, Play, CheckCircle, Menu, X, Edit, Save, PlusCircle, Loader2, Sparkles, ArrowDown, RefreshCw, RotateCcw, CornerDownLeft, Bookmark, Copy, Check, Trash2, AlertTriangle } from 'lucide-react';

interface Props {
  chapters: ChapterContent[];
  world: WorldSetting;
  characters: Character[];
  onUpdateChapter: (index: number, content: string, isGenerated: boolean) => void;
  onUpdateTitle: (index: number, title: string) => void;
  onUpdateGroupSummary: (index: number, summary: string) => void; 
  onDeleteChapter: (index: number) => void; // 新增：删除章节
  onDeleteGroupSummary: (index: number) => void; // 新增：删除卷标
  onLoadMoreChapters: (count: number) => void;
  onBatchGenerate: (count: number) => void;
  isLoadingMore: boolean;
  batchProgress: string | null;
  batchSize: number; // 新增：接收配置的数量
}

const CopyBtn = ({ text, className = "" }: { text: string, className?: string }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = (e: React.MouseEvent) => {
    e.stopPropagation();
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <button 
      onClick={handleCopy} 
      className={`p-1 rounded-md hover:bg-gray-700/50 transition-colors inline-flex items-center justify-center shrink-0 ${copied ? 'text-green-400' : 'text-gray-500 hover:text-indigo-400'} ${className}`}
      title="复制内容"
    >
      {copied ? <Check size={12} /> : <Copy size={12} />}
    </button>
  );
};

const StepWriting: React.FC<Props> = ({ 
  chapters, 
  world, 
  characters, 
  onUpdateChapter, 
  onUpdateTitle, 
  onUpdateGroupSummary,
  onDeleteChapter,
  onDeleteGroupSummary,
  onLoadMoreChapters, 
  onBatchGenerate,
  isLoadingMore,
  batchProgress,
  batchSize
}) => {
  const [activeChapterIndex, setActiveChapterIndex] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [showSidebar, setShowSidebar] = useState(false); 
  const [isEditing, setIsEditing] = useState(false);

  // Loading state specifically for generating group summaries
  // Key is the starting index of the group
  const [generatingSummaryIndices, setGeneratingSummaryIndices] = useState<number[]>([]);

  // 重写功能相关状态
  const [showRewriteModal, setShowRewriteModal] = useState(false);
  const [rewriteInstructions, setRewriteInstructions] = useState("");

  // 删除确认弹窗状态
  const [deleteConfirm, setDeleteConfirm] = useState<{
    isOpen: boolean;
    type: 'chapter' | 'summary';
    index: number;
    title?: string;
  }>({ isOpen: false, type: 'chapter', index: -1 });

  // 撤销历史记录
  const [undoHistory, setUndoHistory] = useState<Record<number, string>>({});

  // 章节跳转输入状态
  const [jumpInput, setJumpInput] = useState("");

  // 确保 activeChapterIndex 不越界
  useEffect(() => {
      if (chapters.length > 0 && activeChapterIndex >= chapters.length) {
          setActiveChapterIndex(Math.max(0, chapters.length - 1));
      }
  }, [chapters.length, activeChapterIndex]);

  const activeChapter = chapters[activeChapterIndex] || chapters[0]; // 防御性处理

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setIsEditing(false);
  }, [activeChapterIndex]);

  const handleGenerate = async () => {
    if (isGenerating || activeChapter.isGenerated) return;
    startGeneration();
  };

  const handleRewrite = async () => {
    if (isGenerating) return;

    if (activeChapter.content) {
      setUndoHistory(prev => ({
        ...prev,
        [activeChapterIndex]: activeChapter.content
      }));
    }

    setShowRewriteModal(false);
    startGeneration(rewriteInstructions);
    setRewriteInstructions("");
  };

  const handleUndoRewrite = () => {
    const prevContent = undoHistory[activeChapterIndex];
    if (!prevContent) return;

    if (window.confirm("确定要撤销重写，恢复到上一个版本吗？当前版本将丢失。")) {
      onUpdateChapter(activeChapterIndex, prevContent, true);
      setUndoHistory(prev => {
        const newState = { ...prev };
        delete newState[activeChapterIndex];
        return newState;
      });
    }
  };

  const handleJumpToChapter = () => {
    const target = parseInt(jumpInput);
    if (isNaN(target)) return;

    if (target < 1 || target > chapters.length) {
      alert(`请输入有效章节号 (1-${chapters.length})`);
      return;
    }

    setActiveChapterIndex(target - 1);
    setJumpInput("");
    if (window.innerWidth < 768) setShowSidebar(false);
  };

  const handleJumpKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleJumpToChapter();
    }
  };

  // 生成分组标题的逻辑
  const handleGenerateGroupSummary = async (startIndex: number) => {
    if (generatingSummaryIndices.includes(startIndex)) return;

    // 获取这5章
    const groupChapters = chapters.slice(startIndex, startIndex + 5).map(c => c.outline);
    if (groupChapters.length === 0) return;

    setGeneratingSummaryIndices(prev => [...prev, startIndex]);

    try {
        const summary = await generateBatchSummary(groupChapters);
        onUpdateGroupSummary(startIndex, summary);
    } catch (e) {
        console.error("生成卷标出错详情:", e);
        alert("生成卷标失败，请查看控制台日志以获取更多信息");
    } finally {
        setGeneratingSummaryIndices(prev => prev.filter(i => i !== startIndex));
    }
  };

  const startGeneration = async (instructions?: string) => {
    setIsGenerating(true);
    setIsEditing(false);

    if (window.innerWidth < 768) {
        setShowSidebar(false);
    }

    let prevContext = "";
    if (activeChapterIndex > 0) {
      const prevChap = chapters[activeChapterIndex - 1];
      prevContext = prevChap.content || prevChap.outline.summary;
    }

    try {
      if (instructions) {
         onUpdateChapter(activeChapterIndex, "", false); 
      }

      let fullText = "";
      await streamChapterContent(
        activeChapter.outline,
        world,
        characters,
        prevContext,
        (textChunk) => {
          fullText += textChunk;
          onUpdateChapter(activeChapterIndex, fullText, false);
        },
        instructions
      );

      onUpdateChapter(activeChapterIndex, fullText, true);

    } catch (e) {
      alert("生成中断，请重试");
    } finally {
      setIsGenerating(false);
    }
  };

  // --- 删除确认逻辑 ---
  const requestDeleteChapter = (index: number) => {
      setDeleteConfirm({
          isOpen: true,
          type: 'chapter',
          index: index,
          title: `第 ${chapters[index].outline.chapterNumber} 章`
      });
  };

  const requestDeleteSummary = (index: number, summary: string) => {
      setDeleteConfirm({
          isOpen: true,
          type: 'summary',
          index: index,
          title: summary || "当前卷标"
      });
  };

  const executeDelete = () => {
      if (deleteConfirm.type === 'chapter') {
          onDeleteChapter(deleteConfirm.index);
          // 如果删除的是当前选中的章节，且不是第一章，需要更新 activeIndex
          if (activeChapterIndex === deleteConfirm.index && activeChapterIndex > 0) {
              setActiveChapterIndex(Math.max(0, activeChapterIndex - 1));
          }
      } else {
          onDeleteGroupSummary(deleteConfirm.index);
      }
      setDeleteConfirm({ ...deleteConfirm, isOpen: false });
  };

  if (!activeChapter) return <div>数据加载中...</div>;

  const isBatchGenerating = batchProgress !== null;
  const canUndo = !!undoHistory[activeChapterIndex];

  return (
    <div className="flex h-[calc(100vh-100px)] overflow-hidden rounded-xl border border-gray-800 bg-gray-950 relative">

      {/* 统一的删除确认模态框 */}
      {deleteConfirm.isOpen && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[70] flex items-center justify-center p-4 animate-in fade-in duration-200">
           <div className="bg-gray-900 border border-red-500/30 rounded-xl p-6 w-full max-w-sm shadow-2xl flex flex-col items-center text-center">
              <div className="w-12 h-12 bg-red-900/20 rounded-full flex items-center justify-center mb-4 text-red-500">
                  <AlertTriangle size={24} />
              </div>
              <h3 className="text-xl font-bold text-white mb-2">
                  确定要删除吗？
              </h3>
              <p className="text-gray-400 text-sm mb-6 leading-relaxed">
                  您即将删除 <span className="text-white font-bold">{deleteConfirm.title}</span>。
                  {deleteConfirm.type === 'chapter' && (
                      <span className="block mt-1 text-red-400 text-xs">注意：删除章节后，后续章节序号将自动前移，且无法撤销。</span>
                  )}
              </p>

              <div className="flex gap-3 w-full">
                  <button 
                    onClick={() => setDeleteConfirm({ ...deleteConfirm, isOpen: false })} 
                    className="flex-1 px-4 py-3 rounded-lg bg-gray-800 hover:bg-gray-700 text-gray-300 font-medium transition-colors"
                  >
                    取消
                  </button>
                  <button 
                    onClick={executeDelete} 
                    className="flex-1 px-4 py-3 rounded-lg bg-red-600 hover:bg-red-500 text-white font-bold shadow-lg shadow-red-900/30 transition-colors"
                  >
                    确认删除
                  </button>
              </div>
           </div>
        </div>
      )}

      {/* 重写设置模态框 */}
      {showRewriteModal && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[60] flex items-center justify-center p-4">
           <div className="bg-gray-900 border border-gray-700 rounded-xl p-6 w-full max-w-lg shadow-2xl animate-in fade-in zoom-in duration-200 flex flex-col max-h-[90vh]">
              <h3 className="text-xl font-bold text-white mb-2 flex items-center gap-2 shrink-0">
                  <RefreshCw className="text-indigo-400" size={20} />
                  重写本章
              </h3>

              <div className="overflow-y-auto mb-4 custom-scrollbar pr-2">
                 <div className="bg-gray-800/50 rounded-lg p-3 mb-4 border border-gray-700">
                    <span className="text-xs font-bold text-indigo-400 uppercase tracking-wider block mb-1">当前大纲摘要</span>
                    <p className="text-sm text-gray-300 leading-relaxed">
                      {activeChapter.outline.summary}
                    </p>
                 </div>

                 <p className="text-sm text-gray-400 mb-2">
                     AI 将根据上述大纲重新撰写正文。您可以输入具体的修改意见，AI会重点关注。
                 </p>
              </div>

              <textarea 
                  className="w-full h-32 bg-gray-950 border border-gray-700 rounded-lg p-3 text-gray-200 focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none resize-none placeholder-gray-600 text-sm shrink-0" 
                  placeholder="例如：这一章的打斗细节太少了，多描写一下招式；或者，女主的反应再害羞一点..."
                  value={rewriteInstructions}
                  onChange={(e) => setRewriteInstructions(e.target.value)}
                  autoFocus
              />
              <div className="flex justify-end gap-3 mt-6 shrink-0">
                  <button 
                    onClick={() => setShowRewriteModal(false)} 
                    className="px-4 py-2 rounded-lg text-gray-400 hover:text-white hover:bg-gray-800 transition-colors text-sm"
                  >
                    取消
                  </button>
                  <button 
                    onClick={handleRewrite} 
                    className="px-4 py-2 rounded-lg bg-indigo-600 hover:bg-indigo-500 text-white font-bold shadow-lg shadow-indigo-500/20 text-sm flex items-center gap-2"
                  >
                    <RefreshCw size={14} />
                    开始重写
                  </button>
              </div>
           </div>
        </div>
      )}

      {showSidebar && (
        <div 
          className="fixed inset-0 bg-black/60 backdrop-blur-sm z-30 md:hidden transition-opacity"
          onClick={() => setShowSidebar(false)}
        />
      )}

      <button 
        className="md:hidden fixed bottom-6 right-6 z-50 bg-indigo-600 hover:bg-indigo-500 text-white p-4 rounded-full shadow-xl shadow-indigo-900/50 transition-all active:scale-95 flex items-center justify-center"
        onClick={() => setShowSidebar(!showSidebar)}
        title={showSidebar ? "关闭目录" : "打开目录"}
      >
        {showSidebar ? <X size={24} /> : <Menu size={24} />}
      </button>

      {/* Sidebar - Chapter List */}
      <div className={`
        fixed md:relative z-40 w-72 max-w-[80vw] bg-gray-900 border-r border-gray-800 h-full flex flex-col transition-transform duration-300 ease-in-out shadow-2xl md:shadow-none
        ${showSidebar ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
      `}>
        <div className="p-4 border-b border-gray-800 bg-gray-900 font-bold text-gray-200 flex justify-between items-center shrink-0">
          <span>目录 ({chapters.length}章)</span>
          <button 
            onClick={() => setShowSidebar(false)}
            className="md:hidden text-gray-500 hover:text-white"
          >
            <X size={20} />
          </button>
        </div>

        <div className="px-3 py-2 border-b border-gray-800 bg-gray-900/50 shrink-0">
          <div className="flex gap-2">
            <input 
              type="number" 
              className="w-full bg-gray-950 border border-gray-700 rounded text-sm px-2 py-1 text-gray-300 focus:border-indigo-500 outline-none placeholder-gray-600"
              placeholder="前往章节..."
              value={jumpInput}
              onChange={(e) => setJumpInput(e.target.value)}
              onKeyDown={handleJumpKeyDown}
              min={1}
              max={chapters.length}
            />
            <button 
              onClick={handleJumpToChapter}
              disabled={!jumpInput}
              className="bg-gray-800 hover:bg-gray-700 border border-gray-700 text-gray-400 hover:text-white px-2 rounded transition-colors disabled:opacity-50"
              title="跳转"
            >
              <CornerDownLeft size={16} />
            </button>
          </div>
        </div>

        {/* Scrollable List */}
        <div className="overflow-y-auto flex-1 p-2 space-y-2">
          {chapters.map((chap, idx) => (
            <React.Fragment key={idx}>
              {/* Group Summary Header (Every 5 chapters) */}
              {idx % 5 === 0 && (
                  <div className="mb-2 mt-4 first:mt-0">
                      <div className="bg-gray-800/80 border border-gray-700 rounded-lg p-2 flex items-center justify-between gap-2 shadow-sm group/header">
                          {chap.outline.groupSummary ? (
                              <>
                                <div className="flex items-center gap-2 flex-1 min-w-0">
                                    <Bookmark size={14} className="text-yellow-500 shrink-0" />
                                    <span className="text-xs font-bold text-yellow-100/90 truncate" title={chap.outline.groupSummary}>
                                        {chap.outline.groupSummary}
                                    </span>
                                    <CopyBtn text={chap.outline.groupSummary} />
                                </div>
                                <button
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        requestDeleteSummary(idx, chap.outline.groupSummary || "");
                                    }}
                                    className="text-gray-500 hover:text-red-400 p-1 rounded hover:bg-red-900/20 transition-colors shrink-0"
                                    title="删除卷标"
                                >
                                    <Trash2 size={12} />
                                </button>
                              </>
                          ) : (
                              <span className="text-xs text-gray-500 font-medium pl-1">第 {chap.outline.chapterNumber}-{Math.min(chap.outline.chapterNumber + 4, chapters[chapters.length-1].outline.chapterNumber)} 章</span>
                          )}

                          <button
                              onClick={(e) => {
                                  e.stopPropagation();
                                  handleGenerateGroupSummary(idx);
                              }}
                              disabled={generatingSummaryIndices.includes(idx)}
                              className="text-gray-500 hover:text-indigo-400 p-1 rounded hover:bg-gray-700/50 transition-colors shrink-0"
                              title={chap.outline.groupSummary ? "重新生成卷标" : "生成卷标"}
                          >
                              {generatingSummaryIndices.includes(idx) ? (
                                  <Loader2 size={12} className="animate-spin" />
                              ) : (
                                  <Sparkles size={12} />
                              )}
                          </button>
                      </div>
                  </div>
              )}

              <div
                id={`chapter-item-${idx}`} 
                role="button"
                tabIndex={0}
                onClick={() => {
                  setActiveChapterIndex(idx);
                  if (window.innerWidth < 768) setShowSidebar(false);
                }}
                onKeyDown={(e) => {
                   if (e.key === 'Enter' || e.key === ' ') {
                      setActiveChapterIndex(idx);
                      if (window.innerWidth < 768) setShowSidebar(false);
                   }
                }}
                className={`w-full text-left p-3 rounded-lg text-sm transition-all flex items-start gap-2 cursor-pointer group/item
                  ${activeChapterIndex === idx 
                    ? 'bg-indigo-900/40 border border-indigo-500/30 text-indigo-200' 
                    : 'hover:bg-gray-800 text-gray-400 border border-transparent'}
                `}
              >
                <div className="mt-0.5 shrink-0">
                  {chap.isGenerated ? <CheckCircle size={14} className="text-green-500" /> : <FileText size={14} />}
                </div>
                <div className="min-w-0 flex-1">
                  <div className="flex items-center justify-between gap-2">
                      <div className="font-semibold truncate">第{chap.outline.chapterNumber}章: {chap.outline.title}</div>
                      <div className="flex items-center gap-1 shrink-0">
                         <CopyBtn 
                            text={`第${chap.outline.chapterNumber}章 ${chap.outline.title}`} 
                            className="shrink-0"
                         />
                         <button
                            onClick={(e) => {
                                e.stopPropagation();
                                requestDeleteChapter(idx);
                            }}
                            className="p-1.5 md:p-1 rounded-md text-gray-500 hover:text-red-400 hover:bg-red-900/20 transition-all opacity-100 md:opacity-0 md:group-hover/item:opacity-100"
                            title="删除本章"
                         >
                            <Trash2 size={14} className="md:w-3 md:h-3" />
                         </button>
                      </div>
                  </div>
                  <div className="text-xs text-gray-500 mt-1 truncate">{chap.outline.coolPoint}</div>
                </div>
              </div>
            </React.Fragment>
          ))}
        </div>

        <div className="p-3 border-t border-gray-800 bg-gray-900 shrink-0 space-y-2">
          {isBatchGenerating && (
             <div className="text-xs text-indigo-400 flex items-center gap-2 bg-indigo-900/20 p-2 rounded mb-2">
                <Loader2 size={12} className="animate-spin" />
                {batchProgress}
             </div>
          )}

          <button
            onClick={() => onBatchGenerate(batchSize)}
            disabled={isLoadingMore || isBatchGenerating}
            className="w-full py-2.5 rounded-lg bg-indigo-600 hover:bg-indigo-500 text-white shadow-lg shadow-indigo-900/30 transition-all flex items-center justify-center gap-2 text-sm font-bold disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isBatchGenerating ? (
              <>
                <Loader2 size={16} className="animate-spin" />
                自动码字中...
              </>
            ) : (
              <>
                <Sparkles size={16} />
                一键生成后续{batchSize}章
              </>
            )}
          </button>

           <button
            onClick={() => onLoadMoreChapters(batchSize)}
            disabled={isLoadingMore || isBatchGenerating}
            className="w-full py-2 rounded-lg border border-dashed border-gray-600 text-gray-400 hover:text-white hover:border-indigo-500 hover:bg-gray-800 transition-all flex items-center justify-center gap-2 text-xs font-medium"
          >
            {isLoadingMore ? (
              <>
                <Loader2 size={14} className="animate-spin" />
                推演中...
              </>
            ) : (
              <>
                <PlusCircle size={14} />
                仅生成后续{batchSize}章大纲
              </>
            )}
          </button>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col h-full overflow-hidden relative bg-black/20">
        <div className="p-4 border-b border-gray-800 bg-gray-850 flex justify-between items-start md:items-center flex-col md:flex-row gap-4 shrink-0">
          <div className="w-full md:w-auto">
             <h3 className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">本章脉络 & 规则</h3>
             <p className="text-sm text-gray-300 line-clamp-2 md:line-clamp-1">
               <span className="text-indigo-400">[{activeChapter.outline.narrativePulse}]</span> {activeChapter.outline.rules.join(" | ")}
             </p>
          </div>

          <div className="flex items-center gap-3 self-end md:self-auto shrink-0">
            {canUndo && !isGenerating && !isBatchGenerating && (
                <button
                    onClick={handleUndoRewrite}
                    className="px-3 py-2 rounded-lg bg-gray-800 hover:bg-gray-700 text-orange-400 border border-orange-500/30 transition-all flex items-center gap-2 text-sm md:text-base font-medium"
                    title="恢复重写前的内容"
                >
                    <RotateCcw size={16} />
                    <span className="hidden sm:inline">撤销重写</span>
                </button>
            )}

            {activeChapter.isGenerated && !isGenerating && !isBatchGenerating && (
                <button
                    onClick={() => setShowRewriteModal(true)}
                    className="px-3 py-2 rounded-lg bg-gray-800 hover:bg-gray-700 text-indigo-300 border border-indigo-500/30 transition-all flex items-center gap-2 text-sm md:text-base font-medium"
                    title="重写本章"
                >
                    <RefreshCw size={16} />
                    <span className="hidden sm:inline">重写</span>
                </button>
            )}

            {(activeChapter.content || activeChapter.isGenerated) && !isGenerating && !isBatchGenerating && (
              <button
                onClick={() => setIsEditing(!isEditing)}
                className={`px-4 py-2 rounded-lg flex items-center gap-2 font-bold transition-all border text-sm md:text-base
                  ${isEditing 
                    ? 'bg-green-600/20 text-green-400 border-green-500/50 hover:bg-green-600/30' 
                    : 'bg-gray-800 hover:bg-gray-700 text-gray-300 border-gray-700'
                  }`}
              >
                {isEditing ? (
                  <>
                    <Save size={16} />
                    <span className="hidden sm:inline">完成</span>
                  </>
                ) : (
                  <>
                    <Edit size={16} />
                    <span className="hidden sm:inline">修改</span>
                  </>
                )}
              </button>
            )}

            {(!activeChapter.isGenerated && !activeChapter.content) && (
              <button
                onClick={handleGenerate}
                disabled={isGenerating || isBatchGenerating}
                className="px-5 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg flex items-center gap-2 font-bold shadow-lg shadow-indigo-500/20 whitespace-nowrap text-sm md:text-base disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {isGenerating ? '创作中...' : (isBatchGenerating ? '批量任务进行中...' : '生成正文')}
                {!isGenerating && !isBatchGenerating && <Play size={16} fill="currentColor" />}
              </button>
            )}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4 md:p-8">
          <div className="max-w-3xl mx-auto h-full pb-24">
             {isEditing ? (
               <div className="h-full min-h-[600px] bg-gray-900 p-4 md:p-8 rounded-xl border border-indigo-500/30 shadow-2xl flex flex-col animate-in fade-in duration-300">
                 <div className="mb-4 pb-4 border-b border-gray-800 flex flex-col gap-2">
                    <div className="flex justify-between items-center text-xs text-gray-500 uppercase tracking-wider font-bold">
                        <span>正在编辑: 第{activeChapter.outline.chapterNumber}章</span>
                        <span className={activeChapter.content.length > 2000 ? 'text-green-500' : 'text-gray-500'}>
                            {activeChapter.content.length} 字
                        </span>
                    </div>
                    <input 
                        type="text" 
                        value={activeChapter.outline.title}
                        onChange={(e) => onUpdateTitle(activeChapterIndex, e.target.value)}
                        className="bg-transparent text-xl md:text-2xl font-serif font-bold text-white border-b border-gray-700 focus:border-indigo-500 outline-none py-1 transition-colors placeholder-gray-700"
                        placeholder="输入章节标题..."
                    />
                 </div>
                 <textarea 
                   className="w-full flex-1 bg-transparent border-none outline-none text-gray-200 font-serif text-base md:text-lg leading-loose resize-none focus:ring-0"
                   value={activeChapter.content}
                   onChange={(e) => onUpdateChapter(activeChapterIndex, e.target.value, true)} 
                   placeholder="在此输入章节正文..."
                   spellCheck={false}
                   autoFocus
                 />
               </div>
             ) : (
               <>
                 <ChapterReader 
                   title={`第${activeChapter.outline.chapterNumber}章 ${activeChapter.outline.title}`}
                   content={activeChapter.content}
                   isStreaming={isGenerating && activeChapterIndex === chapters.findIndex(c => c === activeChapter)}
                 />

                 <div className="mt-12 mb-8 text-center space-y-6">
                    {activeChapter.isGenerated && activeChapterIndex < chapters.length - 1 && (
                       <button
                         onClick={() => setActiveChapterIndex(prev => prev + 1)}
                         className="text-gray-400 hover:text-white underline decoration-indigo-500 underline-offset-4 py-4 px-8 text-lg transition-all flex items-center gap-2 mx-auto"
                       >
                         继续下一章
                         <ArrowDown size={16} />
                       </button>
                    )}

                    {activeChapter.isGenerated && activeChapterIndex === chapters.length - 1 && (
                        <div className="flex flex-col items-center justify-center gap-4 py-8 border-t border-gray-800/50">
                            <p className="text-gray-500 text-sm">当前剧情已至最新，是否继续推演后续发展？</p>
                            <button
                                onClick={() => onBatchGenerate(batchSize)}
                                disabled={isLoadingMore || isBatchGenerating}
                                className="px-8 py-4 bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 text-white rounded-xl font-bold shadow-xl shadow-indigo-900/40 flex items-center gap-3 transition-all transform hover:scale-105 disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none"
                            >
                                {isBatchGenerating ? (
                                    <>
                                        <Loader2 size={24} className="animate-spin" />
                                        <span className="text-lg">AI正在疯狂码字中...</span>
                                    </>
                                ) : (
                                    <>
                                        <Sparkles size={24} />
                                        <span className="text-lg">一键生成后续{batchSize}章 (大纲+正文)</span>
                                    </>
                                )}
                            </button>
                            {!isBatchGenerating && (
                                <p className="text-xs text-gray-600">
                                    * 将根据当前剧情自动规划大纲并撰写正文
                                </p>
                            )}
                        </div>
                    )}
                 </div>
               </>
             )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default StepWriting;

import React, { useState } from 'react';
import { Settings, X, Save, AlertTriangle } from 'lucide-react';

interface Props {
  batchSize: number;
  onSave: (size: number) => void;
  onClose: () => void;
}

const SettingsModal: React.FC<Props> = ({ batchSize, onSave, onClose }) => {
  // Ensure initial size doesn't exceed new max of 5
  const [size, setSize] = useState(Math.min(batchSize, 5));

  const handleSave = () => {
    onSave(size);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4 animate-in fade-in duration-200">
      <div className="bg-gray-900 border border-gray-700 rounded-xl w-full max-w-sm shadow-2xl flex flex-col">
        {/* Header */}
        <div className="flex justify-between items-center p-4 border-b border-gray-800">
          <h3 className="text-lg font-bold text-white flex items-center gap-2">
            <Settings className="text-indigo-400" size={20} />
            生成设置
          </h3>
          <button onClick={onClose} className="text-gray-500 hover:text-white transition-colors">
            <X size={20} />
          </button>
        </div>

        {/* Body */}
        <div className="p-6 space-y-6">
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <label className="text-sm font-medium text-gray-300">
                批量生成章节数量
              </label>
              <span className="text-indigo-400 font-bold text-lg">{size} 章</span>
            </div>

            <input 
              type="range" 
              min="1" 
              max="5" 
              step="1"
              value={size}
              onChange={(e) => setSize(parseInt(e.target.value))}
              className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-indigo-500 hover:accent-indigo-400"
            />

            <div className="flex justify-between text-xs text-gray-500 px-1">
              <span>1章</span>
              <span>3章</span>
              <span>5章</span>
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="p-4 border-t border-gray-800 flex justify-end">
          <button 
            onClick={handleSave}
            className="bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2 rounded-lg font-medium transition-colors flex items-center gap-2 shadow-lg shadow-indigo-900/50"
          >
            <Save size={18} />
            保存设置
          </button>
        </div>
      </div>
    </div>
  );
};

export default SettingsModal;

// 角色定义
export interface Character {
  name: string;
  role: 'Protagonist' | 'Antagonist' | 'Support' | 'Mob';
  personality: string; // 性格特征
  background: string; // 背景故事
  goal: string; // 目标
  cheat?: string; // 金手指/特殊能力 (仅主角有)
}

// 世界观设定
export interface WorldSetting {
  theme: string; // 如：赛博修仙、末世重生
  powerSystem: string; // 力量体系
  rules: string; // 世界核心规则
}

// 故事大纲节点
export interface PlotPoint {
  phase: string; // 阶段：开篇、发展、高潮、结尾
  summary: string; // 剧情概括
}

// 章节细纲
export interface ChapterOutline {
  chapterNumber: number;
  title: string;
  summary: string; // 故事梗概
  narrativePulse: string; // 叙事脉络
  coolPoint: string; // 本章爽点 (Cool Point)
  rules: string[]; // 必须遵守的规则/限制
  groupSummary?: string; // 新增：每5章的卷/段落小标题
}

// 章节正文
export interface ChapterContent {
  outline: ChapterOutline;
  content: string; // 生成的正文内容
  isGenerated: boolean;
}

// 应用当前的生成步骤
export enum GenerationStep {
  SETUP = 'SETUP',
  CHARACTERS = 'CHARACTERS',
  PLOT = 'PLOT',
  CHAPTER_PLAN = 'CHAPTER_PLAN',
  WRITING = 'WRITING'
}

// 导出的项目数据结构
export interface ProjectData {
  version: number;
  step: GenerationStep;
  bookTitle?: string; // 新增：书名
  prompt: string; // 保存初始脑洞
  world: WorldSetting | null;
  characters: Character[];
  plot: PlotPoint[];
  chapters: ChapterContent[];
  batchSize?: number; // 新增：批量生成数量配置
  storySummary?: string; // 新增：剧情回顾/压缩摘要，用于长期记忆
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { Character, WorldSetting, PlotPoint, ChapterOutline, ChapterContent } from "../types";

// 初始化 Gemini 客户端
// 必须确保环境变量 API_KEY 已设置
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// 使用逻辑推理能力最强的模型，保证故事连贯性
const MODEL_NAME = "gemini-3-pro-preview";

/**
 * 第一步：生成角色和世界观
 * 针对后宫爽文优化：要求生成多位高质量女性角色
 */
export const generateCharactersAndWorld = async (prompt: string): Promise<{ characters: Character[], world: WorldSetting }> => {
  console.log("正在请求 Gemini 生成后宫爽文人设和世界观...");

  const systemInstruction = `
    你是一位专门服务于中国年轻男性的网文大神，最擅长写"重生"、"都市/玄幻后宫"、"无敌流"爽文。
    你的文风要骚气、热血、直白，深谙读者的爽点。

    你的任务是根据用户的脑洞，设计一个极具吸引力的世界观和人物列表。

    【核心要求】
    1. **主角设定**：必须是男性，性格杀伐果断，不圣母，智商在线，拥有绝对逆天的金手指（系统、神器、前世记忆等）。
    2. **后宫团设定**：必须至少设计 3-4 位不同类型的**极品美女**作为主要配角（如：高冷校花、傲娇大小姐、温柔青梅、妩媚女总裁、绝美师尊等）。
       - 每个人物都要有极其惊艳的外貌描写关键词（黑丝、长腿、御姐等）。
       - 每个人物都要有明显的"反差萌"或独特的性格标签。
       - 初始对主角态度可以是鄙视或路人，方便后续攻略。
    3. **反派设定**：反派要嚣张跋扈，富二代或宗门圣子，专门用来给主角打脸，也就是"经验包"。
    4. **世界观**：要有等级森严的制度，方便主角通过升级来打破规则，装逼打脸。
  `;

  // 定义返回的 JSON 结构 Schema
  const responseSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      world: {
        type: Type.OBJECT,
        properties: {
          theme: { type: Type.STRING, description: "故事主题，如：都市重生修仙、校花贴身高手" },
          powerSystem: { type: Type.STRING, description: "力量/财富/地位等级划分，要清晰明确" },
          rules: { type: Type.STRING, description: "世界核心运行规则，或者主角必须遵守的系统规则" },
        },
        required: ["theme", "powerSystem", "rules"],
      },
      characters: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            role: { type: Type.STRING, enum: ["Protagonist", "Antagonist", "Support", "Mob"], description: "如果是后宫女主，请标记为 Support" },
            personality: { type: Type.STRING, description: "详细的性格描写，包括对主角的态度（如：暗恋、鄙视、依赖）" },
            background: { type: Type.STRING, description: "外貌描写（身材、颜值）及身份背景" },
            goal: { type: Type.STRING, description: "角色的核心诉求" },
            cheat: { type: Type.STRING, description: "主角的金手指（如：透视眼、签到系统），其他角色可留空" },
          },
          required: ["name", "role", "personality", "background", "goal"],
        },
      },
    },
    required: ["world", "characters"],
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.9, // 提高创造性，让美女设定更丰富
      },
    });

    const text = response.text;
    if (!text) throw new Error("API 返回为空");
    console.log("角色生成完成:", text);
    return JSON.parse(text);
  } catch (error) {
    console.error("生成角色失败:", error);
    throw error;
  }
};

/**
 * 第二步：生成主线大纲
 * 强调打脸节奏和感情线推进
 */
export const generateMainPlot = async (world: WorldSetting, characters: Character[]): Promise<PlotPoint[]> => {
  console.log("正在请求 Gemini 生成爽文主线大纲...");

  const charContext = characters.map(c => {
    let desc = `${c.name} (${c.role === 'Protagonist' ? '男主' : c.role === 'Antagonist' ? '反派' : '重要配角/女主'}): ${c.background}. 性格: ${c.personality}`;
    if (c.role === 'Support') desc += " [后宫预备/重要盟友]";
    return desc;
  }).join("\n");

  const worldContext = `世界: ${world.theme}. 力量体系: ${world.powerSystem}. 规则: ${world.rules}`;

  const prompt = `
    基于以下设定，生成一个让年轻男性读者热血沸腾的爽文主线大纲。

    【世界设定】
    ${worldContext}

    【人物设定】
    ${charContext}

    要求：
    1. **节奏紧凑**：分为 4-6 个关键大剧情节点。
    2. **核心爽点**：每个阶段必须包含"扮猪吃虎"、"人前显圣"或"强势打脸"的情节。
    3. **感情线**：必须穿插主角收服各路美女（女主）的过程，或者英雄救美、暧昧互动的情节。
    4. **目标明确**：从微末崛起，最终登顶世界巅峰，拥有无尽财富和权力。
  `;

  const responseSchema: Schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        phase: { type: Type.STRING, description: "阶段名称，如：重生归来、校花倾心、世家震怖、登顶巅峰" },
        summary: { type: Type.STRING, description: "该阶段的核心剧情概括，包含具体的打脸对象和收服的女主" },
      },
      required: ["phase", "summary"],
    },
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("API 返回为空");
    return JSON.parse(text);
  } catch (error) {
    console.error("生成大纲失败:", error);
    throw error;
  }
};

/**
 * 第三步：生成具体章节细纲 (批量生成前N章)
 * 增加"爽点"（Cool Point）的具体要求
 */
export const generateChapterOutlines = async (
  world: WorldSetting, 
  characters: Character[], 
  plot: PlotPoint[],
  count: number = 5
): Promise<ChapterOutline[]> => {
  console.log(`正在生成前 ${count} 章的细纲...`);

  const plotContext = plot.map(p => `[${p.phase}] ${p.summary}`).join("\n");
  const charContext = characters.map(c => `${c.name} (${c.role})`).join(", ");

  const prompt = `
    请根据主线大纲，规划前 ${count} 章的详细细纲。

    【主线大纲】
    ${plotContext}

    【人物】
    ${charContext}

    要求：
    1. **黄金三章法则**：
       - 第一章：必须有强烈的冲突（被退婚、被羞辱、重生节点），并结尾觉醒金手指。
       - 第二章：小试牛刀，利用金手指获得初步优势，震惊路人。
       - 第三章：第一个小高潮，打脸反派（或反派的小弟），收获第一位美女的好感。
    2. **爽点密集**：每一章都要有一个明确的"爽点"（Cool Point）或"期待感"（Hook）。
    3. **细致**：summary 字段要包含具体发生的事件，不要只写空话。
  `;

  const responseSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      chapters: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            chapterNumber: { type: Type.INTEGER },
            title: { type: Type.STRING, description: "极具吸引力的标题，如：震惊全场！、校花深夜来访" },
            summary: { type: Type.STRING, description: "详细的故事梗概，包含起承转合" },
            narrativePulse: { type: Type.STRING, description: "本章的情绪脉络：压抑->爆发，或者 暧昧->推倒" },
            coolPoint: { type: Type.STRING, description: "本章核心爽点，如：一拳秒杀、女神倒贴" },
            rules: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: "写作时的注意点，如：不要太啰嗦，多描写女主腿部细节" 
            },
          },
          required: ["chapterNumber", "title", "summary", "narrativePulse", "coolPoint", "rules"],
        },
      }
    },
    required: ["chapters"],
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("API 返回为空");
    const json = JSON.parse(text);
    return json.chapters as ChapterOutline[];
  } catch (error) {
    console.error("生成细纲失败:", error);
    throw error;
  }
};

/**
