import React, { useState, useEffect, useRef } from 'react';
import { GenerationStep, Character, WorldSetting, PlotPoint, ChapterContent, ProjectData } from './types';
import { generateCharactersAndWorld, generateMainPlot, generateChapterOutlines, generateNextChapterOutlines, generateFullChapterContent, compressStoryHistory } from './services/geminiService';
import StepSetup from './components/StepSetup';
import StepCharacters from './components/StepCharacters';
import StepPlot from './components/StepPlot';
import StepWriting from './components/StepWriting';
import TitleGeneratorModal from './components/TitleGeneratorModal';
import SettingsModal from './components/SettingsModal';
import { Download, Upload, Save, FileJson, FilePlus, PenLine, Settings } from 'lucide-react';

const STORAGE_KEY = 'soulwriter_autosave_v1';

const App: React.FC = () => {
  // 核心状态
  const [step, setStep] = useState<GenerationStep>(GenerationStep.SETUP);
  const [isLoading, setIsLoading] = useState(false);
  const [isLoadedFromStorage, setIsLoadedFromStorage] = useState(false);
  const [batchProgress, setBatchProgress] = useState<string | null>(null); // null表示不在批量生成中

  // Data State
  const [prompt, setPrompt] = useState("重生回到十年前，觉醒了'万物增幅'系统，这一世我要在这个赛博朋克与古武并存的世界成为最强。");
  const [bookTitle, setBookTitle] = useState("");
  const [world, setWorld] = useState<WorldSetting | null>(null);
  const [characters, setCharacters] = useState<Character[]>([]);
  const [plot, setPlot] = useState<PlotPoint[]>([]);
  const [chapters, setChapters] = useState<ChapterContent[]>([]);
  const [batchSize, setBatchSize] = useState(5); // 默认批量生成5章
  const [storySummary, setStorySummary] = useState(""); // 剧情记忆摘要

  // UI State
  const [showTitleModal, setShowTitleModal] = useState(false);
  const [showSettingsModal, setShowSettingsModal] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- 自动保存与恢复逻辑 ---

  // 1. 初始化时加载数据
  useEffect(() => {
    const savedData = localStorage.getItem(STORAGE_KEY);
    if (savedData) {
      try {
        const parsed: ProjectData = JSON.parse(savedData);
        // 简单的版本检查
        if (parsed.version === 1) {
          console.log("检测到自动保存进度，正在恢复...");
          setStep(parsed.step);
          setPrompt(parsed.prompt || "");
          setBookTitle(parsed.bookTitle || "");
          setWorld(parsed.world);
          setCharacters(parsed.characters);
          setPlot(parsed.plot);
          setChapters(parsed.chapters);
          if (parsed.batchSize) setBatchSize(parsed.batchSize);
          if (parsed.storySummary) setStorySummary(parsed.storySummary);
        }
      } catch (e) {
        console.error("读取自动保存失败:", e);
      }
    }
    setIsLoadedFromStorage(true); // 标记加载尝试已完成
  }, []);

  // 2. 数据变化时自动保存
  useEffect(() => {
    // 只有在初始化加载完成后才开始保存，防止覆盖
    if (!isLoadedFromStorage) return;

    const data: ProjectData = {
      version: 1,
      step,
      prompt,
      bookTitle,
      world,
      characters,
      plot,
      chapters,
      batchSize,
      storySummary
    };

    // 使用 debounce 或直接保存，这里数据量不大直接保存
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    console.log("进度已自动保存");

  }, [step, prompt, bookTitle, world, characters, plot, chapters, batchSize, storySummary, isLoadedFromStorage]);

  // 新建项目 (重置)
  const handleNewProject = () => {
    if (window.confirm("确定要新建项目吗？这将清除当前的自动保存进度，且无法恢复。")) {
      // 清除本地存储
      localStorage.removeItem(STORAGE_KEY);

      // 强制刷新页面以重置所有状态为默认值
      // 这样可以确保 autosave 逻辑不会意外保存旧状态，并且让用户回到带有默认提示文案的初始界面
      window.location.reload();
    }
  };

  // --- 业务逻辑 ---

  // Step 1 -> 2: Setup to Characters
  const handleSetupGenerate = async () => {
    setIsLoading(true);
    try {
      const data = await generateCharactersAndWorld(prompt);
      setWorld(data.world);
      setCharacters(data.characters);
      setStep(GenerationStep.CHARACTERS);
    } catch (e) {
      alert("生成失败，请检查API Key或重试");
    } finally {
      setIsLoading(false);
    }
  };

  // Step 2 -> 3: Characters to Plot
  const handleConfirmCharacters = async (updatedWorld: WorldSetting, updatedCharacters: Character[]) => {
    if (!updatedWorld || updatedCharacters.length === 0) return;

    setWorld(updatedWorld);
    setCharacters(updatedCharacters);

    setIsLoading(true);
    try {
      const data = await generateMainPlot(updatedWorld, updatedCharacters);
      setPlot(data);
      setStep(GenerationStep.PLOT);
    } catch (e) {
      alert("生成大纲失败");
    } finally {
      setIsLoading(false);
    }
  };

  // Step 3 -> 4: Plot to Chapter Outlines -> Writing
  const handleConfirmPlot = async () => {
    if (!world || characters.length === 0 || plot.length === 0) return;
    setIsLoading(true);
    try {
      // 初始生成数量也使用 batchSize
      const outlineData = await generateChapterOutlines(world, characters, plot, batchSize);
      const initialChapters: ChapterContent[] = outlineData.map(o => ({
        outline: o,
        content: '',
        isGenerated: false
      }));
      setChapters(initialChapters);
      setStep(GenerationStep.WRITING);
    } catch (e) {
      alert("生成细纲失败");
    } finally {
      setIsLoading(false);
    }
  };

  // 仅续写后续章节大纲
  const handleAddChaptersOutline = async (count: number = 5) => {
    if (!world || characters.length === 0 || plot.length === 0 || chapters.length === 0) return;

    setIsLoading(true);
    try {
      const lastChapter = chapters[chapters.length - 1];
      // 传递当前的剧情摘要，优化大纲连贯性
      const newOutlines = await generateNextChapterOutlines(world, characters, plot, lastChapter.outline, count, storySummary);

      const newChapters: ChapterContent[] = newOutlines.map(o => ({
        outline: o,
        content: '',
        isGenerated: false
      }));

      setChapters(prev => [...prev, ...newChapters]);
    } catch (e) {
      console.error(e);
      alert("续写章节大纲失败");
    } finally {
      setIsLoading(false);
    }
  };

  /**
   * 批量生成后续章节（大纲 + 正文）
   * 逻辑：
   * 1. 自动压缩前文剧情，更新 storySummary 状态 (新增)
   * 2. 调用大纲生成接口，规划后续 N 章 (带上最新 summary)。
   * 3. 将空章节加入 State。
   * 4. 循环遍历新章节，串行调用正文生成接口（保证上下文连贯）。
   */
  const handleBatchGenerateChapters = async (count: number = 5) => {
    if (!world || characters.length === 0 || plot.length === 0 || chapters.length === 0) return;
    if (batchProgress) return; // 防止重复点击

    try {
      // 0. 自动压缩剧情 (新增优化)
      // 使用 settings 中的压缩逻辑，范围覆盖到最后一章
      setBatchProgress("正在回顾前文并生成记忆摘要...");
      const latestSummary = await compressStoryHistory(chapters, characters, chapters.length - 1);
      setStorySummary(latestSummary); // 更新状态以备持久化

      // 1. 生成大纲
      setBatchProgress("基于最新记忆规划后续大纲...");
      const lastChapter = chapters[chapters.length - 1];

      // 传入最新的摘要
      const newOutlines = await generateNextChapterOutlines(
        world, 
        characters, 
        plot, 
        lastChapter.outline, 
        count,
        latestSummary
      );

      // 2. 创建占位章节并添加到状态
      const newChaptersPlaceholder: ChapterContent[] = newOutlines.map(o => ({
        outline: o,
        content: '',
        isGenerated: false
      }));

      // 先保存当前的章节数量，作为后续更新的起始索引
      const startIndex = chapters.length;

      // 更新 UI 显示出新的空章节
      setChapters(prev => [...prev, ...newChaptersPlaceholder]);

      // 3. 串行生成每一章的正文
      // 注意：这里我们不能直接用 chapters 状态，因为它是旧的闭包。
      // 我们需要构建一个临时的上下文链。
      let previousContent = lastChapter.content || lastChapter.outline.summary; 

      for (let i = 0; i < newChaptersPlaceholder.length; i++) {
        const currentChapterIndex = startIndex + i;
        const currentChapter = newChaptersPlaceholder[i];

        setBatchProgress(`正在撰写第 ${currentChapter.outline.chapterNumber} 章... (${i + 1}/${count})`);

        // 调用非流式生成接口
        const generatedContent = await generateFullChapterContent(
          currentChapter.outline,
          world,
          characters,
          previousContent,
          undefined, // additionalInstructions
          latestSummary // 使用最新的记忆摘要
        );

        // 更新单个章节状态
        handleUpdateChapter(currentChapterIndex, generatedContent, true);

        // 更新上下文，为下一章做准备
        previousContent = generatedContent;
      }

      setBatchProgress(null);

    } catch (e) {
      console.error(e);
      alert("批量生成过程中断，请重试");
      setBatchProgress(null);
    }
  };


  // 更新章节内容
  const handleUpdateChapter = (index: number, content: string, isGenerated: boolean) => {
    setChapters(prev => {
      const newChapters = [...prev];
      if (newChapters[index]) {
        newChapters[index] = {
          ...newChapters[index],
          content,
          isGenerated
        };
      }
      return newChapters;
    });
  };

  // 更新章节标题
  const handleUpdateChapterTitle = (index: number, title: string) => {
    setChapters(prev => {
      const newChapters = [...prev];
      if (newChapters[index]) {
        newChapters[index] = {
          ...newChapters[index],
          outline: {
            ...newChapters[index].outline,
            title
          }
        };
      }
      return newChapters;
    });
  };

  // 更新分组小结
  const handleUpdateGroupSummary = (index: number, summary: string) => {
      setChapters(prev => {
          const newChapters = [...prev];
          if (newChapters[index]) {
              newChapters[index] = {
                  ...newChapters[index],
                  outline: {
                      ...newChapters[index].outline,
                      groupSummary: summary
                  }
              }
          }
          return newChapters;
      })
  }

  // 删除分组小结
  const handleDeleteGroupSummary = (index: number) => {
      handleUpdateGroupSummary(index, "");
  };

  // 删除章节
  const handleDeleteChapter = (index: number) => {
      if (chapters.length <= 1) {
          alert("无法删除：至少需要保留一个章节。");
          return;
      }

      setChapters(prev => {
          // 1. 过滤掉删除的章节
          const newChapters = prev.filter((_, i) => i !== index);

          // 2. 重新编排章节号，保证连续性
          return newChapters.map((chap, i) => ({
              ...chap,
              outline: {
                  ...chap.outline,
                  chapterNumber: i + 1
              }
          }));
      });
  };

  // 导出项目
  const handleExport = () => {
    const data: ProjectData = {
      version: 1,
      step,
      prompt,
      bookTitle,
      world,
      characters,
      plot,
      chapters,
      batchSize,
      storySummary
    };

    const jsonString = JSON.stringify(data, null, 2);
    const blob = new Blob([jsonString], { type: "application/json" });
    const url = URL.createObjectURL(blob);

    const link = document.createElement('a');
    link.href = url;
    link.download = `${bookTitle || 'soulwriter-project'}-${new Date().toISOString().slice(0, 10)}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  // 导入项目触发
  const triggerImport = () => {
    fileInputRef.current?.click();
  };

  // 处理文件读取
  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (json.version && json.step) {
          const data = json as ProjectData;
          setStep(data.step);
          setPrompt(data.prompt || "");
          setBookTitle(data.bookTitle || "");
          setWorld(data.world);
          setCharacters(data.characters);
          setPlot(data.plot);
          setChapters(data.chapters);
          if (data.batchSize) setBatchSize(data.batchSize);
          if (data.storySummary) setStorySummary(data.storySummary);
          alert("项目导入成功！");
        } else {
          alert("无效的项目文件格式");
        }
      } catch (error) {
        console.error("Import error", error);
        alert("文件解析失败");
      }
    };
    reader.readAsText(file);
    e.target.value = ''; 
  };

  return (
    <div className="min-h-screen bg-[#0d1117] text-gray-100 font-sans selection:bg-indigo-500/30">
      <header className="border-b border-gray-800 bg-[#0d1117]/80 backdrop-blur sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-4">
             {/* Logo */}
             <div className="font-bold text-xl tracking-tight bg-gradient-to-r from-indigo-400 to-cyan-400 bg-clip-text text-transparent flex items-center gap-2 cursor-pointer shrink-0" onClick={() => setStep(GenerationStep.SETUP)}>
                <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center text-white">
                  <FileJson size={20} />
                </div>
                <span className="hidden sm:inline">SoulWriter AI</span>
              </div>

              {/* Divider */}
              <div className="h-6 w-px bg-gray-700 mx-2 hidden sm:block"></div>

              {/* Book Title */}
              <button 
                onClick={() => setShowTitleModal(true)}
                className="flex items-center gap-2 px-3 py-1.5 rounded-lg hover:bg-gray-800 transition-colors group max-w-[150px] sm:max-w-xs"
                title="点击修改书名"
              >
                <div className="text-sm font-bold text-gray-200 truncate">
                   {bookTitle || "未命名作品"}
                </div>
                <PenLine size={14} className="text-gray-500 group-hover:text-indigo-400 shrink-0" />
              </button>
          </div>


          <div className="flex items-center gap-4">
            {/* Steps Indicator (Desktop) */}
            <div className="hidden lg:flex gap-2 text-xs font-mono text-gray-500 mr-4">
              <span className={step === GenerationStep.SETUP ? 'text-indigo-400' : ''}>01.设定</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.CHARACTERS ? 'text-indigo-400' : ''}>02.人物</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.PLOT ? 'text-indigo-400' : ''}>03.大纲</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.WRITING ? 'text-indigo-400' : ''}>04.正文</span>
            </div>

            {/* Actions */}
            <div className="flex items-center gap-2 border-l border-gray-700 pl-4">
              <input 
                type="file" 
                ref={fileInputRef} 
                className="hidden" 
                accept=".json" 
                onChange={handleImport}
              />

              {/* Settings Button - 可见性：所有端可见 */}
              <button 
                onClick={() => setShowSettingsModal(true)}
                className="p-2 text-gray-400 hover:text-white hover:bg-gray-800 rounded-lg transition-colors flex items-center gap-2 text-sm"
                title="设置"
              >
                <Settings size={20} />
              </button>

              {/* 新建项目按钮 */}
              <button 
                onClick={handleNewProject}
                className="p-2 text-gray-400 hover:text-white hover:bg-gray-800 rounded-lg transition-colors flex items-center gap-2 text-sm"
                title="新建项目 (清空进度)"
              >
                <FilePlus size={18} />
                <span className="hidden sm:inline">新建项目</span>
              </button>

              <button 
                onClick={triggerImport}
                className="p-2 text-gray-400 hover:text-white hover:bg-gray-800 rounded-lg transition-colors flex items-center gap-2 text-sm"
                title="导入项目"
              >
                <Upload size={18} />
                <span className="hidden sm:inline">导入</span>
              </button>

              <button 
                onClick={handleExport}
                className="px-3 py-1.5 bg-gray-800 hover:bg-gray-700 text-indigo-300 border border-indigo-500/30 rounded-lg transition-colors flex items-center gap-2 text-sm font-medium"
                title="导出项目"
              >
                <Save size={18} />
                <span className="hidden sm:inline">保存</span>
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8">
        {step === GenerationStep.SETUP && (
          <StepSetup 
            prompt={prompt}
            setPrompt={setPrompt}
            onGenerate={handleSetupGenerate} 
            isLoading={isLoading} 
          />
        )}

        {step === GenerationStep.CHARACTERS && world && (
          <StepCharacters 
            world={world} 
            characters={characters} 
            onConfirm={handleConfirmCharacters}
            isLoading={isLoading}
          />
        )}

        {step === GenerationStep.PLOT && (
          <StepPlot 
            plot={plot}
            onConfirm={handleConfirmPlot}
            isLoading={isLoading}
          />
        )}

        {step === GenerationStep.WRITING && world && (
          <StepWriting 
            chapters={chapters}
            world={world}
            characters={characters}
            onUpdateChapter={handleUpdateChapter}
            onUpdateTitle={handleUpdateChapterTitle}
            onUpdateGroupSummary={handleUpdateGroupSummary}
            onDeleteChapter={handleDeleteChapter}
            onDeleteGroupSummary={handleDeleteGroupSummary}
            onLoadMoreChapters={handleAddChaptersOutline}
            onBatchGenerate={handleBatchGenerateChapters}
            isLoadingMore={isLoading}
            batchProgress={batchProgress}
            batchSize={batchSize}
            storySummary={storySummary} // Pass summary
          />
        )}
      </main>

      {/* Modals */}
      {showTitleModal && (
        <TitleGeneratorModal 
           currentTitle={bookTitle}
           onSelect={(t) => setBookTitle(t)}
           onClose={() => setShowTitleModal(false)}
           contextData={{ prompt, world, characters }}
        />
      )}

      {showSettingsModal && (
        <SettingsModal 
          batchSize={batchSize}
          onSaveBatchSize={setBatchSize}
          storySummary={storySummary}
          onSaveStorySummary={setStorySummary}
          chapters={chapters}
          characters={characters}
          onClose={() => setShowSettingsModal(false)}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ChapterContent, Character, WorldSetting } from '../types';
import { streamChapterContent, generateBatchSummary } from '../services/geminiService';
import ChapterReader from './ChapterReader';
import { FileText, Play, CheckCircle, Menu, X, Edit, Save, PlusCircle, Loader2, Sparkles, ArrowDown, RefreshCw, RotateCcw, CornerDownLeft, Bookmark, Copy, Check, Trash2, AlertTriangle, Eye } from 'lucide-react';

interface Props {
  chapters: ChapterContent[];
  world: WorldSetting;
  characters: Character[];
  onUpdateChapter: (index: number, content: string, isGenerated: boolean) => void;
  onUpdateTitle: (index: number, title: string) => void;
  onUpdateGroupSummary: (index: number, summary: string) => void; 
  onDeleteChapter: (index: number) => void; // 新增：删除章节
  onDeleteGroupSummary: (index: number) => void; // 新增：删除卷标
  onLoadMoreChapters: (count: number) => void;
  onBatchGenerate: (count: number) => void;
  isLoadingMore: boolean;
  batchProgress: string | null;
  batchSize: number; // 新增：接收配置的数量
  storySummary: string; // 新增：剧情记忆
}

const CopyBtn = ({ text, className = "" }: { text: string, className?: string }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = (e: React.MouseEvent) => {
    e.stopPropagation();
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <button 
      onClick={handleCopy} 
      className={`p-1 rounded-md hover:bg-gray-700/50 transition-colors inline-flex items-center justify-center shrink-0 ${copied ? 'text-green-400' : 'text-gray-500 hover:text-indigo-400'} ${className}`}
      title="复制内容"
    >
      {copied ? <Check size={12} /> : <Copy size={12} />}
    </button>
  );
};

const StepWriting: React.FC<Props> = ({ 
  chapters, 
  world, 
  characters, 
  onUpdateChapter, 
  onUpdateTitle, 
  onUpdateGroupSummary,
  onDeleteChapter,
  onDeleteGroupSummary,
  onLoadMoreChapters, 
  onBatchGenerate,
  isLoadingMore,
  batchProgress,
  batchSize,
  storySummary
}) => {
  const [activeChapterIndex, setActiveChapterIndex] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [showSidebar, setShowSidebar] = useState(false); 
  const [isEditing, setIsEditing] = useState(false);

  // Loading state specifically for generating group summaries
  // Key is the starting index of the group
  const [generatingSummaryIndices, setGeneratingSummaryIndices] = useState<number[]>([]);

  // 重写功能相关状态
  const [showRewriteModal, setShowRewriteModal] = useState(false);
  const [rewriteInstructions, setRewriteInstructions] = useState("");

  // 删除确认弹窗状态
  const [deleteConfirm, setDeleteConfirm] = useState<{
    isOpen: boolean;
    type: 'chapter' | 'summary';
    index: number;
    title?: string;
  }>({ isOpen: false, type: 'chapter', index: -1 });

  // 规则详情弹窗状态
  const [showRulesModal, setShowRulesModal] = useState(false);

  // 撤销历史记录
  const [undoHistory, setUndoHistory] = useState<Record<number, string>>({});

  // 章节跳转输入状态
  const [jumpInput, setJumpInput] = useState("");

  // 确保 activeChapterIndex 不越界
  useEffect(() => {
      if (chapters.length > 0 && activeChapterIndex >= chapters.length) {
          setActiveChapterIndex(Math.max(0, chapters.length - 1));
      }
  }, [chapters.length, activeChapterIndex]);

  const activeChapter = chapters[activeChapterIndex] || chapters[0]; // 防御性处理

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setIsEditing(false);
  }, [activeChapterIndex]);

  const handleGenerate = async () => {
    if (isGenerating || activeChapter.isGenerated) return;
    startGeneration();
  };

  const handleRewrite = async () => {
    if (isGenerating) return;

    if (activeChapter.content) {
      setUndoHistory(prev => ({
        ...prev,
        [activeChapterIndex]: activeChapter.content
      }));
    }

    setShowRewriteModal(false);
    startGeneration(rewriteInstructions);
    setRewriteInstructions("");
  };

  const handleUndoRewrite = () => {
    const prevContent = undoHistory[activeChapterIndex];
    if (!prevContent) return;

    if (window.confirm("确定要撤销重写，恢复到上一个版本吗？当前版本将丢失。")) {
      onUpdateChapter(activeChapterIndex, prevContent, true);
      setUndoHistory(prev => {
        const newState = { ...prev };
        delete newState[activeChapterIndex];
        return newState;
      });
    }
  };

  const handleJumpToChapter = () => {
    const target = parseInt(jumpInput);
    if (isNaN(target)) return;

    if (target < 1 || target > chapters.length) {
      alert(`请输入有效章节号 (1-${chapters.length})`);
      return;
    }

    setActiveChapterIndex(target - 1);
    setJumpInput("");
    if (window.innerWidth < 768) setShowSidebar(false);
  };

  const handleJumpKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleJumpToChapter();
    }
  };

  // 生成分组标题的逻辑
  const handleGenerateGroupSummary = async (startIndex: number) => {
    if (generatingSummaryIndices.includes(startIndex)) return;

    // 获取这5章
    const groupChapters = chapters.slice(startIndex, startIndex + 5).map(c => c.outline);
    if (groupChapters.length === 0) return;

    setGeneratingSummaryIndices(prev => [...prev, startIndex]);

    try {
        const summary = await generateBatchSummary(groupChapters);
        onUpdateGroupSummary(startIndex, summary);
    } catch (e) {
        console.error("生成卷标出错详情:", e);
        alert("生成卷标失败，请查看控制台日志以获取更多信息");
    } finally {
        setGeneratingSummaryIndices(prev => prev.filter(i => i !== startIndex));
    }
  };

  const startGeneration = async (instructions?: string) => {
    setIsGenerating(true);
    setIsEditing(false);

    if (window.innerWidth < 768) {
        setShowSidebar(false);
    }

    let prevContext = "";
    if (activeChapterIndex > 0) {
      const prevChap = chapters[activeChapterIndex - 1];
      prevContext = prevChap.content || prevChap.outline.summary;
    }

    try {
      if (instructions) {
         onUpdateChapter(activeChapterIndex, "", false); 
      }

      let fullText = "";
      await streamChapterContent(
        activeChapter.outline,
        world,
        characters,
        prevContext,
        (textChunk) => {
          fullText += textChunk;
          onUpdateChapter(activeChapterIndex, fullText, false);
        },
        instructions,
        storySummary // 传递剧情记忆
      );

      onUpdateChapter(activeChapterIndex, fullText, true);

    } catch (e) {
      alert("生成中断，请重试");
    } finally {
      setIsGenerating(false);
    }
  };

  // --- 删除确认逻辑 ---
  const requestDeleteChapter = (index: number) => {
      setDeleteConfirm({
          isOpen: true,
          type: 'chapter',
          index: index,
          title: `第 ${chapters[index].outline.chapterNumber} 章`
      });
  };

  const requestDeleteSummary = (index: number, summary: string) => {
      setDeleteConfirm({
          isOpen: true,
          type: 'summary',
          index: index,
          title: summary || "当前卷标"
      });
  };

  const executeDelete = () => {
      if (deleteConfirm.type === 'chapter') {
          onDeleteChapter(deleteConfirm.index);
          // 如果删除的是当前选中的章节，且不是第一章，需要更新 activeIndex
          if (activeChapterIndex === deleteConfirm.index && activeChapterIndex > 0) {
              setActiveChapterIndex(Math.max(0, activeChapterIndex - 1));
          }
      } else {
          onDeleteGroupSummary(deleteConfirm.index);
      }
      setDeleteConfirm({ ...deleteConfirm, isOpen: false });
  };

  if (!activeChapter) return <div>数据加载中...</div>;

  const isBatchGenerating = batchProgress !== null;
  const canUndo = !!undoHistory[activeChapterIndex];

  return (
    <div className="flex h-[calc(100vh-100px)] overflow-hidden rounded-xl border border-gray-800 bg-gray-950 relative">

      {/* 统一的删除确认模态框 */}
      {deleteConfirm.isOpen && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[70] flex items-center justify-center p-4 animate-in fade-in duration-200">
           <div className="bg-gray-900 border border-red-500/30 rounded-xl p-6 w-full max-w-sm shadow-2xl flex flex-col items-center text-center">
              <div className="w-12 h-12 bg-red-900/20 rounded-full flex items-center justify-center mb-4 text-red-500">
                  <AlertTriangle size={24} />
              </div>
              <h3 className="text-xl font-bold text-white mb-2">
                  确定要删除吗？
              </h3>
              <p className="text-gray-400 text-sm mb-6 leading-relaxed">
                  您即将删除 <span className="text-white font-bold">{deleteConfirm.title}</span>。
                  {deleteConfirm.type === 'chapter' && (
                      <span className="block mt-1 text-red-400 text-xs">注意：删除章节后，后续章节序号将自动前移，且无法撤销。</span>
                  )}
              </p>

              <div className="flex gap-3 w-full">
                  <button 
                    onClick={() => setDeleteConfirm({ ...deleteConfirm, isOpen: false })} 
                    className="flex-1 px-4 py-3 rounded-lg bg-gray-800 hover:bg-gray-700 text-gray-300 font-medium transition-colors"
                  >
                    取消
                  </button>
                  <button 
                    onClick={executeDelete} 
                    className="flex-1 px-4 py-3 rounded-lg bg-red-600 hover:bg-red-500 text-white font-bold shadow-lg shadow-red-900/30 transition-colors"
                  >
                    确认删除
                  </button>
              </div>
           </div>
        </div>
      )}

      {/* 脉络与规则详情模态框 */}
      {showRulesModal && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[80] flex items-center justify-center p-4 animate-in fade-in duration-200" onClick={() => setShowRulesModal(false)}>
           <div className="bg-gray-900 border border-gray-700 rounded-xl w-full max-w-lg shadow-2xl p-6 relative flex flex-col max-h-[90vh]" onClick={e => e.stopPropagation()}>
              <button 
                  onClick={() => setShowRulesModal(false)}
                  className="absolute top-4 right-4 text-gray-500 hover:text-white transition-colors"
              >
                  <X size={20} />
              </button>

              <div className="border-b border-gray-800 pb-4 mb-4 shrink-0">
                  <h3 className="text-xl font-bold text-white flex items-center gap-2">
                      <FileText className="text-indigo-400" size={20} />
                      第{activeChapter.outline.chapterNumber}章创作指引
                  </h3>
                  <p className="text-sm text-gray-500 mt-1">{activeChapter.outline.title}</p>
              </div>

              <div className="space-y-6 overflow-y-auto custom-scrollbar pr-2">
                  {/* 爽点 */}
                  <div className="bg-gradient-to-r from-indigo-900/30 to-purple-900/30 border border-indigo-500/30 rounded-lg p-4">
                      <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2 flex items-center gap-1">
                          <Sparkles size={12} />
                          核心爽点 (Cool Point)
                      </h4>
                      <p className="text-indigo-100 text-sm font-medium leading-relaxed">
                          {activeChapter.outline.coolPoint}
                      </p>
                  </div>

                  {/* 脉络 */}
                  <div>
                      <h4 className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">叙事脉络 (Narrative Pulse)</h4>
                      <div className="bg-gray-800/50 rounded-lg p-3 border border-gray-700 text-gray-300 text-sm leading-relaxed">
                          {activeChapter.outline.narrativePulse}
                      </div>
                  </div>

                  {/* 规则 */}
                  <div>
                      <h4 className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">写作规则 (Rules)</h4>
                      <ul className="space-y-2">
                          {activeChapter.outline.rules.map((rule, idx) => (
                              <li key={idx} className="flex items-start gap-2 text-sm text-gray-300 bg-gray-800/30 p-2 rounded border border-gray-700/30">
