  // Google Schema (using SDK Types)
  const googleSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      world: {
        type: Type.OBJECT,
        properties: {
          theme: { type: Type.STRING },
          powerSystem: { type: Type.STRING },
          rules: { type: Type.STRING },
