    1. **节奏紧凑**：分为 4-6 个关键大剧情节点。
    2. **核心爽点**：每个阶段必须包含"扮猪吃虎"、"人前显圣"或"强势打脸"的情节。
    3. **感情线**：必须穿插主角收服各路美女（女主）的过程，或者英雄救美、暧昧互动的情节。
    4. **目标明确**：从微末崛起，最终登顶世界巅峰，拥有无尽财富和权力。
  `;

  // Schema Definitions
  const googleSchema: Schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        phase: { type: Type.STRING },
        summary: { type: Type.STRING },
      },
      required: ["phase", "summary"],
    },
  };

  const aliyunSchema = {
      type: "object", // Aliyun response_format usually requires object root for json_object mode, so we might wrap it or just prompt for array
      properties: {
          plot_points: {
              type: "array",
              items: {
                  type: "object",
                  properties: {
                      phase: { type: "string" },
                      summary: { type: "string" }
                  },
                  required: ["phase", "summary"]
