          required: ["chapterNumber", "title", "summary", "narrativePulse", "coolPoint", "rules"],
        },
      }
    },
    required: ["chapters"],
  };

  // Plain JSON schema for Aliyun prompt injection
  const aliyunSchema = {
      type: "object",
      properties: {
          chapters: {
              type: "array",
              items: {
                  type: "object",
                  properties: {
                      chapterNumber: { type: "integer" },
                      title: { type: "string" },
                      summary: { type: "string" },
                      narrativePulse: { type: "string" },
                      coolPoint: { type: "string" },
                      rules: { type: "array", items: { type: "string" } }
                  },
                  required: ["chapterNumber", "title", "summary", "narrativePulse", "coolPoint", "rules"]
              }
          }
