/**
 * 额外功能：生成书名
 */
export const generateBookTitles = async (
  promptText: string,
  world?: WorldSetting | null,
  characters?: Character[],
  provider: ModelProvider = 'google', 
  aliyunApiKey?: string,
  googleModelName: string = DEFAULT_GOOGLE_MODEL
): Promise<string[]> => {
  console.log("正在生成书名...");

  let context = `核心脑洞：${promptText}\n`;
  if (world) {
    context += `世界观主题：${world.theme}\n`;
    context += `力量体系：${world.powerSystem}\n`;
  }
  if (characters && characters.length > 0) {
    const protag = characters.find(c => c.role === 'Protagonist');
    if (protag) {
      context += `主角金手指：${protag.cheat}\n`;
      context += `主角性格：${protag.personality}\n`;
    }
  }

  const prompt = `
    你是一个精通中国网文市场的资深编辑。请根据以下小说设定，想出 10 个极具吸引力、符合"飞卢风"或"起点爽文风"的书名。

    【小说设定】
    ${context}

    【起名要求】
    1. **吸睛**：要包含"重生"、"开局"、"无敌"、"多子多福"、"校花"、"女帝"等热门关键词。
    2. **直白**：书名要能直接体现金手指或核心爽点。
    3. **格式**：不要加书名号，直接返回书名列表。
    4. **风格多样**：有的可以侧重系统，有的侧重后宫，有的侧重无敌。

    例如：
    - 重生都市：开局截胡校花机缘
    - 高武：因为太怕痛所以全点防御力了
    - 让你代管宗门，全成大帝了？
  `;

  const googleSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      titles: { type: Type.ARRAY, items: { type: Type.STRING } },
    },
    required: ["titles"],
  };

  const aliyunSchema = {
      type: "object",
      properties: {
          titles: { type: "array", items: { type: "string" } },
      },
      required: ["titles"],
  };

  try {
    if (provider === 'aliyun') {
         if (!aliyunApiKey) throw new Error("请配置阿里云 API Key");
         const res = await callAliyunJSON([
             { role: "user", content: prompt }
         ], aliyunApiKey, aliyunSchema);
         return res.titles;
    } else {
        const response = await ai.models.generateContent({
            model: googleModelName,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: googleSchema,
                temperature: 0.95,
            },
        });

        const text = response.text;
        if (!text) throw new Error("书名生成返回为空");
        const json = JSON.parse(text);
        return json.titles;
    }
  } catch (error) {
    console.error("书名生成失败:", error);
    return ["重生之逆天改命", "都市之最强仙尊", "开局一把刀", "我的系统太强了"];
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { GenerationStep, Character, WorldSetting, PlotPoint, ChapterContent, ProjectData, ModelProvider } from './types';
import { generateCharactersAndWorld, generateMainPlot, generateChapterOutlines, generateNextChapterOutlines, generateFullChapterContent, compressStoryHistory } from './services/geminiService';
import StepSetup from './components/StepSetup';
import StepCharacters from './components/StepCharacters';
import StepPlot from './components/StepPlot';
import StepWriting from './components/StepWriting';
import TitleGeneratorModal from './components/TitleGeneratorModal';
import SettingsModal from './components/SettingsModal';
import { Download, Upload, Save, FileJson, FilePlus, PenLine, Settings } from 'lucide-react';

const STORAGE_KEY = 'soulwriter_autosave_v1';

const App: React.FC = () => {
  // 核心状态
  const [step, setStep] = useState<GenerationStep>(GenerationStep.SETUP);
  const [isLoading, setIsLoading] = useState(false);
  const [isLoadedFromStorage, setIsLoadedFromStorage] = useState(false);
  const [batchProgress, setBatchProgress] = useState<string | null>(null); // null表示不在批量生成中

  // Data State
  const [prompt, setPrompt] = useState("重生回到十年前，觉醒了'万物增幅'系统，这一世我要在这个赛博朋克与古武并存的世界成为最强。");
  const [bookTitle, setBookTitle] = useState("");
  const [world, setWorld] = useState<WorldSetting | null>(null);
  const [characters, setCharacters] = useState<Character[]>([]);
  const [plot, setPlot] = useState<PlotPoint[]>([]);
  const [chapters, setChapters] = useState<ChapterContent[]>([]);
  const [batchSize, setBatchSize] = useState(5); // 默认批量生成5章
  const [storySummary, setStorySummary] = useState(""); // 剧情记忆摘要

  // Model Config State
  const [modelProvider, setModelProvider] = useState<ModelProvider>('google');
  const [googleModelName, setGoogleModelName] = useState("gemini-3-pro-preview");
  const [aliyunApiKey, setAliyunApiKey] = useState("");

  // UI State
  const [showTitleModal, setShowTitleModal] = useState(false);
  const [showSettingsModal, setShowSettingsModal] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- 自动保存与恢复逻辑 ---

  // 1. 初始化时加载数据
  useEffect(() => {
    const savedData = localStorage.getItem(STORAGE_KEY);
    if (savedData) {
      try {
        const parsed: ProjectData = JSON.parse(savedData);
        // 简单的版本检查
        if (parsed.version === 1) {
          console.log("检测到自动保存进度，正在恢复...");
          setStep(parsed.step);
          setPrompt(parsed.prompt || "");
          setBookTitle(parsed.bookTitle || "");
          setWorld(parsed.world);
          setCharacters(parsed.characters);
          setPlot(parsed.plot);
          setChapters(parsed.chapters);
          if (parsed.batchSize) setBatchSize(parsed.batchSize);
          if (parsed.storySummary) setStorySummary(parsed.storySummary);
          if (parsed.modelProvider) setModelProvider(parsed.modelProvider);
          if (parsed.googleModelName) setGoogleModelName(parsed.googleModelName);
          if (parsed.aliyunApiKey) setAliyunApiKey(parsed.aliyunApiKey);
        }
      } catch (e) {
        console.error("读取自动保存失败:", e);
      }
    }
    setIsLoadedFromStorage(true); // 标记加载尝试已完成
  }, []);

  // 2. 数据变化时自动保存
  useEffect(() => {
    // 只有在初始化加载完成后才开始保存，防止覆盖
    if (!isLoadedFromStorage) return;

    const data: ProjectData = {
      version: 1,
      step,
      prompt,
      bookTitle,
      world,
      characters,
      plot,
      chapters,
      batchSize,
      storySummary,
      modelProvider,
      googleModelName,
      aliyunApiKey
    };

    // 使用 debounce 或直接保存，这里数据量不大直接保存
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    console.log("进度已自动保存");

  }, [step, prompt, bookTitle, world, characters, plot, chapters, batchSize, storySummary, modelProvider, googleModelName, aliyunApiKey, isLoadedFromStorage]);

  // 新建项目 (重置)
  const handleNewProject = () => {
    if (window.confirm("确定要新建项目吗？这将清除当前的自动保存进度，且无法恢复。")) {
      // 清除本地存储
      localStorage.removeItem(STORAGE_KEY);

      // 强制刷新页面以重置所有状态为默认值
      // 这样可以确保 autosave 逻辑不会意外保存旧状态，并且让用户回到带有默认提示文案的初始界面
      window.location.reload();
    }
  };

  // --- 业务逻辑 ---

  // Step 1 -> 2: Setup to Characters
  const handleSetupGenerate = async () => {
    setIsLoading(true);
    try {
      const data = await generateCharactersAndWorld(prompt, modelProvider, aliyunApiKey, googleModelName);
      setWorld(data.world);
      setCharacters(data.characters);
      setStep(GenerationStep.CHARACTERS);
    } catch (e: any) {
      alert(`生成失败: ${e.message}`);
    } finally {
      setIsLoading(false);
    }
  };

  // Step 2 -> 3: Characters to Plot
  const handleConfirmCharacters = async (updatedWorld: WorldSetting, updatedCharacters: Character[]) => {
    if (!updatedWorld || updatedCharacters.length === 0) return;

    setWorld(updatedWorld);
    setCharacters(updatedCharacters);

    setIsLoading(true);
    try {
      const data = await generateMainPlot(updatedWorld, updatedCharacters, modelProvider, aliyunApiKey, googleModelName);
      setPlot(data);
      setStep(GenerationStep.PLOT);
    } catch (e: any) {
      alert(`生成大纲失败: ${e.message}`);
    } finally {
      setIsLoading(false);
    }
  };

  // Step 3 -> 4: Plot to Chapter Outlines -> Writing
  const handleConfirmPlot = async () => {
    if (!world || characters.length === 0 || plot.length === 0) return;
    setIsLoading(true);
    try {
      // 初始生成数量也使用 batchSize
      const outlineData = await generateChapterOutlines(world, characters, plot, batchSize, modelProvider, aliyunApiKey, googleModelName);
      const initialChapters: ChapterContent[] = outlineData.map(o => ({
        outline: o,
        content: '',
        isGenerated: false
      }));
      setChapters(initialChapters);
      setStep(GenerationStep.WRITING);
    } catch (e: any) {
      alert(`生成细纲失败: ${e.message}`);
    } finally {
      setIsLoading(false);
    }
  };

  // 仅续写后续章节大纲
  const handleAddChaptersOutline = async (count: number = 5, plotDirection?: string) => {
    if (!world || characters.length === 0 || plot.length === 0 || chapters.length === 0) return;

    setIsLoading(true);
    try {
      const lastChapter = chapters[chapters.length - 1];
      // 传递当前的剧情摘要，优化大纲连贯性
      const newOutlines = await generateNextChapterOutlines(
        world, 
        characters, 
        plot, 
        lastChapter.outline, 
        count, 
        storySummary,
        plotDirection, // 传递剧情指令
        modelProvider,
        aliyunApiKey,
        googleModelName
      );

      const newChapters: ChapterContent[] = newOutlines.map(o => ({
        outline: o,
        content: '',
        isGenerated: false
      }));

      setChapters(prev => [...prev, ...newChapters]);
    } catch (e: any) {
      console.error(e);
      alert(`续写章节大纲失败: ${e.message}`);
    } finally {
      setIsLoading(false);
    }
  };

  /**
   * 批量生成后续章节（大纲 + 正文）
   */
  const handleBatchGenerateChapters = async (count: number = 5, plotDirection?: string) => {
    if (!world || characters.length === 0 || plot.length === 0 || chapters.length === 0) return;
    if (batchProgress) return; // 防止重复点击

    try {
      // 0. 自动压缩剧情 (新增优化)
      // 使用 settings 中的压缩逻辑，范围覆盖到最后一章
      setBatchProgress("正在回顾前文并生成记忆摘要...");
      const latestSummary = await compressStoryHistory(chapters, characters, chapters.length - 1, modelProvider, aliyunApiKey, googleModelName);
      setStorySummary(latestSummary); // 更新状态以备持久化

      // 1. 生成大纲
      setBatchProgress("基于最新记忆规划后续大纲...");
      const lastChapter = chapters[chapters.length - 1];

      // 传入最新的摘要
      const newOutlines = await generateNextChapterOutlines(
        world, 
        characters, 
        plot, 
        lastChapter.outline, 
        count,
        latestSummary,
        plotDirection, // 传递剧情指令
        modelProvider,
        aliyunApiKey,
        googleModelName
      );

      // 2. 创建占位章节并添加到状态
      const newChaptersPlaceholder: ChapterContent[] = newOutlines.map(o => ({
        outline: o,
        content: '',
        isGenerated: false
      }));

      // 先保存当前的章节数量，作为后续更新的起始索引
      const startIndex = chapters.length;

      // 更新 UI 显示出新的空章节
      setChapters(prev => [...prev, ...newChaptersPlaceholder]);

      // 3. 串行生成每一章的正文
      // 注意：这里我们不能直接用 chapters 状态，因为它是旧的闭包。
      // 我们需要构建一个临时的上下文链。
      let previousContent = lastChapter.content || lastChapter.outline.summary; 

      for (let i = 0; i < newChaptersPlaceholder.length; i++) {
        const currentChapterIndex = startIndex + i;
        const currentChapter = newChaptersPlaceholder[i];

        setBatchProgress(`正在撰写第 ${currentChapter.outline.chapterNumber} 章... (${i + 1}/${count})`);

        // 调用非流式生成接口
        const generatedContent = await generateFullChapterContent(
          currentChapter.outline,
          world,
          characters,
          previousContent,
          undefined, // additionalInstructions
          latestSummary, // 使用最新的记忆摘要
          modelProvider,
          aliyunApiKey,
          googleModelName
        );

        // 更新单个章节状态
        handleUpdateChapter(currentChapterIndex, generatedContent, true);

        // 更新上下文，为下一章做准备
        previousContent = generatedContent;
      }

      setBatchProgress(null);

    } catch (e: any) {
      console.error(e);
      alert(`批量生成过程中断: ${e.message}`);
      setBatchProgress(null);
    }
  };


  // 更新章节内容
  const handleUpdateChapter = (index: number, content: string, isGenerated: boolean) => {
    setChapters(prev => {
      const newChapters = [...prev];
      if (newChapters[index]) {
        newChapters[index] = {
          ...newChapters[index],
          content,
          isGenerated
        };
      }
      return newChapters;
    });
  };

  // 更新章节标题
  const handleUpdateChapterTitle = (index: number, title: string) => {
    setChapters(prev => {
      const newChapters = [...prev];
      if (newChapters[index]) {
        newChapters[index] = {
          ...newChapters[index],
          outline: {
            ...newChapters[index].outline,
            title
          }
        };
      }
      return newChapters;
    });
  };

  // 更新分组小结
  const handleUpdateGroupSummary = (index: number, summary: string) => {
      setChapters(prev => {
          const newChapters = [...prev];
          if (newChapters[index]) {
              newChapters[index] = {
                  ...newChapters[index],
                  outline: {
                      ...newChapters[index].outline,
                      groupSummary: summary
                  }
              }
          }
          return newChapters;
      })
  }

  // 删除分组小结
  const handleDeleteGroupSummary = (index: number) => {
      handleUpdateGroupSummary(index, "");
  };

  // 删除章节
  const handleDeleteChapter = (index: number) => {
      if (chapters.length <= 1) {
          alert("无法删除：至少需要保留一个章节。");
          return;
      }

      setChapters(prev => {
          // 1. 过滤掉删除的章节
          const newChapters = prev.filter((_, i) => i !== index);

          // 2. 重新编排章节号，保证连续性
          return newChapters.map((chap, i) => ({
              ...chap,
              outline: {
                  ...chap.outline,
                  chapterNumber: i + 1
              }
          }));
      });
  };

  // 导出项目
  const handleExport = () => {
    const data: ProjectData = {
      version: 1,
      step,
      prompt,
      bookTitle,
      world,
      characters,
      plot,
      chapters,
      batchSize,
      storySummary,
      modelProvider,
      googleModelName,
      aliyunApiKey
    };

    const jsonString = JSON.stringify(data, null, 2);
    const blob = new Blob([jsonString], { type: "application/json" });
    const url = URL.createObjectURL(blob);

    const link = document.createElement('a');
    link.href = url;
    link.download = `${bookTitle || 'soulwriter-project'}-${new Date().toISOString().slice(0, 10)}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  // 导入项目触发
  const triggerImport = () => {
    fileInputRef.current?.click();
  };

  // 处理文件读取
  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (json.version && json.step) {
          const data = json as ProjectData;
          setStep(data.step);
          setPrompt(data.prompt || "");
          setBookTitle(data.bookTitle || "");
          setWorld(data.world);
          setCharacters(data.characters);
          setPlot(data.plot);
          setChapters(data.chapters);
          if (data.batchSize) setBatchSize(data.batchSize);
          if (data.storySummary) setStorySummary(data.storySummary);
          if (data.modelProvider) setModelProvider(data.modelProvider);
          if (data.googleModelName) setGoogleModelName(data.googleModelName);
          if (data.aliyunApiKey) setAliyunApiKey(data.aliyunApiKey);
          alert("项目导入成功！");
        } else {
          alert("无效的项目文件格式");
        }
      } catch (error) {
        console.error("Import error", error);
        alert("文件解析失败");
      }
    };
    reader.readAsText(file);
    e.target.value = ''; 
  };

  return (
    <div className="min-h-screen bg-[#0d1117] text-gray-100 font-sans selection:bg-indigo-500/30">
      <header className="border-b border-gray-800 bg-[#0d1117]/80 backdrop-blur sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-4">
             {/* Logo */}
             <div className="font-bold text-xl tracking-tight bg-gradient-to-r from-indigo-400 to-cyan-400 bg-clip-text text-transparent flex items-center gap-2 cursor-pointer shrink-0" onClick={() => setStep(GenerationStep.SETUP)}>
                <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center text-white">
                  <FileJson size={20} />
                </div>
                <span className="hidden sm:inline">SoulWriter AI</span>
              </div>

              {/* Divider */}
              <div className="h-6 w-px bg-gray-700 mx-2 hidden sm:block"></div>

              {/* Book Title */}
              <button 
                onClick={() => setShowTitleModal(true)}
                className="flex items-center gap-2 px-3 py-1.5 rounded-lg hover:bg-gray-800 transition-colors group max-w-[150px] sm:max-w-xs"
                title="点击修改书名"
              >
                <div className="text-sm font-bold text-gray-200 truncate">
                   {bookTitle || "未命名作品"}
                </div>
                <PenLine size={14} className="text-gray-500 group-hover:text-indigo-400 shrink-0" />
              </button>
          </div>


          <div className="flex items-center gap-4">
            {/* Steps Indicator (Desktop) */}
            <div className="hidden lg:flex gap-2 text-xs font-mono text-gray-500 mr-4">
              <span className={step === GenerationStep.SETUP ? 'text-indigo-400' : ''}>01.设定</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.CHARACTERS ? 'text-indigo-400' : ''}>02.人物</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.PLOT ? 'text-indigo-400' : ''}>03.大纲</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.WRITING ? 'text-indigo-400' : ''}>04.正文</span>
            </div>

            {/* Actions */}
            <div className="flex items-center gap-2 border-l border-gray-700 pl-4">
              <input 
                type="file" 
                ref={fileInputRef} 
                className="hidden" 
                accept=".json" 
                onChange={handleImport}
              />

              {/* Settings Button - 可见性：所有端可见 */}
              <button 
                onClick={() => setShowSettingsModal(true)}
                className="p-2 text-gray-400 hover:text-white hover:bg-gray-800 rounded-lg transition-colors flex items-center gap-2 text-sm"
                title="设置"
              >
                <Settings size={20} />
              </button>

              {/* 新建项目按钮 */}
              <button 
                onClick={handleNewProject}
                className="p-2 text-gray-400 hover:text-white hover:bg-gray-800 rounded-lg transition-colors flex items-center gap-2 text-sm"
                title="新建项目 (清空进度)"
              >
                <FilePlus size={18} />
                <span className="hidden sm:inline">新建项目</span>
              </button>

              <button 
                onClick={triggerImport}
                className="p-2 text-gray-400 hover:text-white hover:bg-gray-800 rounded-lg transition-colors flex items-center gap-2 text-sm"
                title="导入项目"
              >
                <Upload size={18} />
                <span className="hidden sm:inline">导入</span>
              </button>

              <button 
                onClick={handleExport}
                className="px-3 py-1.5 bg-gray-800 hover:bg-gray-700 text-indigo-300 border border-indigo-500/30 rounded-lg transition-colors flex items-center gap-2 text-sm font-medium"
                title="导出项目"
              >
                <Save size={18} />
                <span className="hidden sm:inline">保存</span>
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8">
        {step === GenerationStep.SETUP && (
          <StepSetup 
            prompt={prompt}
            setPrompt={setPrompt}
            onGenerate={handleSetupGenerate} 
            isLoading={isLoading} 
          />
        )}

        {step === GenerationStep.CHARACTERS && world && (
          <StepCharacters 
            world={world} 
            characters={characters} 
            onConfirm={handleConfirmCharacters}
            isLoading={isLoading}
          />
        )}

        {step === GenerationStep.PLOT && (
          <StepPlot 
            plot={plot}
            onConfirm={handleConfirmPlot}
            isLoading={isLoading}
          />
        )}

        {step === GenerationStep.WRITING && world && (
          <StepWriting 
            chapters={chapters}
            world={world}
            characters={characters}
            onUpdateChapter={handleUpdateChapter}
            onUpdateTitle={handleUpdateChapterTitle}
            onUpdateGroupSummary={handleUpdateGroupSummary}
            onDeleteChapter={handleDeleteChapter}
            onDeleteGroupSummary={handleDeleteGroupSummary}
            onLoadMoreChapters={handleAddChaptersOutline}
            onBatchGenerate={handleBatchGenerateChapters}
            isLoadingMore={isLoading}
            batchProgress={batchProgress}
            batchSize={batchSize}
            storySummary={storySummary} // Pass summary
            googleModelName={googleModelName} // Pass model name prop
          />
        )}
      </main>

      {/* Modals */}
      {showTitleModal && (
        <TitleGeneratorModal 
           currentTitle={bookTitle}
           onSelect={(t) => setBookTitle(t)}
           onClose={() => setShowTitleModal(false)}
           contextData={{ prompt, world, characters }}
        />
      )}

      {showSettingsModal && (
        <SettingsModal 
          batchSize={batchSize}
          onSaveBatchSize={setBatchSize}
          storySummary={storySummary}
          onSaveStorySummary={setStorySummary}
          chapters={chapters}
          characters={characters}
          modelProvider={modelProvider}
          onSaveModelProvider={setModelProvider}
          googleModelName={googleModelName}
          onSaveGoogleModelName={setGoogleModelName}
          aliyunApiKey={aliyunApiKey}
          onSaveAliyunApiKey={setAliyunApiKey}
          onClose={() => setShowSettingsModal(false)}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Settings, X, Save, AlertTriangle, FileText, Sparkles, Loader2, Check, Cpu, Key } from 'lucide-react';
import { ChapterContent, Character, ModelProvider } from '../types';
import { compressStoryHistory } from '../services/geminiService';

interface Props {
  batchSize: number;
  onSaveBatchSize: (size: number) => void;
  storySummary: string;
  onSaveStorySummary: (summary: string) => void;
  chapters: ChapterContent[];
  characters: Character[];
  modelProvider: ModelProvider;
  onSaveModelProvider: (provider: ModelProvider) => void;
  googleModelName: string;
  onSaveGoogleModelName: (name: string) => void;
  aliyunApiKey: string;
  onSaveAliyunApiKey: (key: string) => void;
  onClose: () => void;
}

const SettingsModal: React.FC<Props> = ({ 
  batchSize, 
  onSaveBatchSize, 
  storySummary, 
  onSaveStorySummary,
  chapters,
  characters,
  modelProvider,
  onSaveModelProvider,
  googleModelName,
  onSaveGoogleModelName,
  aliyunApiKey,
  onSaveAliyunApiKey,
  onClose 
}) => {
  // Ensure initial size doesn't exceed new max of 5
  const [size, setSize] = useState(Math.min(batchSize, 5));

  // Compression State
  const [summary, setSummary] = useState(storySummary || "");
  const [compressTargetChapter, setCompressTargetChapter] = useState<number>(chapters.length > 0 ? chapters.length - 1 : 0);
  const [isCompressing, setIsCompressing] = useState(false);
  const [activeTab, setActiveTab] = useState<'general' | 'model' | 'memory'>('general');

  // Model State
  const [localProvider, setLocalProvider] = useState<ModelProvider>(modelProvider);
  const [localGoogleModel, setLocalGoogleModel] = useState(googleModelName);
  const [localAliyunKey, setLocalAliyunKey] = useState(aliyunApiKey);

  const handleSave = () => {
    onSaveBatchSize(size);
    onSaveStorySummary(summary);
    onSaveModelProvider(localProvider);
    onSaveGoogleModelName(localGoogleModel);
    onSaveAliyunApiKey(localAliyunKey);
    onClose();
  };

  const handleCompress = async () => {
    if (chapters.length === 0) return;
    setIsCompressing(true);
    try {
        const result = await compressStoryHistory(
            chapters, 
            characters, 
            compressTargetChapter, 
            localProvider, 
            localAliyunKey,
            localGoogleModel
        );
        setSummary(result);
    } catch (e: any) {
        alert(`剧情压缩失败: ${e.message}`);
    } finally {
        setIsCompressing(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4 animate-in fade-in duration-200">
      <div className="bg-gray-900 border border-gray-700 rounded-xl w-full max-w-lg shadow-2xl flex flex-col max-h-[90vh]">
        {/* Header */}
        <div className="flex justify-between items-center p-4 border-b border-gray-800 shrink-0">
          <h3 className="text-lg font-bold text-white flex items-center gap-2">
            <Settings className="text-indigo-400" size={20} />
            生成设置
          </h3>
          <button onClick={onClose} className="text-gray-500 hover:text-white transition-colors">
            <X size={20} />
          </button>
        </div>

        {/* Tabs */}
        <div className="flex border-b border-gray-800 shrink-0">
             <button 
                onClick={() => setActiveTab('general')}
                className={`flex-1 py-3 text-sm font-bold text-center border-b-2 transition-colors ${activeTab === 'general' ? 'border-indigo-500 text-indigo-400' : 'border-transparent text-gray-400 hover:text-white'}`}
             >
                通用设置
             </button>
             <button 
                onClick={() => setActiveTab('model')}
                className={`flex-1 py-3 text-sm font-bold text-center border-b-2 transition-colors ${activeTab === 'model' ? 'border-indigo-500 text-indigo-400' : 'border-transparent text-gray-400 hover:text-white'}`}
             >
                模型设置
             </button>
             <button 
                onClick={() => setActiveTab('memory')}
                className={`flex-1 py-3 text-sm font-bold text-center border-b-2 transition-colors ${activeTab === 'memory' ? 'border-indigo-500 text-indigo-400' : 'border-transparent text-gray-400 hover:text-white'}`}
             >
                剧情压缩
             </button>
        </div>

        {/* Body */}
        <div className="p-6 space-y-6 overflow-y-auto custom-scrollbar">

          {activeTab === 'general' && (
              <div className="space-y-4">
                <div className="flex justify-between items-center">
                  <label className="text-sm font-medium text-gray-300">
                    批量生成章节数量
                  </label>
                  <span className="text-indigo-400 font-bold text-lg">{size} 章</span>
                </div>

                <input 
                  type="range" 
                  min="1" 
                  max="5" 
                  step="1"
                  value={size}
                  onChange={(e) => setSize(parseInt(e.target.value))}
                  className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-indigo-500 hover:accent-indigo-400"
                />

                <div className="flex justify-between text-xs text-gray-500 px-1">
                  <span>1章</span>
                  <span>3章</span>
                  <span>5章</span>
                </div>

                 <div className="bg-gray-800/50 rounded-lg p-3 text-xs text-gray-400 leading-relaxed border border-gray-700 mt-4">
                    <p>提示：批量生成用于快速推进剧情。如果需要精细控制每一章的内容，建议在正文页面逐章生成。</p>
                 </div>
              </div>
          )}

          {activeTab === 'model' && (
              <div className="space-y-6">
                 <div className="space-y-3">
                    <label className="text-sm font-medium text-gray-300 flex items-center gap-2">
                        <Cpu size={16} className="text-indigo-400" />
                        AI 模型提供商
                    </label>
                    <div className="grid grid-cols-2 gap-3">
                        <button 
                            onClick={() => setLocalProvider('google')}
                            className={`p-3 rounded-lg border text-sm font-medium transition-all ${localProvider === 'google' ? 'bg-indigo-900/30 border-indigo-500 text-white shadow-md shadow-indigo-500/10' : 'bg-gray-800 border-gray-700 text-gray-400 hover:bg-gray-750'}`}
                        >
                            Google Gemini
                            <span className="block text-xs font-normal opacity-70 mt-1">系统默认</span>
                        </button>
                        <button 
                            onClick={() => setLocalProvider('aliyun')}
                            className={`p-3 rounded-lg border text-sm font-medium transition-all ${localProvider === 'aliyun' ? 'bg-indigo-900/30 border-indigo-500 text-white shadow-md shadow-indigo-500/10' : 'bg-gray-800 border-gray-700 text-gray-400 hover:bg-gray-750'}`}
                        >
                            阿里云百炼
                            <span className="block text-xs font-normal opacity-70 mt-1">通义千问 Max</span>
                        </button>
                    </div>
                 </div>

                 {localProvider === 'google' && (
                    <div className="space-y-3 animate-in fade-in slide-in-from-top-2 duration-300">
                        <label className="text-sm font-medium text-gray-300 block">选择 Google 模型版本</label>
                        <select 
                            value={localGoogleModel}
                            onChange={(e) => setLocalGoogleModel(e.target.value)}
                            className="w-full bg-gray-950 border border-gray-700 rounded-lg px-3 py-2 text-white outline-none focus:border-indigo-500 text-sm"
                        >
                            <option value="gemini-3-pro-preview">Gemini 3 Pro (Preview) - 默认推荐</option>
                            <option value="gemini-3-flash-preview">Gemini 3 Flash (Preview) - 更快更省</option>
                        </select>
                        <p className="text-xs text-gray-500 leading-relaxed">
                            * Pro 模型逻辑推理能力更强，适合复杂剧情规划；Flash 模型生成速度更快。
                        </p>
                    </div>
                 )}

                 {localProvider === 'aliyun' && (
                     <div className="space-y-3 animate-in fade-in slide-in-from-top-2 duration-300">
                        <label className="text-sm font-medium text-gray-300 flex items-center gap-2">
                            <Key size={16} className="text-indigo-400" />
                            阿里云 API Key
                        </label>
                        <input 
                            type="password"
                            value={localAliyunKey}
                            onChange={(e) => setLocalAliyunKey(e.target.value)}
                            className="w-full bg-gray-950 border border-gray-700 rounded-lg px-4 py-3 text-white focus:ring-2 focus:ring-indigo-500 outline-none placeholder-gray-600 text-sm font-mono"
                            placeholder="sk-..."
                        />
                        <p className="text-xs text-gray-500 leading-relaxed">
                            * 请前往阿里云百炼控制台获取 API Key。该 Key 仅保存在您的浏览器本地存储中。
                        </p>
                     </div>
                 )}
              </div>
          )}

          {activeTab === 'memory' && (
              <div className="space-y-6">
                 <div className="bg-indigo-900/20 border border-indigo-500/30 rounded-lg p-3 flex gap-2">
                    <Sparkles size={16} className="text-indigo-400 shrink-0 mt-0.5" />
                    <p className="text-xs text-indigo-200/80 leading-relaxed">
                        随着章节增多，AI 可能会遗忘前期剧情。通过“剧情压缩”，将前文浓缩为一份摘要，作为 AI 的长期记忆，确保后续剧情连贯，特别是男女主关系进展。
                    </p>
                 </div>

                 <div className="space-y-2">
                     <label className="text-sm font-medium text-gray-300 block">压缩范围</label>
                     <div className="flex gap-2">
                        <select 
                            value={compressTargetChapter}
                            onChange={(e) => setCompressTargetChapter(parseInt(e.target.value))}
                            className="flex-1 bg-gray-950 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm outline-none focus:border-indigo-500"
                            disabled={chapters.length === 0}
                        >
                            {chapters.map((c, i) => (
                                <option key={i} value={i}>
                                    截止到：第 {c.outline.chapterNumber} 章 {c.outline.title}
                                </option>
                            ))}
                        </select>
                        <button 
                            onClick={handleCompress}
                            disabled={isCompressing || chapters.length === 0}
                            className="bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 disabled:cursor-not-allowed text-white px-3 py-2 rounded-lg text-sm font-bold flex items-center gap-2 shrink-0 transition-colors"
                        >
                            {isCompressing ? <Loader2 size={16} className="animate-spin" /> : <FileText size={16} />}
                            {isCompressing ? '分析中...' : '生成摘要'}
                        </button>
                     </div>
                 </div>

                 <div className="space-y-2">
                     <label className="text-sm font-medium text-gray-300 flex justify-between">
                         <span>当前记忆摘要</span>
                         <span className="text-xs text-gray-500">{summary.length} 字</span>
                     </label>
                     <textarea 
                        value={summary}
                        onChange={(e) => setSummary(e.target.value)}
                        className="w-full h-48 bg-gray-950 border border-gray-700 rounded-lg p-3 text-gray-300 text-sm leading-relaxed outline-none focus:border-indigo-500 resize-none custom-scrollbar"
                        placeholder="暂无摘要。点击上方按钮生成，或手动输入..."
                     />
                     <p className="text-xs text-gray-500">
                         * 您可以手动修改这份摘要，补充被 AI 遗漏的关键信息。
                     </p>
                 </div>
              </div>
          )}
        </div>

        {/* Footer */}
        <div className="p-4 border-t border-gray-800 flex justify-end">
          <button 
            onClick={handleSave}
            className="bg-indigo-600 hover:bg-indigo-500 text-white px-6 py-2 rounded-lg font-medium transition-colors flex items-center gap-2 shadow-lg shadow-indigo-900/50"
          >
            <Save size={18} />
            保存全部设置
          </button>
        </div>
      </div>
    </div>
  );
};

