      chapters: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            chapterNumber: { type: Type.INTEGER },
            title: { type: Type.STRING },
            summary: { type: Type.STRING },
            narrativePulse: { type: Type.STRING },
            coolPoint: { type: Type.STRING },
            rules: { type: Type.ARRAY, items: { type: Type.STRING } },
